es.","main_translations_es":["Wi-Fi","wifi","red inalámbrica"],"collocations":["Wi-Fi connection","Wi-Fi network","Wi-Fi hotspot","Wi-Fi signal"],"synonyms_en":[],"example_sentence":"I connected my phone to the hotel’s Wi‑Fi.","example_es":"Conecté mi teléfono al Wi‑Fi del hotel.","example_en":"I connected my phone to the hotel’s Wi‑Fi.","mnemonic_en":null,"cloze_distractors_en":[],"examples":[{"es":"Conecté mi teléfono al Wi‑Fi del hotel.","en":"I connected my phone to the hotel’s Wi‑Fi."}]},{"spanish_text":"Ascensor","english_text":"Elevator","section_name":"Travel Phrases","part_of_speech":"noun","definition_en":"A mechanical device that transports people or goods between floors of a building.","main_translations_es":["Elevador"],"collocations":["take the elevator","elevator music","elevator pitch","elevator ride"],"synonyms_en":["lift","people mover"],"example_sentence":"The elevator is at the building''s entrance.","example_es":"El ascensor está en la entrada del edificio.","example_en":"The elevator is at the building''s entrance.","mnemonic_en":"Picture an elevator shouting Eleva señor as it lifts you up.","cloze_distractors_en":[],"examples":[{"es":"El ascensor está en la entrada del edificio.","en":"The elevator is at the building''s entrance."}]},{"spanish_text":"Equipaje","english_text":"Luggage","section_name":"Travel Phrases","part_of_speech":"noun","definition_en":"Items of personal belongings carried in a suitcase or bag, especially when traveling.","main_translations_es":["Bolsas","Maletas","Equipamiento"],"collocations":["checked luggage","carry-on luggage","lost luggage","luggage tag"],"synonyms_en":["baggage","travel gear","suitcases"],"example_sentence":"My luggage from the flight arrived late.","example_es":"El equipaje de mi vuelo llegó tarde.","example_en":"My luggage from the flight arrived late.","mnemonic_en":"Picture a strong lug pulling a suitcase full of equipaje across the airport.","cloze_distractors_en":[],"examples":[{"es":"El equipaje de mi vuelo llegó tarde.","en":"My luggage from the flight arrived late."}]},{"spanish_text":"Mochila","english_text":"Backpack","section_name":"Travel Phrases","part_of_speech":"noun","definition_en":"A bag carried on the back, typically with two straps, used for carrying books, supplies, or other items.","main_translations_es":["Bolsa","Bolso","Bolsa de viaje"],"collocations":["backpack school","backpack travel","backpack tour","backpack for hiking"],"synonyms_en":["knapsack","rucksack","daypack"],"example_sentence":"I need to bring my backpack to campus.","example_es":"Necesito llevar mi mochila al campus.","example_en":"I need to bring my backpack to campus.","mnemonic_en":"Picture a mochi bag strapped to your back, a mochila backpack.","cloze_distractors_en":[],"examples":[{"es":"Necesito llevar mi mochila al campus.","en":"I need to bring my backpack to campus."}]},{"spanish_text":"Cargador","english_text":"Charger","section_name":"Travel Phrases","part_of_speech":"noun","definition_en":"a device that supplies electrical energy to recharge a battery","main_translations_es":["cargador","recargador","alimentador"],"collocations":["phone charger","battery charger","USB charger","portable charger"],"synonyms_en":["power adapter","charging device","battery pack"],"example_sentence":"I need a new charger for my phone.","example_es":"Necesito un cargador nuevo para mi teléfono.","example_en":"I need a new charger for my phone.","mnemonic_en":"Picture a charger feeding a car''s battery, like a CARGA‑door opening power.","cloze_distractors_en":[],"examples":[{"es":"Necesito un cargador nuevo para mi teléfono.","en":"I need a new charger for my phone."}]},{"spanish_text":"Enchufe","english_text":"Plug","section_name":"Travel Phrases","part_of_speech":"noun","definition_en":"a device that connects an electrical appliance to a power source","main_translations_es":["toma de corriente","conector","enchufe"],"collocations":["plug in","plug out","plug and play","plug into"],"synonyms_en":["connector","stopper","adapter"],"example_sentence":"The plug in the wall is loose.","example_es":"El enchufe en la pared está suelto.","example_en":"The plug in the wall is loose.","mnemonic_en":"Visualize a bright plug stamped ENCHUFE, snapping into the wall like a Spanish power plug","cloze_distractors_en":[],"examples":[{"es":"El enchufe en la pared está suelto.","en":"The plug in the wall is loose."}]},{"spanish_text":"Adaptador","english_text":"Adapter","section_name":"Travel Phrases","part_of_speech":"noun","definition_en":"A device that allows one type of connection to be used with another.","main_translations_es":["Adaptador"],"collocations":["adapter for USB","adapter cable","power adapter","audio adapter"],"synonyms_en":["converter","connector","interface"],"example_sentence":"I need an adapter to plug my laptop into the European outlet.","example_es":"Necesito un adaptador para conectar mi portátil al enchufe europeo.","example_en":"I need an adapter to plug my laptop into the European outlet.","mnemonic_en":"Visualize an adapter plugging a Spanish adaptador into a socket, the words sound identical.","cloze_distractors_en":[],"examples":[{"es":"Necesito un adaptador para conectar mi portátil al enchufe europeo.","en":"I need an adapter to plug my laptop into the European outlet."}]},{"spanish_text":"Dinero en efectivo","english_text":"Cash","section_name":"Travel Phrases","part_of_speech":"noun","definition_en":"Money in the form of coins and banknotes that can be used for transactions.","main_translations_es":["Efectivo","Dinero en mano","Dinero en efectivo"],"collocations":["cash register","cash flow","cash out","cash on hand"],"synonyms_en":["money","currency","hard cash"],"example_sentence":"The ATM gave me cash.","example_es":"El cajero me dio dinero en efectivo.","example_en":"The ATM gave me cash.","mnemonic_en":"Imagine a cash box, a caja overflowing with dinero.","cloze_distractors_en":[],"examples":[{"es":"El cajero me dio dinero en efectivo.","en":"The ATM gave me cash."}]},{"spanish_text":"Tarjeta","english_text":"Card","section_name":"Travel Phrases","part_of_speech":"noun","definition_en":"A small, flat piece of paper, cardboard, or plastic used for identification, payment, or as a playing piece.","main_translations_es":["Tarjeta","Ficha","Cartón"],"collocations":["business card","credit card","playing card","card game"],"synonyms_en":["ticket","pass","note"],"example_sentence":"I bought a credit card at the bank.","example_es":"Compré una tarjeta de crédito en el banco.","example_en":"I bought a credit card at the bank.","mnemonic_en":"Picture a playing card covered in dark tar with a tiny jet sticker echoing tarjeta","cloze_distractors_en":[],"examples":[{"es":"Compré una tarjeta de crédito en el banco.","en":"I bought a credit card at the bank."}]},{"spanish_text":"Moneda","english_text":"Coin","section_name":"Travel Phrases","part_of_speech":"noun","definition_en":"A small, flat piece of metal used as money.","main_translations_es":["Moneda","Dinero"],"collocations":["coin toss","coin flip","coin collection","coin-operated"],"synonyms_en":["currency","piece of money","token"],"example_sentence":"I bought a gold coin at the fair.","example_es":"Compré una moneda de oro en la feria.","example_en":"I bought a gold coin at the fair.","mnemonic_en":"Imagine a shiny coin stamped with the word moneda on its edge.","cloze_distractors_en":[],"examples":[{"es":"Compré una moneda de oro en la feria.","en":"I bought a gold coin at the fair."}]},{"spanish_text":"Cambio","english_text":"Change","section_name":"Travel Phrases","part_of_speech":"noun","definition_en":"the act of becoming different","main_translations_es":["Intercambio","Transformación","Modificación"],"collocations":["change of heart","change of pace","change of scenery","change of plans"],"synonyms_en":["alteration","modification","shift"],"example_sentence":"Change is inevitable.","example_es":"El cambio es inevitable.","example_en":"Change is inevitable.","mnemonic_en":"Picture a coin flipping and you hear cambio as it changes.","cloze_distractors_en":[],"examples":[{"es":"El cambio es inevitable.","en":"Change is inevitable."}]},{"spanish_text":"Recibo","english_text":"Receipt","section_name":"Travel Phrases","part_of_speech":"noun","definition_en":"A written acknowledgment of having received something, typically a payment or goods.","main_translations_es":["comprobante","boleta","ticket"],"collocations":["receipt of","receipt for","receipt slip","receipt number"],"synonyms_en":["proof of purchase","sales slip","transaction record"],"example_sentence":"Keep the receipt in your folder.","example_es":"Guarda el recibo en tu carpeta.","example_en":"Keep the receipt in your folder.","mnemonic_en":"I hand the cashier a receipt, thinking of my recibo tucked in my pocket.","cloze_distractors_en":[],"examples":[{"es":"Guarda el recibo en tu carpeta.","en":"Keep the receipt in your folder."}]},{"spanish_text":"Precio","english_text":"Price","section_name":"Travel Phrases","part_of_speech":"noun","definition_en":"the amount of money expected, required, or given in payment for something.","main_translations_es":["Costo","Tarifa","Valor"],"collocations":["price tag","price point","price range","price list"],"synonyms_en":["cost","charge","fee"],"example_sentence":"The price of the ticket is twenty euros.","example_es":"El precio de la entrada es de veinte euros.","example_en":"The price of the ticket is twenty euros.","mnemonic_en":"Picture a price tag shouting precio as it slides down a cash register.","cloze_distractors_en":[],"examples":[{"es":"El precio de la entrada es de veinte euros.","en":"The price of the ticket is twenty euros."}]},{"spanish_text":"Abierto","english_text":"Open","section_name":"Travel Phrases","part_of_speech":"adjective","definition_en":"Not closed; allowing passage or access.","main_translations_es":["Disponible","Libre","Apertura"],"collocations":["open door","open mind","open source","open for business"],"synonyms_en":["unlocked","unsealed","available"],"example_sentence":"The restaurant is open every day.","example_es":"El restaurante está abierto todos los días.","example_en":"The restaurant is open every day.","mnemonic_en":"Imagine an open door shouting abierto as you walk in.","cloze_distractors_en":[],"examples":[{"es":"El restaurante está abierto todos los días.","en":"The restaurant is open every day."}]},{"spanish_text":"Cerrado","english_text":"Closed","section_name":"Travel Phrases","part_of_speech":"adjective","definition_en":"Not open; shut.","main_translations_es":["Inactivo","Bloqueado","Sin acceso"],"collocations":["closed shop","closed door","closed circuit","closed season"],"synonyms_en":["shut","sealed","locked"],"example_sentence":"The museum is closed.","example_es":"El museo está cerrado.","example_en":"The museum is closed.","mnemonic_en":"Closed sounds like Spanish ''cerrado'', picture a door shut with a big red ''C'' lock.","cloze_distractors_en":[],"examples":[{"es":"El museo está cerrado.","en":"The museum is closed."}]},{"spanish_text":"Ayuda","english_text":"Help","section_name":"Travel Phrases","part_of_speech":"noun","definition_en":"Assistance or support given to someone in need.","main_translations_es":["Asistencia","Soporte","Auxilio"],"collocations":["help out","help with","help someone","help yourself"],"synonyms_en":["assist","aid","support"],"example_sentence":"I need help.","example_es":"Necesito ayuda.","example_en":"I need help.","mnemonic_en":"Imagine a superhero shouting ''Ayuda!'' as he lifts a heavy box, reminding you that help sounds like ayuda.","cloze_distractors_en":[],"examples":[{"es":"Necesito ayuda.","en":"I need help."}]},{"spanish_text":"Llama a la policía","english_text":"Call the police","section_name":"Travel Phrases","part_of_speech":"verb","definition_en":"to contact the police for assistance or to report a crime","main_translations_es":["Llama a la policía","Contacta a la policía","Ponte en contacto con la policía"],"collocations":["call the police right away","call the police if there''s a fire","call the police for a robbery","call the police to report a crime"],"synonyms_en":["alert the police","dial 911","report to authorities"],"example_sentence":"In case of emergency, call the police.","example_es":"En caso de emergencia, llama a la policía.","example_en":"In case of emergency, call the police.","mnemonic_en":"Imagine a llama dialing the phone to call the police.","cloze_distractors_en":[],"examples":[{"es":"En caso de emergencia, llama a la policía.","en":"In case of emergency, call the police."}]},{"spanish_text":"Necesito un médico","english_text":"I need a doctor","section_name":"Travel Phrases","part_of_speech":"expression","definition_en":"A statement expressing the speaker''s requirement for a medical professional.","main_translations_es":["Necesito un doctor","Me hace falta un médico","Requiero un médico"],"collocations":["I need a doctor right now","I need a doctor for my child","I need a doctor urgently","I need a doctor at the hospital"],"synonyms_en":["I require a doctor","I need a physician","I need medical assistance"],"example_sentence":"I need a doctor to check my headache.","example_es":"Necesito un médico para revisar mi dolor de cabeza.","example_en":"I need a doctor to check my headache.","mnemonic_en":"When I shout ''I need a doctor'', I picture saying ''necesito doctor'' to a panicked patient.","cloze_distractors_en":[],"examples":[{"es":"Necesito un médico para revisar mi dolor de cabeza.","en":"I need a doctor to check my headache."}]},{"spanish_text":"Emergencia","english_text":"Emergency","section_name":"Travel Phrases","part_of_speech":"noun","definition_en":"A sudden, urgent situation requiring immediate action.","main_translations_es":["Crisis","Situación de emergencia"],"collocations":["emergency situation","emergency services","emergency department","emergency exit"],"synonyms_en":["crisis","urgent situation","critical incident"],"example_sentence":"The medical emergency requires immediate attention.","example_es":"La emergencia médica requiere atención inmediata.","example_en":"The medical emergency requires immediate attention.","mnemonic_en":"A flashing red alarm makes me think emergency, like the word emerges from the chaos","cloze_distractors_en":[],"examples":[{"es":"La emergencia médica requiere atención inmediata.","en":"The medical emergency requires immediate attention."}]},{"spanish_text":"He perdido mi pasaporte","english_text":"I lost my passport","section_name":"Travel Phrases","part_of_speech":"expression","definition_en":"A statement indicating that the speaker has lost their passport.","main_translations_es":["Perdí mi pasaporte","He extraviado mi pasaporte","He perdido mi documento de viaje"],"collocations":["I lost my passport at the airport","I lost my passport while traveling","I lost my passport and had to get a replacement","I lost my passport and can''t travel"],"synonyms_en":["misplaced my passport","my passport is missing","can''t locate my passport"],"example_sentence":"I lost my passport, so I need to apply for a new one.","example_es":"He perdido mi pasaporte, así que necesito solicitar uno nuevo.","example_en":"I lost my passport, so I need to apply for a new one.","mnemonic_en":"I lost my passport, just like I lost my ''pasaporte'' on a windy beach.","cloze_distractors_en":[],"examples":[{"es":"He perdido mi pasaporte, así que necesito solicitar uno nuevo.","en":"I lost my passport, so I need to apply for a new one."}]},{"spanish_text":"He perdido mi cartera","english_text":"I lost my wallet","section_name":"Travel Phrases","part_of_speech":"expression","definition_en":"A sentence expressing that the speaker has misplaced or lost their wallet.","main_translations_es":["Perdí mi cartera","He perdido mi billetera","Perdí mi bolso"],"collocations":["I lost my wallet at the restaurant","I lost my wallet in the subway","I lost my wallet and had to cancel my cards"],"synonyms_en":["misplaced my wallet","my wallet is missing","can''t locate my wallet"],"example_sentence":"I lost my wallet on the bus.","example_es":"He perdido mi cartera en el autobús.","example_en":"I lost my wallet on the bus.","mnemonic_en":"Picture a carter dropping his wallet on the road, shouting lost my wallet!","cloze_distractors_en":[],"examples":[{"es":"He perdido mi cartera en el autobús.","en":"I lost my wallet on the bus."}]},{"spanish_text":"Estoy enfermo","english_text":"I am sick","section_name":"Travel Phrases","part_of_speech":"expression","definition_en":"I am ill or unwell.","main_translations_es":["Me siento enfermo","Estoy indispuesto","Tengo fiebre"],"collocations":["I am sick with a cold","I am sick and need to rest","I am sick to my stomach","I am sick of this"],"synonyms_en":["I''m ill","I feel unwell","I''m under the weather"],"example_sentence":"I am sick and can''t go to work.","example_es":"Estoy enfermo y no puedo ir al trabajo.","example_en":"I am sick and can''t go to work.","mnemonic_en":"I am sick, picture a patient in a hospital shouting ''Estoy enfermo'' while clutching his stomach.","cloze_distractors_en":[],"examples":[{"es":"Estoy enfermo y no puedo ir al trabajo.","en":"I am sick and can''t go to work."}]},{"spanish_text":"Está roto","english_text":"It is broken","section_name":"Travel Phrases","part_of_speech":"expression","definition_en":"It is not functioning properly; it has been damaged.","main_translations_es":["Se ha roto","Se rompió","Está averiado"],"collocations":["It is broken beyond repair","It is broken into pieces","It is broken down","It is broken up"],"synonyms_en":["It''s damaged","It''s busted","It''s not working"],"example_sentence":"The glass is broken.","example_es":"El vaso está roto.","example_en":"The glass is broken.","mnemonic_en":"Picture a broken vase yelling Roto!","cloze_distractors_en":[],"examples":[{"es":"El vaso está roto.","en":"The glass is broken."}]},{"spanish_text":"No funciona","english_text":"It does not work","section_name":"Travel Phrases","part_of_speech":"expression","definition_en":"A phrase indicating that something is not functioning or operating as intended.","main_translations_es":["No funciona"],"collocations":["It does not work for me","It does not work on my machine","It does not work as expected","It does not work properly"],"synonyms_en":["doesn''t work","fails","malfunctions"],"example_sentence":"The button I tried to press does not work.","example_es":"No funciona el botón que intenté presionar.","example_en":"The button I tried to press does not work.","mnemonic_en":"Imagine a broken robot shouting No function, it does not work.","cloze_distractors_en":[],"examples":[{"es":"No funciona el botón que intenté presionar.","en":"The button I tried to press does not work."}]},{"spanish_text":"¿Puede repetir?","english_text":"Can you repeat?","section_name":"Travel Phrases","part_of_speech":"question","definition_en":"A polite request asking someone to say something again.","main_translations_es":["¿Puedes repetir?","¿Podría repetir?","¿Me lo puede repetir?"],"collocations":["Can you repeat that?","Can you repeat the last part?","Can you repeat the instructions?","Can you repeat the question?"],"synonyms_en":["Could you say that again?","Would you repeat that?","Say that again, please."],"example_sentence":"Can you repeat what you said?","example_es":"¿Puede repetir lo que dijo?","example_en":"Can you repeat what you said?","mnemonic_en":"Picture a can shouting Can you repeat? to a parrot that answers repetir.","cloze_distractors_en":[],"examples":[{"es":"¿Puede repetir lo que dijo?","en":"Can you repeat what you said?"}]},{"spanish_text":"Más despacio, por favor","english_text":"More slowly, please","section_name":"Travel Phrases","part_of_speech":"expression","definition_en":"A polite request to reduce the speed.","main_translations_es":["Más lento, por favor","Con más lentitud, por favor","Más pausado, por favor"],"collocations":["Could you speak more slowly, please?","Please speak more slowly, please.","Could you explain more slowly, please?"],"synonyms_en":["slow down, please","take it slower","go slower"],"example_sentence":"Could you speak more slowly, please?","example_es":"Podrías hablar más despacio, por favor?","example_en":"Could you speak more slowly, please?","mnemonic_en":"A massive pushy robot crawls slower, politely saying please.","cloze_distractors_en":[],"examples":[{"es":"Podrías hablar más despacio, por favor?","en":"Could you speak more slowly, please?"}]},{"spanish_text":"No entiendo","english_text":"I do not understand","section_name":"Travel Phrases","part_of_speech":"expression","definition_en":"A statement indicating lack of comprehension.","main_translations_es":["No comprendo","No lo entiendo","No me queda claro"],"collocations":["I do not understand what you mean","I do not understand the instructions","I do not understand why","I do not understand the concept"],"synonyms_en":["I don''t get it","I''m confused","I don''t follow"],"example_sentence":"I do not understand what you are saying.","example_es":"No entiendo lo que dices.","example_en":"I do not understand what you are saying.","mnemonic_en":"Picture a person shaking head saying no while saying I do not understand.","cloze_distractors_en":[],"examples":[{"es":"No entiendo lo que dices.","en":"I do not understand what you are saying."}]},{"spanish_text":"¿Habla inglés?","english_text":"Do you speak English?","section_name":"Travel Phrases","part_of_speech":"question","definition_en":"A question asking whether someone can speak English.","main_translations_es":["¿Hablas inglés?","¿Puede hablar inglés?","¿Puedes hablar inglés?"],"collocations":["speak English fluently","speak English well","speak English with confidence"],"synonyms_en":["Can you speak English?","Do you understand English?"],"example_sentence":"Do you speak English?","example_es":"¿Habla inglés?","example_e