n":["ship","vessel","craft"],"example_sentence":"The boat sails calmly across the sea.","example_es":"El barco navega tranquilamente por el mar.","example_en":"The boat sails calmly across the sea.","mnemonic_en":"Picture a boat with a big bar of chocolate on deck, like a barco.","cloze_distractors_en":[],"examples":[{"es":"El barco navega tranquilamente por el mar.","en":"The boat sails calmly across the sea."}]},{"spanish_text":"Playa","english_text":"Beach","section_name":"Travel Phrases","part_of_speech":"noun","definition_en":"A sandy area by the sea where people can swim and sunbathe.","main_translations_es":["Costa","Litoral","Ribera"],"collocations":["beach house","beach day","beach front","beach volleyball"],"synonyms_en":["seashore","shoreline","coast"],"example_sentence":"I love walking along the beach at sunset.","example_es":"Me encanta caminar por la playa al atardecer.","example_en":"I love walking along the beach at sunset.","mnemonic_en":"Imagine a beach where every wave whispers \"play-a\" like a Spanish song","cloze_distractors_en":[],"examples":[{"es":"Me encanta caminar por la playa al atardecer.","en":"I love walking along the beach at sunset."}]},{"spanish_text":"Montaña","english_text":"Mountain","section_name":"Travel Phrases","part_of_speech":"noun","definition_en":"A large natural elevation of the earth''s surface, typically rising abruptly and reaching a peak.","main_translations_es":["pico","cerro","montañón"],"collocations":["mountain range","mountain peak","mountain trail","mountain view"],"synonyms_en":["peak","summit","highland"],"example_sentence":"The mountain rises majestically over the valley.","example_es":"La montaña se alza majestuosa sobre el valle.","example_en":"The mountain rises majestically over the valley.","mnemonic_en":"Imagine a massive mount of cheese topped with a Spanish montaña flag soaring like a mountain.","cloze_distractors_en":[],"examples":[{"es":"La montaña se alza majestuosa sobre el valle.","en":"The mountain rises majestically over the valley."}]}]'::jsonb) as x(
  spanish_text text, english_text text, section_name text, part_of_speech text, definition_en text,
