  and lower(c.english_text) = lower(x.english_text);

-- daily-life (107 cards)
update public.decks set
  title = 'Daily Life', description = 'Useful vocabulary for routines, places, and simple actions.',
  language_from = 'es', language_to = 'en'
where slug = 'daily-life';

update public.cards c set
  section_name = x.section_name, part_of_speech = x.part_of_speech, definition_en = x.definition_en,
  main_translations_es = coalesce(x.main_translations_es, '[]'::jsonb),
  collocations = coalesce(x.collocations, '[]'::jsonb),
  synonyms_en = coalesce(x.synonyms_en, '[]'::jsonb),
  example_sentence = x.example_sentence, example_es = x.example_es, example_en = x.example_en,
  mnemonic_en = coalesce(x.mnemonic_en, c.mnemonic_en),
  cloze_distractors_en = case when jsonb_array_length(coalesce(x.cloze_distractors_en, '[]'::jsonb)) > 0
                              then x.cloze_distractors_en else c.cloze_distractors_en end,
  examples = case when jsonb_array_length(coalesce(x.examples, '[]'::jsonb)) > 0
                  then x.examples else c.examples end
from (select id from public.decks where slug = 'daily-life') dk
