other","She told me to call your mother"],"synonyms_en":["Phone your mother","Give your mother a call","Ring your mother"],"example_sentence":"Call your mother when you get home.","example_es":"Llama a tu madre cuando llegues a casa.","example_en":"Call your mother when you get home.","mnemonic_en":"Imagine calling a llama and telling it call your mother","cloze_distractors_en":[],"examples":[{"es":"Llama a tu madre cuando llegues a casa.","en":"Call your mother when you get home."}]},{"spanish_text":"Envía un mensaje","english_text":"Send a message","section_name":"Daily Life","part_of_speech":"verb (imperative)","definition_en":"To transmit a written or electronic communication to someone.","main_translations_es":["Manda un mensaje","Envía un mensaje","Remite un mensaje"],"collocations":["send a message to","send a message via email","send a message instantly","send a message quickly"],"synonyms_en":["message someone","dispatch a message","transmit a message"],"example_sentence":"Send a message to your friend when you arrive.","example_es":"Envía un mensaje a tu amigo cuando llegues.","example_en":"Send a message to your friend when you arrive.","mnemonic_en":"Picture a courier handing over a note that says SEND like a Spanish envía sign","cloze_distractors_en":[],"examples":[{"es":"Envía un mensaje a tu amigo cuando llegues.","en":"Send a message to your friend when you arrive."}]},{"spanish_text":"Revisa el correo","english_text":"Check the mail","section_name":"Daily Life","part_of_speech":"verb phrase","definition_en":"To look at or retrieve the email messages.","main_translations_es":["Revisa el correo","Chequea el correo","Mira el correo"],"collocations":["check the mail regularly","check the mail before leaving","check the mail daily"],"synonyms_en":["look at the mail","review the mail","inspect the mail"],"example_sentence":"Check the mail before you leave.","example_es":"Revisa el correo antes de salir.","example_en":"Check the mail before you leave.","mn