"expression","definition_en":"A casual way of saying that something is not an issue or that you are happy to help.","main_translations_es":["No hay problema","Todo bien","No ocurre nada"],"collocations":["No problem at all","No problem, thanks","No problem, you''re welcome"],"synonyms_en":["It''s fine","All good","No worries"],"example_sentence":"No problem, we can try again.","example_es":"No pasa nada, podemos intentarlo de nuevo.","example_en":"No problem, we can try again.","mnemonic_en":"No problem—no pasa nada, nothing passes by.","cloze_distractors_en":[],"examples":[{"es":"No pasa nada, podemos intentarlo de nuevo.","en":"No problem, we can try again."}]},{"spanish_text":"Vecino","english_text":"Neighbor","section_name":"Daily Life","part_of_speech":"noun","definition_en":"A person who lives near or next to another person.","main_translations_es":["Vecino","Vecina","colindante"],"collocations":["next‑door neighbor","good neighbor","friendly neighbor","neighboring house"],"synonyms_en":["adjacent resident","nearby dweller","next-door resident"],"example_sentence":"My neighbor helped me carry the boxes.","example_es":"Mi vecino me ayudó a cargar las cajas.","example_en":"My neighbor helped me carry the boxes.","mnemonic_en":"I see my neighbor waving a big ve sign, echoing the Spanish vecino.","cloze_distractors_en":[],"examples":[{"es":"Mi vecino me ayudó a cargar las cajas.","en":"My neighbor helped me carry the boxes."}]},{"spanish_text":"Parque","english_text":"Park","section_name":"Daily Life","part_of_speech":"noun","definition_en":"A public area of land with grass, trees, and facilities for recreation and leisure.","main_translations_es":["Parque","Jardín público","Zona verde"],"collocations":["national park","theme park","park the car"],"synonyms_en":["playground","garden","green space"],"example_sentence":"We go to the park to play soccer.","example_es":"Vamos al parque a jugar al fútbol.","example_en":"We go to the park to play soccer.","mnemonic_en":"Picture a park with a long queue of ducks waiting for bread.","cloze_distractors_en":[],"examples":[{"es":"Vamos al parque a jugar al fútbol.","en":"We go to the park to play soccer."}]}]'::jsonb) as x(
  spanish_text text, english_text text, section_name text, part_of_speech text, definition_en text,
  main_translations_es jsonb, collocations jsonb, synonyms_en jsonb, example_sentence text, example_es text, example_en text, mnemonic_en text, cloze_distractors_en jsonb, examples jsonb
)
where c.deck_id = dk.id
  and lower(c.spanish_text) = lower(x.spanish_text)
  and lower(c.english_text) = lower(x.english_text);

-- basics (105 cards)
update public.decks set
  title = 'English Basics', description = 'Everyday words and short expressions for beginners.',
  language_from = 'es', language_to = 'en'
where slug = 'basics';

update public.cards c set
  section_name = x.section_name, part_of_speech = x.part_of_speech, definition_en = x.definition_en,
  main_translations_es = coalesce(x.main_translations_es, '[]'::jsonb),
  collocations = coalesce(x.collocations, '[]'::jsonb),
  synonyms_en = coalesce(x.synonyms_en, '[]'::jsonb),
  example_sentence = x.example_sentence, example_es = x.example_es, example_en = x.example_en,
  mnemonic_en = coalesce(x.mnemonic_en, c.mnemonic_en),
  cloze_distractors_en = case when jsonb_array_length(coalesce(x.cloze_distractors_en, '[]'::jsonb)) > 0
                              then x.cloze_distractors_en else c.cloze_distractors_en end,
  examples = case when jsonb_array_length(coalesce(x.examples, '[]'::jsonb)) > 0
                  then x.examples else c.examples end
from (select id from public.decks where slug = 'basics') dk
