beled CINCO.","cloze_distractors_en":[],"examples":[{"es":"Tengo cinco manzanas.","en":"I have five apples."}]},{"spanish_text":"Seis","english_text":"Six","section_name":"English Basics","part_of_speech":"numeral","definition_en":"The integer that comes after five and before seven.","main_translations_es":["seis","el número seis","el 6"],"collocations":["six-pack","six feet under","six of one, half a dozen","sixth sense"],"synonyms_en":["half a dozen","sextet"],"example_sentence":"Six people entered the cinema.","example_es":"Seis personas entraron al cine.","example_en":"Six people entered the cinema.","mnemonic_en":"Imagine six dice shouting seis as they tumble across the table.","cloze_distractors_en":[],"examples":[{"es":"Seis personas entraron al cine.","en":"Six people entered the cinema."}]},{"spanish_text":"Siete","english_text":"Seven","section_name":"English Basics","part_of_speech":"noun","definition_en":"The cardinal number that comes after six and before eight.","main_translations_es":["siete","el número siete"],"collocations":["seven wonders","seven days","seven seas","seven years"],"synonyms_en":["VII","septet","heptad"],"example_sentence":"I have seven books on my shelf.","example_es":"Tengo siete libros en mi estantería.","example_en":"I have seven books on my shelf.","mnemonic_en":"Picture a lucky seven dice shouting siete as it rolls.","cloze_distractors_en":[],"examples":[{"es":"Tengo siete libros en mi estantería.","en":"I have seven books on my shelf."}]},{"spanish_text":"Ocho","english_text":"Eight","section_name":"English Basics","part_of_speech":"noun","definition_en":"The number that comes after seven and before nine.","main_translations_es":["el ocho","el número ocho","el dígito ocho"],"collocations":["eight ball","eight years old","eightfold","eight miles"],"synonyms_en":["octet","eightfold"],"example_sentence":"I have eight apples.","example_es":"Tengo ocho manzanas.","example_en":"I have eight apples.","mnemonic_en":"Picture an octopus