tive","definition_en":"Recently created, discovered, or introduced; not existing before.","main_translations_es":["Reciente","Fresco","Novedoso"],"collocations":["brand new","new and improved","new generation","new era"],"synonyms_en":["fresh","brand‑new","recent"],"example_sentence":"I bought a new car.","example_es":"Compré un coche nuevo.","example_en":"I bought a new car.","mnemonic_en":"Picture a newborn baby holding a fresh, new blanket, echoing the nu sound of nuevo","cloze_distractors_en":[],"examples":[{"es":"Compré un coche nuevo.","en":"I bought a new car."}]},{"spanish_text":"Viejo","english_text":"Old","section_name":"English Basics","part_of_speech":"adjective","definition_en":"Having existed or been in use for a long time; not new.","main_translations_es":["antiguo","anciano","vetusto"],"collocations":["old friend","old habits","old age","old-fashioned"],"synonyms_en":["ancient","aged","elderly"],"example_sentence":"The old book is on the shelf.","example_es":"El libro viejo está en la estantería.","example_en":"The old book is on the shelf.","mnemonic_en":"Picture an old wizard saying VIEJO while opening a dusty ancient book.","cloze_distractors_en":[],"examples":[{"es":"El libro viejo está en la estantería.","en":"The old book is on the shelf."}]},{"spanish_text":"Feliz","english_text":"Happy","section_name":"English Basics","part_of_speech":"adjective","definition_en":"Feeling or showing pleasure, contentment, or joy.","main_translations_es":["Contento","Alegre","Jubiloso"],"collocations":["happy birthday","happy hour","happy ending","happy couple"],"synonyms_en":["joyful","cheerful","content"],"example_sentence":"I am happy with the results.","example_es":"Estoy feliz con los resultados.","example_en":"I am happy with the results.","mnemonic_en":"A happy clown shouts Feliz as he receives a big birthday cake.","cloze_distractors_en":[],"examples":[{"es":"Estoy feliz con los resultados.","en":"I am happy with the results."}]}]'::jsonb) as x(
