rd","cultured milk"],"example_sentence":"I like to eat yogurt with fruit for breakfast.","example_es":"Me gusta comer yogur con frutas en el desayuno.","example_en":"I like to eat yogurt with fruit for breakfast.","mnemonic_en":"Imagine a yogurt cup wearing a tiny yogur label like a flag.","cloze_distractors_en":[],"examples":[{"es":"Me gusta comer yogur con frutas en el desayuno.","en":"I like to eat yogurt with fruit for breakfast."}]},{"spanish_text":"Queso","english_text":"Cheese","section_name":"Cafe Counter Basics","part_of_speech":"noun","definition_en":"A dairy product made from curdled milk, commonly eaten as food.","main_translations_es":["queso","queso curado","queso fresco"],"collocations":["cheese plate","cheese sandwich","cheese sauce","cheese cake"],"synonyms_en":["dairy product","curd"],"example_sentence":"I like to eat cheese with crackers.","example_es":"Me gusta comer queso con galletas.","example_en":"I like to eat cheese with crackers.","mnemonic_en":"Say cheese and picture a mouse shouting queso as it nibbles the cheesy slice.","cloze_distractors_en":[],"examples":[{"es":"Me gusta comer queso con galletas.","en":"I like to eat cheese with crackers."}]},{"spanish_text":"Mantequilla","english_text":"Butter","section_name":"Cafe Counter Basics","part_of_speech":"noun","definition_en":"A pale yellow dairy product made by churning cream, used as a spread or in cooking.","main_translations_es":["Mantequilla","Manteca de leche"],"collocations":["spread butter","butter up","melt butter","butter the toast"],"synonyms_en":["dairy spread","spread","butterfat"],"example_sentence":"I like to spread butter on the bread.","example_es":"Me gusta untar mantequilla en el pan.","example_en":"I like to spread butter on the bread.","mnemonic_en":"A buttered bat spreads mantequilla on toast, melting like gold.","cloze_distractors_en":[],"examples":[{"es":"Me gusta untar mantequilla en el pan.","en":"I like to spread butter on the bread."}]},{"spanish_text":"Mermelad