rs_en":[],"examples":[{"es":"El cliente pidió una factura detallada.","en":"The customer requested a detailed invoice."}]},{"spanish_text":"Camarero","english_text":"Server","section_name":"Cafe Counter Basics","part_of_speech":"noun","definition_en":"A person who serves food and drinks to customers in a restaurant or café.","main_translations_es":["Mesero","Mozo"],"collocations":["web server","file server","server farm","server room"],"synonyms_en":["waiter","waitstaff","attendant"],"example_sentence":"The server brought the check quickly.","example_es":"El camarero trajo la cuenta rápidamente.","example_en":"The server brought the check quickly.","mnemonic_en":"Picture a server handing a tray to a smiling camaro driver, the camarero.","cloze_distractors_en":[],"examples":[{"es":"El camarero trajo la cuenta rápidamente.","en":"The server brought the check quickly."}]},{"spanish_text":"Barista","english_text":"Barista","section_name":"Cafe Counter Basics","part_of_speech":"noun","definition_en":"A person who prepares and serves coffee and other drinks, typically in a coffee shop.","main_translations_es":["camarero de café","preparador de café"],"collocations":["friendly barista","expert barista","barista training"],"synonyms_en":[],"example_sentence":"The barista made a perfect cappuccino.","example_es":"El barista preparó un cappuccino perfecto.","example_en":"The barista made a perfect cappuccino.","mnemonic_en":null,"cloze_distractors_en":[],"examples":[{"es":"El barista preparó un cappuccino perfecto.","en":"The barista made a perfect cappuccino."}]},{"spanish_text":"Caja registradora","english_text":"Cash register","section_name":"Cafe Counter Basics","part_of_speech":"noun","definition_en":"A machine used in stores to record sales transactions and hold cash.","main_translations_es":["Caja registradora","Registradora","Caja de cobro"],"collocations":["open the cash register","cash register drawer","cash register receipt","cash register tape"],"synonyms_en":["till","register","point-of-sale terminal"],"example_sentence":"The cash register ran out of paper.","example_es":"La caja registradora se quedó sin papel.","example_en":"The cash register ran out of paper.","mnemonic_en":"Picture a cash register as a giant caja that registers every cash coin.","cloze_distractors_en":[],"examples":[{"es":"La caja registradora se quedó sin papel.","en":"The cash register ran out of paper."}]},{"spanish_text":"Pago","english_text":"Payment","section_name":"Cafe Counter Basics","part_of_speech":"noun","definition_en":"A sum of money given in exchange for goods, services, or to settle a debt.","main_translations_es":["Abono","Desembolso","Cancelación"],"collocations":["make a payment","payment method","payment terms","payment deadline"],"synonyms_en":["remittance","settlement","fee"],"example_sentence":"The payment will be made tomorrow.","example_es":"El pago se realizará mañana.","example_en":"The payment will be made tomorrow.","mnemonic_en":"Think of a PAYing MENTor handing a coin for each PAGO you settle.","cloze_distractors_en":[],"examples":[{"es":"El pago se realizará mañana.","en":"The payment will be made tomorrow."}]},{"spanish_text":"Tarjeta","english_text":"Card","section_name":"Cafe Counter Basics","part_of_speech":"noun","definition_en":"A small piece of paper or plastic used for identification, payment, or playing games.","main_translations_es":["cédula","credencial","carné"],"collocations":["credit card","gift card","business card","card game"],"synonyms_en":["ticket","badge","credential"],"example_sentence":"I need my credit card to pay the bill.","example_es":"Necesito mi tarjeta de crédito para pagar la cuenta.","example_en":"I need my credit card to pay the bill.","mnemonic_en":"I picture a card shaped like a tiny tarjeta with a car driving on it.","cloze_distractors_en":[],"examples":[{"es":"Necesito mi tarjeta de crédito para pagar la cuenta.","en":"I need my credit card to pay the bill."}]},{"spanish_text":"Efectivo","english_text":"Cash","section_name":"Cafe Counter Basics","part_of_speech":"noun","definition_en":"Money in the form of coins and banknotes that is readily available for transactions.","main_translations_es":["Dinero en efectivo","Dinero","Plata"],"collocations":["cash flow","cash register","cash on hand","cash payment"],"synonyms_en":["money","currency","hard cash"],"example_sentence":"I prefer to pay in cash.","example_es":"Prefiero pagar en efectivo.","example_en":"I prefer to pay in cash.","mnemonic_en":"Imagine a cash register shouting Efectivo as it prints money.","cloze_distractors_en":[],"examples":[{"es":"Prefiero pagar en efectivo.","en":"I prefer to pay in cash."}]},{"spanish_text":"Cambio","english_text":"Change","section_name":"Cafe Counter Basics","part_of_speech":"noun","definition_en":"the act or result of making something different, a transformation or alteration.","main_translations_es":["alteración","modificación","variación"],"collocations":["make a change","change of pace","change your mind","change the subject"],"synonyms_en":["alteration","modification","shift"],"example_sentence":"The change in weather affects me.","example_es":"El cambio de clima me afecta.","example_en":"The change in weather affects me.","mnemonic_en":"Picture a cashier handing you a fresh stack of bills, a cambio, to remember Change.","cloze_distractors_en":[],"examples":[{"es":"El cambio de clima me afecta.","en":"The change in weather affects me."}]},{"spanish_text":"Propina","english_text":"Tip","section_name":"Cafe Counter Basics","part_of_speech":"noun","definition_en":"A small amount of money given to someone as a gratuity for their service.","main_translations_es":["propina","corte","gratificación"],"collocations":["leave a tip","tip the waiter","tip jar","tip amount"],"synonyms_en":["gratuity","bonus","extra"],"example_sentence":"I left a good tip for the waiter.","example_es":"Dejé una buena propina al camarero.","example_en":"I left a good tip for the waiter.","mnemonic_en":"Tip the waiter with a tiny propina, like sprinkling a pinch of salt.","cloze_distractors_en":[],"examples":[{"es":"Dejé una buena propina al camarero.","en":"I left a good tip for the waiter."}]},{"spanish_text":"Recibo","english_text":"Receipt","section_name":"Cafe Counter Basics","part_of_speech":"noun","definition_en":"A written acknowledgment that something, typically a payment, has been received.","main_translations_es":["Comprobante","Factura","Ticket"],"collocations":["receipt of payment","receipt number","receipt for"],"synonyms_en":["sales slip","proof of purchase","transaction record"],"example_sentence":"I kept the receipt of the purchase so I could return the item.","example_es":"Guardé el recibo de la compra para poder devolver el artículo.","example_en":"I kept the receipt of the purchase so I could return the item.","mnemonic_en":"Picture a receipt with the bold word Recibo printed on it.","cloze_distractors_en":[],"examples":[{"es":"Guardé el recibo de la compra para poder devolver el artículo.","en":"I kept the receipt of the purchase so I could return the item."}]},{"spanish_text":"Cuenta separada","english_text":"Separate bill","section_name":"Cafe Counter Basics","part_of_speech":"noun","definition_en":"A bill that is issued separately from other charges.","main_translations_es":["Factura separada","Cuenta individual","Dividir la cuenta"],"collocations":["ask for a separate bill","receive a separate bill","separate bill for each person"],"synonyms_en":["individual check","split check","separate check"],"example_sentence":"Could you bring me the separate bill, please?","example_es":"¿Podrías traerme la cuenta separada, por favor?","example_en":"Could you bring me the separate bill, please?","mnemonic_en":"Picture a separate bill, a split cuenta left on the table.","cloze_distractors_en":[],"examples":[{"es":"¿Podrías traerme la cuenta separada, por favor?","en":"Could you bring me the separate bill, please?"}]},{"spanish_text":"¿Puedo pagar ahora?","english_text":"Can I pay now?","section_name":"Cafe Counter Basics","part_of_speech":"question","definition_en":"Asking if it is possible to make a payment now.","main_translations_es":["¿Puedo pagar ya?","¿Me dejo pagar ahora?","¿Es posible pagar ahora?"],"collocations":["Can I pay now or later?","Can I pay now with a credit card?","Can I pay now and get a receipt?"],"synonyms_en":["May I pay now?","Is it possible to pay now?","Can I settle the bill now?"],"example_sentence":"Can I pay now?","example_es":"¿Puedo pagar ahora?","example_en":"Can I pay now?","mnemonic_en":"Imagine a tin can paying a bill right now, shouting ''Can I pay now?'' like a Spanish shopper.","cloze_distractors_en":[],"examples":[{"es":"¿Puedo pagar ahora?","en":"Can I pay now?"}]},{"spanish_text":"¿Aceptan tarjeta?","english_text":"Do you take cards?","section_name":"Cafe Counter Basics","part_of_speech":"question","definition_en":"A polite way to ask if a business accepts credit or debit cards.","main_translations_es":["¿Aceptan tarjetas?","¿Se puede pagar con tarjeta?","¿Pagan con tarjeta?"],"collocations":["Do you take cards?","We take cards.","Do you accept credit cards?","We accept all major cards."],"synonyms_en":["Accept cards","Take credit cards","Card payment accepted"],"example_sentence":"Do you take cards?","example_es":"¿Aceptan tarjeta?","example_en":"Do you take cards?","mnemonic_en":"Visualize a shopkeeper holding a deck, asking Accept an card? Do you take cards?","cloze_distractors_en":[],"examples":[{"es":"¿Aceptan tarjeta?","en":"Do you take cards?"}]},{"spanish_text":"Falta algo","english_text":"Something is missing","section_name":"Cafe Counter Basics","part_of_speech":"expression","definition_en":"A statement indicating that an item or element is absent.","main_translations_es":["Algo falta","Se echa de menos algo","Hay algo que falta"],"collocations":["something is missing from","something is missing here","something is missing altogether","something is missing in the report"],"synonyms_en":["There''s a gap","A piece is absent","It''s incomplete"],"example_sentence":"Something is missing from the song; it doesn''t sound complete.","example_es":"Falta algo en la canción; no suena completa.","example_en":"Something is missing from the song; it doesn''t sound complete.","mnemonic_en":"A faulty gap appears where the word ''falta'' signals something is missing","cloze_distractors_en":[],"examples":[{"es":"Falta algo en la canción; no suena completa.","en":"Something is missing from the song; it doesn''t sound complete."}]},{"spanish_text":"Sin cebolla","english_text":"No onion","section_name":"Cafe Counter Basics","part_of_speech":"expression","definition_en":"A statement indicating that there is no onion.","main_translations_es":["Sin cebolla","Sin cebollas","Sin cebolla añadida"],"collocations":["no onion pizza","no onion, please","no onion in the salad"],"synonyms_en":["without onion","onion-free"],"example_sentence":"I would like the pizza without onion, please.","example_es":"Quisiera la pizza sin cebolla, por favor.","example_en":"I would like the pizza without onion, please.","mnemonic_en":"Imagine a No Onion sign with a sin wave spilling over a bowl (cebula).","cloze_distractors_en":[],"examples":[{"es":"Quisiera la pizza sin cebolla, por favor.","en":"I would like the pizza without onion, please."}]},{"spanish_text":"Sin leche","english_text":"No milk","section_name":"Cafe Counter Basics","part_of_speech":"noun phrase","definition_en":"A statement indicating that there is no milk.","main_translations_es":["Sin leche","No hay leche","Sin leche disponible"],"collocations":["No milk, please","I want coffee, no milk","No milk in my tea"],"synonyms_en":["dairy‑free","milkless","without milk"],"example_sentence":"I want coffee with no milk.","example_es":"Quiero café sin leche.","example_en":"I want coffee with no milk.","mnemonic_en":"Picture a cow holding a sign that reads No milk, because it’s sin (without) any dairy.","cloze_distractors_en":[],"examples":[{"es":"Quiero café sin leche.","en":"I want coffee with no milk."}]},{"spanish_text":"Más agua","english_text":"More water","section_name":"Cafe Counter Basics","part_of_speech":"noun phrase","definition_en":"An increased amount of water.","main_translations_es":["Más agua","Más líquido","Más agua, por favor"],"collocations":["drink more water","add more water","need more water","more water, please"],"synonyms_en":["additional water","extra water","increased water"],"example_sentence":"I would like more water, please.","example_es":"Quiero más agua, por favor.","example_en":"I would like more water, please.","mnemonic_en":"Imagine a thirsty dog shouting más agua for more water.","cloze_distractors_en":[],"examples":[{"es":"Quiero más agua, por favor.","en":"I would like more water, please."}]},{"spanish_text":"Otra servilleta","english_text":"Another napkin","section_name":"Cafe Counter Basics","part_of_speech":"noun phrase","definition_en":"A second napkin, used as a replacement or additional one.","main_translations_es":["Otra servilleta","Una servilleta más","Otra toalla de mesa"],"collocations":["hand me another napkin","need another napkin","grab another napkin","spill the sauce, get another napkin"],"synonyms_en":["a spare napkin","extra napkin","additional napkin"],"example_sentence":"Can you pass me another napkin, please?","example_es":"¿Puedes pasarme otra servilleta, por favor?","example_en":"Can you pass me another napkin, please?","mnemonic_en":"Picture a second napkin, because ''another napkin'' sounds like ''otra napkin'' in Spanish.","cloze_distractors_en":[],"examples":[{"es":"¿Puedes pasarme otra servilleta, por favor?","en":"Can you pass me another napkin, please?"}]},{"spanish_text":"La mesa está sucia","english_text":"The table is dirty","section_name":"Cafe Counter Basics","part_of_speech":"expression","definition_en":"A statement indicating that the table is not clean.","main_translations_es":["La mesa está mugrienta","La mesa está sucia","La mesa está ensuciada"],"collocations":["dirty table","clean the table","wipe the table","clear the table"],"synonyms_en":["The table is filthy","The table is soiled","The table is grimy"],"example_sentence":"The table is dirty.","example_es":"La mesa está sucia.","example_en":"The table is dirty.","mnemonic_en":"Picture a table covered in mud, just like a sucia mesa.","cloze_distractors_en":[],"examples":[{"es":"La mesa está sucia.","en":"The table is dirty."}]},{"spanish_text":"Está delicioso","english_text":"It is delicious","section_name":"Cafe Counter Basics","part_of_speech":"expression","definition_en":"A statement indicating that something tastes very good.","main_translations_es":["Qué rico","Está sabroso","Se ve delicioso"],"collocations":["This dish is delicious","That was delicious","It tastes delicious","The food is delicious"],"synonyms_en":["It''s tasty","It''s scrumptious","It''s flavorful"],"example_sentence":"The cake is delicious.","example_es":"El pastel está delicioso.","example_en":"The cake is delicious.","mnemonic_en":"Picture a chef tasting soup and saying It is delish-ous while pointing at the menu that reads ESTA.","cloze_distractors_en":[],"examples":[{"es":"El pastel está delicioso.","en":"The cake is delicious."}]},{"spanish_text":"Está muy caliente","english_text":"It is very hot","section_name":"Cafe Counter Basics","part_of_speech":"expression","definition_en":"A statement indicating that the temperature is high.","main_translations_es":["Hace mucho calor","Está muy caluroso","Hace un calor tremendo"],"collocations":["It''s very hot today","It''s very hot outside","It''s very hot in here","It''s very hot during summer"],"synonyms_en":["It''s scorching","It''s sweltering","It''s boiling"],"example_sentence":"The coffee is very hot.","example_es":"El café está muy caliente.","example_en":"The coffee is very hot.","mnemonic_en":"Picture the sun shouting Caliente as the air becomes very hot.","cloze_distractors_en":[],"examples":[{"es":"El café está muy caliente.","en":"The coffee is very hot."}]},{"spanish_text":"Buen provecho","english_text":"Enjoy your meal","section_name":"Cafe Counter Basics","part_of_speech":"expression","definition_en":"A polite phrase said to someone before they start eating, wishing them a pleasant meal.","main_translations_es":["Que aproveche","¡A comer!","Disfruta tu comida"],"collocations":["Enjoy your meal!","Enjoy your meal, everyone","Enjoy your meal and dessert"],"synonyms_en":["Have a nice meal","Eat well","Enjoy your food"],"example_sentence":"Enjoy your meal!","example_es":"¡Buen provecho!","example_en":"Enjoy your meal!","mnemonic_en":"When you prove a chew, you say enjoy your meal.","cloze_distractors_en":[],"examples":[{"es":"¡Buen provecho!","en":"Enjoy your meal!"}]}]'::jsonb) as x(
  spanish_text text, english_text text, section_name text, part_of_speech text, definition_en text,
  main_translations_es jsonb, collocations jsonb, synonyms_en jsonb, example_sentence text, example_es text, example_en text, mnemonic_en text, cloze_distractors_en jsonb, examples jsonb
)
where c.deck_id = dk.id
  and lower(c.spanish_text) = lower(x.spanish_text)
  and lower(c.english_text) = lower(x.english_text);

-- english-c1-vocabulary (100 cards)
update public.decks set
  title = 'English C1 Vocabulary', description = 'Advanced English words and expressions for upper-level learners.',
  language_from = 'es', language_to = 'en'
where slug = 'english-c1-vocabulary';

update public.cards c set
  section_name = x.section_name, part_of_speech = x.part_of_speech, definition_en = x.definition_en,
  main_translations_es = coalesce(x.main_translations_es, '[]'::jsonb),
  collocations = coalesce(x.collocations, '[]'::jsonb),
  synonyms_en = coalesce(x.synonyms_en, '[]'::jsonb),
  example_sentence = x.example_sentence, example_es = x.example_es, example_en = x.example_en,
  mnemonic_en = coalesce(x.mnemonic_en, c.mnemonic_en),
  cloze_distractors_en = case when jsonb_array_length(coalesce(x.cloze_distractors_en, '[]'::jsonb)) > 0
                              then x.cloze_distractors_en else c.cloze_distractors_en end,
  examples = case when jsonb_array_length(coalesce(x.examples, '[]'::jsonb)) > 0
                  then x.examples else c.examples end
from (select id from public.decks where slug = 'english-c1-vocabulary') dk
cross join jsonb_to_recordset('[{"spanish_text":"Aclarar","english_text":"Clarify","section_name":"English C1 Vocabulary","part_of_speech":"verb","definition_en":"to make something clear or easier to understand","main_translations_es":["Explicar","Precisar","Elucidar"],"collocations":["clarify the situation","clarify your doubts","clarify the meaning","clarify the issue"],"synonyms_en":["explain","elucidate","make clear"],"example_sentence":"Could you clarify the steps we need to follow to complete the project?","example_es":"¿Podrías aclarar los pasos que debemos seguir para completar el proyecto?","example_en":"Could you clarify the steps we need to follow to complete the project?","mnemonic_en":"Imagine a clear window, ''a clear'' view, to clarify the meaning.","cloze_distractors_en":[],"examples":[{"es":"¿Podrías aclarar los pasos que debemos seguir para completar el proyecto?","en":"Could you clarify the steps we need to follow to complete the project?"}]},{"spanish_text":"Recalcar","english_text":"Emphasize","section_name":"English C1 Vocabulary","part_of_speech":"verb","definition_en":"To give special importance or attention to something.","main_translations_es":["Destacar","Subrayar","Enfatizar"],"collocations":["emphasize the importance","emphasize the need","emphasize that","emphasize the point"],"synonyms_en":["highlight","stress","underscore"],"example_sentence":"The teacher wanted to emphasize the importance of punctuality.","example_es":"El profesor quiso recalcar la importancia de la puntualidad.","example_en":"The teacher wanted to emphasize the importance of punctuality.","mnemonic_en":"A RECALL CAR EMphasizes the road sign, so you never miss the point.","cloze_distractors_en":[],"examples":[{"es":"El profesor quiso recalcar la importancia de la puntualidad.","en":"The teacher wanted to emphasize the importance of punctuality."}]},{"spanish_text":"Sostener","english_text":"Maintain","section_name":"English C1 Vocabulary","part_of_speech":"verb","definition_en":"To keep something in its existing state or condition.","main_translations_es":["Mantener","Conservar","Sustentar"],"collocations":["maintain a balance","maintain control","maintain the status quo","maintain relationships"],"synonyms_en":["preserve","keep up","sustain"],"example_sentence":"It is important to maintain a balanced diet to stay healthy.","example_es":"Es importante sostener una dieta equilibrada para mantenerse saludable.","example_en":"It is important to maintain a balanced diet to stay healthy.","mnemonic_en":"Picture a sturdy stand (sostener) that you maintain, never letting the banner fall.","cloze_distractors_en":[],"examples":[{"es":"Es importante sostener una dieta equilibrada para mantenerse saludable.","en":"It is important to maintain a balanced diet to stay healthy."}]},{"spanish_text":"Cuestionar","english_text":"Challenge","section_name":"English C1 Vocabulary","part_of_speech":"verb","definition_en":"To invite someone to compete or to question the validity of something.","main_translations_es":["Desafiar","Poner en duda","Interrogar"],"collocations":["rise to the challenge","meet the challenge","challenge yourself","face a challenge"],"synonyms_en":["contest","oppose","question"],"example_sentence":"It''s important to challenge the sources before believing them.","example_es":"Es importante cuestionar las fuentes antes de creer en ellas.","example_en":"It''s important to challenge the sources before believing them.","mnemonic_en":"Picture a chalice smashing a question mark—challenge means to cuestionar.","cloze_distractors_en":[],"examples":[{"es":"Es importante cuestionar las fuentes antes de creer en ellas.","en":"It''s important to challenge the sources before believing them."}]},{"spanish_text":"Respaldar","english_text":"Substantiate","section_name":"English C1 Vocabulary","part_of_speech":"verb","definition_en":"To provide evidence or proof that something is true or valid.","main_translations_es":["Apoyar","Confirmar","Sustentar"],"collocations":["substantiate a claim","substantiate the evidence","substantiate the allegations","substantiate findings"],"synonyms_en":["prove","validate","confirm"],"example_sentence":"The researcher must substantiate his conclusions with solid data.","example_es":"El investigador debe respaldar sus conclusiones con datos sólidos.","example_en":"The researcher must substantiate his conclusions with solid data.","mnemonic_en":"Picture a submarine planting a sturdy stance on a ship''s back to support it","cloze_distractors_en":[],"examples":[{"es":"El investigador debe respaldar sus conclusiones con datos sólidos.","en":"The researcher must substantiate his conclusions with solid data."}]},{"spanish_text":"Desestimar","english_text":"Dismiss","section_name":"English C1 Vocabulary","part_of_speech":"verb","definition_en":"To reject, disregard, or send away someone or something.","main_translations_es":["Rechazar","Descartar","Desestimar"],"collocations":["dismiss a case","dismiss the allegations","dismiss the idea","dismiss someone from their job"],"synonyms_en":["reject","send away","turn down"],"example_sentence":"The judge decided to dismiss the case due to lack of evidence.","example_es":"El juez decidió desestimar el caso por falta de pruebas.","example_en":"The judge decided to dismiss the case due to lack of evidence.","mnemonic_en":"Picture a missed call being ignored, a dis-miss that dismisses the message.","cloze_distractors_en":[],"examples":[{"es":"El juez decidió desestimar el caso por falta de pruebas.","en":"The judge decided to dismiss the case due to lack of evidence."}]},{"spanish_text":"Impulsar","english_text":"Foster","section_name":"English C1 Vocabulary","part_of_speech":"verb","definition_en":"To encourage or promote the development or growth of something.","main_translations_es":["Promover","Estimular","Fomentar"],"collocations":["foster growth","foster relationships","foster development","foster innovation"],"synonyms_en":["encourage","promote","nurture"],"example_sentence":"The government wants to foster technological innovation in the country.","example_es":"El gobierno quiere impulsar la innovación tecnológica en el país.","example_en":"The government wants to foster technological innovation in the country.","mnemonic_en":"Imagine a foster parent giving a child a strong push, a force that impulsar forward.","cloze_distractors_en":[],"examples":[{"es":"El gobierno quiere impulsar la innovación tecnológica en el país.","en":"The government wants to foster technological innovation in the country."}]},{"spanish_text":"Conllevar","english_text":"Entail","section_name":"English C1 Vocabulary","part_of_speech":"verb","definition_en":"To involve or require something as a necessary consequence.","main_translations_es":["implicar","suponer","acarrear"],"collocations":["entail consequences","entail risks","entail a cost","entail responsibility"],"synonyms_en":["involve","require","necessitate"],"example_sentence":"This project entails a great financial risk.","example_es":"Este proyecto conlleva un gran riesgo financiero.","example_en":"This project entails a great financial risk.","mnemonic_en":"A tangled tail (en-tail) carries the load, just like conllevar means to involve","cloze_distractors_en":[],"examples":[{"es":"Este proyecto conlleva un gran riesgo financiero.","en":"This project entails a great financial risk."}]},{"spanish_text":"Mitigar","english_text":"Mitigate","section_name":"English C1 Vocabulary","part_of_speech":"verb","definition_en":"To make something less severe, harmful, or painful.","main_translations_es":["Aliviar","Reducir","Suavizar"],"collocations":["mitigate the risk","mitigate the damage","mitigate the effects","mitigate the impact"],"synonyms_en":["alleviate","lessen","reduce"],"example_sentence":"The government implemented new policies to mitigate the effects of climate change.","example_es":"El gobierno implementó nuevas políticas para mitigar los efectos del cambio climático.","example_en":"The government implemented new policies to mitigate the effects of climate change.","mnemonic_en":"Picture a tiny mite gently soothing a blaze, so the fire is mitigated.","cloze_distractors_en":[],"examples":[{"es":"El gobierno implementó nuevas políticas para mitigar los efectos del cambio climático.","en":"The government implemented new policies to mitigate the effects of climate change."}]},{"spanish_text":"Agravar","english_text":"Exacerbate","section_name":"English C1 Vocabulary","part_of_speech":"verb","definition_en":"To make a problem, situation, or feeling worse or more intense.","main_translations_es":["Empeorar","Intensificar","Agravarse"],"collocations":["exacerbate the problem","exacerbate tensions","exacerbate symptoms","exacerbate the situation"],"synonyms_en":["worsen","intensify","aggravate"],"example_sentence":"Lack of sleep can exacerbate the symptoms of depression.","example_es":"La falta de sueño puede agravar los síntomas de la depresión.","example_en":"Lack of sleep can exacerbate the symptoms of depression.","mnemonic_en":"Picture an ex‑ace chef adding extra sour sauce, making the dish even worse.","cloze_distractors_en":[],"examples":[{"es":"La falta de sueño puede agravar los síntomas de la depresión.","en":"Lack of sleep can exacerbate the symptoms of depression."}]},{"spanish_text":"Plantear","english_text":"Put forward","section_name":"English C1 Vocabulary","part_of_speech":"verb","definition_en":"To propose or suggest something for consideration.","main_translations_es":["proponer","exponer","presentar"],"collocations":["put forward a proposal","put forward an argument","put forward a suggestion","put forward a theory"],"synonyms_en":["propose","suggest","present"],"example_sentence":"The committee decided to put forward a new strategy for the next year.","example_es":"El comité decidió plantear una nueva estrategia para el próximo año.","example_en":"The committee decided to put forward a new strategy for the next year.","mnemonic_en":"Plant a seed and put forward your idea, just like you would plantear a new garden.","cloze_distractors_en":[],"examples":[{"es":"El comité decidió plantear una nueva estrategia para el próximo año.","en":"The committee decided to put forward a new strategy for the next year."}]},{"spanish_text":"Abordar","english_text":"Address","section_name":"English C1 Vocabulary","part_of_speech":"verb","definition_en":"To direct attention to, discuss, or deal with something.","main_translations_es":["Tratar","Enfocar","Abordar"],"collocations":["address the issue","address a problem","address the audience","address the question"],"synonyms_en":["deal with","tackle","speak to"],"example_sentence":"The committee must address the climate change problem as soon as possible.","example_es":"El comité debe abordar el problema del cambio climático lo antes posible.","example_en":"The committee must address the climate change problem as soon as possible.","mnemonic_en":"Imagine a fancy dress boarding a ship, so you address (abordar) the problem.","cloze_distractors_en":[],"examples":[{"es":"El comité debe abordar el problema del cambio climático lo antes posible.","en":"The committee must address the climate change problem as soon as possible."}]},{"spanish_text":"Determinar","english_text":"Determine","section_name":"English C1 Vocabulary","part_of_speech":"verb","definition_en":"To find out or establish something through investigation, calculation, or reasoning.","main_translations_es":["Establecer","Fijar","Precisar"],"collocations":["determine the cause","determine the outcome","determine the best approach","determine if"],"synonyms_en":["ascertain","establish","figure out"],"example_sentence":"Scientists must determine the cause of the outbreak.","example_es":"Los científicos deben determinar la causa del brote.","example_en":"Scientists must determine the cause of the outbreak.","mnemonic_en":"Picture a judge stamping a verdict, saying determine as if shouting the Spanish word determinar.","cloze_distractors_en":[],"examples":[{"es":"Los científicos deben determinar la causa del brote.","en":"Scientists must determine the cause of the outbreak."}]},{"spanish_text":"Comprensivo","english_text":"Comprehensive","section_name":"English C1 Vocabulary","part_of_speech":"adjective","definition_en":"Including all or nearly all elements or aspects; thorough and complete.","main_translations_es":["amplio","extenso","integral"],"collocations":["comprehensive review","comprehensive plan","comprehensive guide","comprehensive analysis"],"synonyms_en":["thorough","all‑inclusive","extensive"],"example_sentence":"The report is very comprehensive and covers all aspects of the project.","example_es":"El informe es muy comprensivo y cubre todos los aspectos del proyecto.","example_en":"The report is very comprehensive and covers all aspects of the project.","mnemonic_en":"A COMPREHENSIVE textbook feels like a comprensivo hug that covers every detail.","cloze_distractors_en":[],"examples":[{"es":"El informe es muy comprensivo y cubre todos los aspectos del proyecto.","en":"The report is very comprehensive and covers all aspects of the project."}]},{"spanish_text":"Matizado","english_text":"Nuanced","section_name":"English C1 Vocabulary","part_of_speech":"adjective","definition_en":"Having subtle distinctions or variations in meaning, expression, or tone.","main_translations_es":["Sutil","Detallado","Con matices"],"collocations":["nuanced argument","nuanced perspective","nuanced approach","nuanced understanding"],"synonyms_en":["subtle","refined","complex"],"example_sentence":"His argument is nuanced and considers several points of view.","example_es":"Su argumento es matizado y considera varios puntos de vista.","example_en":"His argument is nuanced and considers several points of view.","mnemonic_en":"New ants add subtle shades to the painting, making it nuanced.","cloze_distractors_en":[],"examples":[{"es":"Su argumento es matizado y considera varios puntos de vista.","en":"His argument is nuanced and considers several points of view."}]},{"spanish_text":"Ambiguo","english_text":"Ambiguous","section_name":"English C1 Vocabulary","part_of_speech":"adjective","definition_en":"Open to more than one interpretation or having an unclear meaning.","main_translations_es":["Vago","Confuso","Equívoco"],"collocations":["ambiguous meaning","ambiguous statement","ambiguous result","ambiguous situation"],"synonyms_en":["unclear","vague","equivocal"],"example_sentence":"The message of the ad was ambiguous, so many interpreted it in different ways.","example_es":"El mensaje del anuncio era ambiguo, por lo que muchos lo interpretaron de distintas maneras.","example_en":"The message of the ad was ambiguous, so many interpreted it in different ways.","mnemonic_en":"Picture a vague sign that reads ambi‑guo, reminding you the meaning is ambiguous","cloze_distractors_en":[],"examples":[{"es":"El mensaje del anuncio era ambiguo, por lo que muchos lo interpretaron de distintas maneras.","en":"The message of the ad was ambiguous, so many interpreted it in different ways."}]},{"spanish_text":"Coherente","english_text":"Coherent","section_name":"English C1 Vocabulary","part_of_speech":"adjective","definition_en":"Logical, consistent, and forming a unified whole.","main_translations_es":["Lógico","Consistente","Razonable"],"collocations":["coherent argument","coherent plan","coherent theory","coherent response"],"synonyms_en":["logical","consistent","clear"],"example_sentence":"His argument is coherent and easy to follow.","example_es":"Su argumento es coherente y fácil de seguir.","example_en":"His argument is coherent and easy to follow.","mnemonic_en":"Picture a coherent story where every line fits, just like the Spanish word coherente snapping neatly together.","cloze_distractors_en":[],"examples":[{"es":"Su argumento es coherente y fácil de seguir.","en":"His argument is coherent and easy to follow."}]},{"spanish_text":"Preciso","english_text":"Precise","section_name":"English C1 Vocabulary","part_of_speech":"adjective","definition_en":"Exact and accurate, leaving no room for error or ambiguity.","main_translations_es":["Exacto","Concreto","Detallado"],"collocations":["precise measurement","precise timing","precise language","precise answer"],"synonyms_en":["exact","accurate","specific"],"example_sentence":"I need a precise watch to measure the race time.","example_es":"Necesito un reloj preciso para medir el tiempo de la carrera.","example_en":"I need a precise watch to measure the race time.","mnemonic_en":"Picture a precise surgeon shouting preciso while making exact, razor‑thin cuts.","cloze_distractors_en":[],"examples":[{"es":"Necesito un reloj preciso para medir el tiempo de la carrera.","en":"I need a precise watch to measure the race time."}]},{"spanish_text":"Convincente","english_text":"Compelling","section_name":"English C1 Vocabulary","part_of_speech":"adjective","definition_en":"Evoking interest, attention, or admiration in a powerful and persuasive way.","main_translations_es":["Persuasivo","Irresistible","Cautivador"],"collocations":["compelling argument","compelling evidence","compelling story","compelling reason"],"synonyms_en":["persuasive","forceful","irresistible"],"example_sentence":"The lawyer''s argument was so compelling that the jury had no doubts.","example_es":"El argumento del abogado fue tan convincente que el jurado no tuvo dudas.","example_en":"The lawyer''s argument was so compelling that the jury had no doubts.","mnemonic_en":"A compelling speaker convinces the crowd like a confident convict shouting convince","cloze_distractors_en":[],"examples":[{"es":"El argumento del abogado fue tan convincente que el jurado no tuvo dudas.","en":"The lawyer''s argument was so compelling that the jury had no doubts."}]},{"spanish_text":"Discrepancia","english_text":"Discrepancy","section_name":"English C1 Vocabulary","part_of_speech":"noun","definition_en":"