ng human rights."}]},{"spanish_text":"Dimitir","english_text":"Step down","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To resign from a position or office.","main_translations_es":["Renunciar","Abandonar el cargo","Dejar el puesto"],"collocations":["step down from","step down as","step down voluntarily","step down after"],"synonyms_en":["resign","quit","abdicate"],"example_sentence":"The president announced that he will step down after the scandal.","example_es":"El presidente anunció que va a dimitir después del escándalo.","example_en":"The president announced that he will step down after the scandal.","mnemonic_en":"Picture a timid boss taking a step down from the throne.","cloze_distractors_en":[],"examples":[{"es":"El presidente anunció que va a dimitir después del escándalo.","en":"The president announced that he will step down after the scandal."}]},{"spanish_text":"Parecerse a","english_text":"Take after","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"to resemble or be similar to someone, especially a family member","main_translations_es":["Asemejarse a","Se parecer a","Tener el parecido de"],"collocations":["take after his father","take after his mother","take after his brother","take after the family"],"synonyms_en":["resemble","be similar to","look like"],"example_sentence":"María takes after her mother.","example_es":"María se parece a su madre.","example_en":"María takes after her mother.","mnemonic_en":"Picture a pair of tacos you take after, because ''take after'' sounds like a ''pair'' (pare) of tacos.","cloze_distractors_en":[],"examples":[{"es":"María se parece a su madre.","en":"María takes after her mother."}]},{"spanish_text":"Asumir","english_text":"Take on","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To accept responsibility for something or to assume a task or role.","main_translations_es":["Aceptar","Encargar","Adoptar"],"collocations":["take on a challenge","take on responsibilities","take on a new role","take on board"],"synonyms_en":["assume","accept","undertake"],"example_sentence":"He decided to take on the responsibility of the project.","example_es":"Decidió asumir la responsabilidad del proyecto.","example_en":"He decided to take on the responsibility of the project.","mnemonic_en":"Take on sounds like a sum, so picture yourself taking on a huge pile of cash.","cloze_distractors_en":[],"examples":[{"es":"Decidió asumir la responsabilidad del proyecto.","en":"He decided to take on the responsibility of the project."}]},{"spanish_text":"Tomar el control","english_text":"Take over","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"to assume control or responsibility for something","main_translations_es":["Asumir el control","Hacerse cargo","Dominar"],"collocations":["take over the company","take over the reins","take over from","take over the project"],"synonyms_en":["assume control","seize control","take charge"],"example_sentence":"The new CEO decided to take over the company.","example_es":"El nuevo CEO decidió tomar el control de la empresa.","example_en":"The new CEO decided to take over the company.","mnemonic_en":"Picture a giant taco taking over the control console.","cloze_distractors_en":[],"examples":[{"es":"El nuevo CEO decidió tomar el control de la empresa.","en":"The new CEO decided to take over the company."}]},{"spanish_text":"Pensarlo detenidamente","english_text":"Think over","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"to consider something carefully","main_translations_es":["Reflexionar sobre ello","Considerarlo con cuidado","Meditar al respecto"],"collocations":["think it over","think over the proposal","think over the decision","think over the options"],"synonyms_en":["consider","ponder","mull over"],"example_sentence":"Before making a decision, it''s important to think it over.","example_es":"Antes de tomar una decisión, es importante pensarlo detenidamente.","example_en":"Before making a decision, it''s important to think it over.","mnemonic_en":"Picture a thinker standing over a pond, whispering ''pensar'' as he weighs the idea.","cloze_distractors_en":[],"examples":[{"es":"Antes de tomar una decisión, es importante pensarlo detenidamente.","en":"Before making a decision, it''s important to think it over."}]},{"spanish_text":"Rechazar","english_text":"Turn down","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To reject or refuse something.","main_translations_es":["Rehusar","Negar","Declinar"],"collocations":["turn down the volume","turn down the offer","turn down a request","turn down the lights"],"synonyms_en":["reject","refuse","decline"],"example_sentence":"He decided to turn down the job offer.","example_es":"Decidió rechazar la oferta de trabajo.","example_en":"He decided to turn down the job offer.","mnemonic_en":"I reach a jar, then turn it down, rejecting the offer.","cloze_distractors_en":[],"examples":[{"es":"Decidió rechazar la oferta de trabajo.","en":"He decided to turn down the job offer."}]},{"spanish_text":"Resultar","english_text":"Turn out","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"to have a particular result or outcome","main_translations_es":["acabar","salir","concluir"],"collocations":["turn out to be","turn out well","turn out for the best","turn out the lights"],"synonyms_en":["prove","result","end up"],"example_sentence":"The exam turned out to be easier than I expected.","example_es":"El examen resultó más fácil de lo que esperaba.","example_en":"The exam turned out to be easier than I expected.","mnemonic_en":"The result of the experiment turned out exactly as predicted.","cloze_distractors_en":[],"examples":[{"es":"El examen resultó más fácil de lo que esperaba.","en":"The exam turned out to be easier than I expected."}]},{"spanish_text":"Salirse bien","english_text":"Work out","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"to succeed or have a favorable outcome","main_translations_es":["Salir bien","Resultar bien","Ir bien"],"collocations":["work out at the gym","work out the details","work out a solution","work out a plan"],"synonyms_en":["succeed","turn out well","manage"],"example_sentence":"In the end, everything worked out.","example_es":"Al final, todo se salió bien.","example_en":"In the end, everything worked out.","mnemonic_en":"Sail out of the gym after a workout, feeling well.","cloze_distractors_en":[],"examples":[{"es":"Al final, todo se salió bien.","en":"In the end, everything worked out."}]},{"spanish_text":"Retirarse","english_text":"Back out","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"to withdraw from an agreement, plan, or commitment","main_translations_es":["Echarse atrás","Desistir","Recuarse"],"collocations":["back out of a deal","back out of a commitment","back out at the last minute"],"synonyms_en":["withdraw","pull out","renege"],"example_sentence":"He decided to back out of the project before it was too late.","example_es":"Decidió retirarse del proyecto antes de que fuera demasiado tarde.","example_en":"He decided to back out of the project before it was too late.","mnemonic_en":"Picture a car backing out while shouting retire as it leaves the driveway.","cloze_distractors_en":[],"examples":[{"es":"Decidió retirarse del proyecto antes de que fuera demasiado tarde.","en":"He decided to back out of the project before it was too late."}]},{"spanish_text":"Romper con","english_text":"Break off","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb (phrasal verb)","definition_en":"To end a relationship with someone.","main_translations_es":["Terminar con","Poner fin a","Separarse de"],"collocations":["break off a relationship","break off negotiations","break off a conversation","break off the engagement"],"synonyms_en":["sever","terminate","cut off"],"example_sentence":"He decided to break off his relationship with his girlfriend after three years.","example_es":"Decidió romper con su novia después de tres años.","example_en":"He decided to break off his relationship with his girlfriend after three years.","mnemonic_en":"I break off the chain, Romper con the lock, ending its hold.","cloze_distractors_en":[],"examples":[{"es":"Decidió romper con su novia después de tres años.","en":"He decided to break off his relationship with his girlfriend after three years."}]},{"spanish_text":"Abrirse paso","english_text":"Break through","section_name":"Advanced Phrasal Verbs","part_of_speech":"phrasal verb","definition_en":"To succeed in overcoming an obstacle or to make a way forward.","main_translations_es":["Abrir camino","Hacer hueco","Forzar la entrada"],"collocations":["break through the barrier","break through the market","break through to the audience","break through the noise"],"synonyms_en":["penetrate","make headway","forge ahead"],"example_sentence":"The pioneers had to break through the jungle.","example_es":"Los pioneros tuvieron que abrirse paso en la selva.","example_en":"The pioneers had to break through the jungle.","mnemonic_en":"Imagine a brake breaking a wall, letting people abrirse paso.","cloze_distractors_en":[],"examples":[{"es":"Los pioneros tuvieron que abrirse paso en la selva.","en":"The pioneers had to break through the jungle."}]},{"spanish_text":"Interrumpir","english_text":"Cut in","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To interrupt someone while they are speaking.","main_translations_es":["interrumpir","intervenir","intercalar"],"collocations":["cut in line","cut in on","cut in the conversation","cut in while"],"synonyms_en":["interrupt","interject","butt in"],"example_sentence":"You shouldn''t cut in when someone is speaking.","example_es":"No deberías interrumpir cuando alguien está hablando.","example_en":"You shouldn''t cut in when someone is speaking.","mnemonic_en":"A cutter (corte) jumps in, interrupting the chat.","cloze_distractors_en":[],"examples":[{"es":"No deberías interrumpir cuando alguien está hablando.","en":"You shouldn''t cut in when someone is speaking."}]},{"spanish_text":"Agotar","english_text":"Use up","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To consume something completely until none remains.","main_translations_es":["exhaustar","consumir","desgastar"],"collocations":["use up the resources","use up all the water","use up your time","use up the budget"],"synonyms_en":["exhaust","deplete","consume"],"example_sentence":"The fire managed to use up all the water supply in the area.","example_es":"El incendio logró agotar todo el suministro de agua de la zona.","example_en":"The fire managed to use up all the water supply in the area.","mnemonic_en":"When you use up the battery, it goes a‑go‑tar empty.","cloze_distractors_en":[],"examples":[{"es":"El incendio logró agotar todo el suministro de agua de la zona.","en":"The fire managed to use up all the water supply in the area."}]},{"spanish_text":"Terminar en","english_text":"End up","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"to finally reach a particular place, condition, or result, often unexpectedly","main_translations_es":["acabar en","quedar en","finalizar en"],"collocations":["end up with","end up doing","end up in","end up somewhere"],"synonyms_en":["result","turn out","come to be"],"example_sentence":"If you don''t study, you could end up on the street.","example_es":"Si no estudias, podrías terminar en la calle.","example_en":"If you don''t study, you could end up on the street.","mnemonic_en":"Picture crossing the finish line and yelling ''en!'' as you finally end up there.","cloze_distractors_en":[],"examples":[{"es":"Si no estudias, podrías terminar en la calle.","en":"If you don''t study, you could end up on the street."}]},{"spanish_text":"Dar con","english_text":"Find out","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To discover or learn something.","main_translations_es":["Encontrar","Toparse con","Descubrir"],"collocations":["find out the truth","find out more","find out what happened"],"synonyms_en":["discover","learn","determine"],"example_sentence":"After searching for hours, I finally found out the solution to the problem.","example_es":"Después de buscar durante horas, finalmente di con la solución al problema.","example_en":"After searching for hours, I finally found out the solution to the problem.","mnemonic_en":"When I find out, I dar con the secret like uncovering a buried chest.","cloze_distractors_en":[],"examples":[{"es":"Después de buscar durante horas, finalmente di con la solución al problema.","en":"After searching for hours, I finally found out the solution to the problem."}]},{"spanish_text":"Irse apagando","english_text":"Fade away","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To gradually disappear or lose intensity.","main_translations_es":["Desvanecerse","Ir perdiendo intensidad","Desaparecer poco a poco"],"collocations":["fade away slowly","fade away over time","fade away into the distance","fade away completely"],"synonyms_en":["diminish","die out","ebb"],"example_sentence":"Over time, the lantern''s light began to fade away.","example_es":"Con el tiempo, la luz del farol se fue apagando.","example_en":"Over time, the lantern''s light began to fade away.","mnemonic_en":"See a lamp fade away as its light apagando like a ghost slipping into darkness.","cloze_distractors_en":[],"examples":[{"es":"Con el tiempo, la luz del farol se fue apagando.","en":"Over time, the lantern''s light began to fade away."}]},{"spanish_text":"Aplastar","english_text":"Crack down on","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"to take strict or severe measures against something or someone","main_translations_es":["machacar","triturar","aplastar"],"collocations":["crack down on crime","crack down on corruption","crack down on tax evasion","crack down on illegal immigration"],"synonyms_en":["clamp down on","suppress","repress"],"example_sentence":"The government decided to crack down on tax evasion.","example_es":"El gobierno decidió aplastar la evasión fiscal.","example_en":"The government decided to crack down on tax evasion.","mnemonic_en":"Picture a crack hammer slamming down on a wall, crushing it flat like aplastar.","cloze_distractors_en":[],"examples":[{"es":"El gobierno decidió aplastar la evasión fiscal.","en":"The government decided to crack down on tax evasion."}]},{"spanish_text":"Rechazar de plano","english_text":"Brush off","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb (phrasal verb)","definition_en":"To dismiss or reject something or someone in a casual or indifferent manner.","main_translations_es":["Desestimar","Descartar","Rechazar rotundamente"],"collocations":["brush off criticism","brush off a comment","brush off the suggestion"],"synonyms_en":["dismiss","snub","turn down"],"example_sentence":"When they proposed the idea to him, he brushed it off.","example_es":"Cuando le propusieron la idea, la rechazó de plano.","example_en":"When they proposed the idea to him, he brushed it off.","mnemonic_en":"Brush off the plain (plano) like dust from a model plane","cloze_distractors_en":[],"examples":[{"es":"Cuando le propusieron la idea, la rechazó de plano.","en":"When they proposed the idea to him, he brushed it off."}]},{"spanish_text":"Acompañar","english_text":"Go along with","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"to agree with or support something or someone","main_translations_es":["acompañar","ir con","seguir"],"collocations":["go along with the plan","go along with the decision","go along with the idea","go along with the crowd"],"synonyms_en":["agree with","support","concur with"],"example_sentence":"He decided to go along with his brother on the hike.","example_es":"Decidió acompañar a su hermano en la caminata.","example_en":"He decided to go along with his brother on the hike.","mnemonic_en":"Picture a companion shouting Go! Along! With! as you both walk.","cloze_distractors_en":[],"examples":[{"es":"Decidió acompañar a su hermano en la caminata.","en":"He decided to go along with his brother on the hike."}]},{"spanish_text":"Tolerar","english_text":"Put up with","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"to tolerate or endure something or someone","main_translations_es":["soportar","aguantar","sufrir"],"collocations":["can''t put up with","put up with the noise","put up with his behavior"],"synonyms_en":["tolerate","endure","stand"],"example_sentence":"I can''t put up with the constant construction noise.","example_es":"No puedo tolerar el ruido constante de la construcción.","example_en":"I can''t put up with the constant construction noise.","mnemonic_en":"Picture a stubborn bull you tolerate, so you literally put up with it.","cloze_distractors_en":[],"examples":[{"es":"No puedo tolerar el ruido constante de la construcción.","en":"I can''t put up with the constant construction noise."}]},{"spanish_text":"Intervenir","english_text":"Step in","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To intervene or become involved in a situation.","main_translations_es":["Intervenir","Interceder","Meterse"],"collocations":["step in to help","step in and take over","step in at the last minute","step in for someone"],"synonyms_en":["intervene","intercede","meddle"],"example_sentence":"The doctor had to step in quickly to save the patient.","example_es":"El médico tuvo que intervenir rápidamente para salvar al paciente.","example_en":"The doctor had to step in quickly to save the patient.","mnemonic_en":"Step in like an intervenir hero entering the scene","cloze_distractors_en":[],"examples":[{"es":"El médico tuvo que intervenir rápidamente para salvar al paciente.","en":"The doctor had to step in quickly to save the patient."}]},{"spanish_text":"Retirarse gradualmente","english_text":"Phase out","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To gradually stop using or providing something.","main_translations_es":["Eliminar gradualmente","Descontinuar","Ir reduciendo"],"collocations":["phase out the program","phase out subsidies","phase out gradually","phase out over time"],"synonyms_en":["gradually eliminate","wind down","discontinue"],"example_sentence":"The company decided to phase out its mobile phone market.","example_es":"La empresa decidió retirarse gradualmente del mercado de teléfonos móviles.","example_en":"The company decided to phase out its mobile phone market.","mnemonic_en":"Picture a stage (phase) where you slowly walk out, retiring step by step.","cloze_distractors_en":[],"examples":[{"es":"La empresa decidió retirarse gradualmente del mercado de teléfonos móviles.","en":"The company decided to phase out its mobile phone market."}]},{"spanish_text":"Introducir gradualmente","english_text":"Phase in","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To introduce something gradually or in stages.","main_translations_es":["Implementar de forma gradual","Ir incorporando poco a poco","Introducir paulatinamente"],"collocations":["phase in gradually","phase in over time","phase in the new system","phase in the changes"],"synonyms_en":["introduce gradually","roll out","implement gradually"],"example_sentence":"The company decided to phase in the new software to avoid problems.","example_es":"La empresa decidió introducir gradualmente el nuevo software para evitar problemas.","example_en":"The company decided to phase in the new software to avoid problems.","mnemonic_en":"Imagine “fases en” – the Spanish for phases in – as you phase in something gradually.","cloze_distractors_en":[],"examples":[{"es":"La empresa decidió introducir gradualmente el nuevo software para evitar problemas.","en":"The company decided to phase in the new software to avoid problems."}]},{"spanish_text":"Fallar","english_text":"Break down","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"to cause something to collapse, fail, or separate into its component parts.","main_translations_es":["Equivocarse","Fallarse","Desacertar"],"collocations":["break down the problem","break down into steps","break down barriers","break down in tears"],"synonyms_en":["malfunction","collapse","analyze"],"example_sentence":"The car started to break down and stopped in the middle of the road.","example_es":"El coche empezó a fallar y se detuvo en medio de la carretera.","example_en":"The car started to break down and stopped in the middle of the road.","mnemonic_en":"When it falls, it breaks down.","cloze_distractors_en":[],"examples":[{"es":"El coche empezó a fallar y se detuvo en medio de la carretera.","en":"The car started to break down and stopped in the middle of the road."}]},{"spanish_text":"Separarse","english_text":"Break up","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To end a romantic relationship.","main_translations_es":["Divorciarse","Romper","Terminar"],"collocations":["break up with","break up a fight","break up the band","break up the meeting"],"synonyms_en":["split","separate","disband"],"example_sentence":"After five years together, they decided to break up.","example_es":"Después de cinco años de relación, decidieron separarse.","example_en":"After five years together, they decided to break up.","mnemonic_en":"Picture a broken vase that separates into shards as the couple breaks up","cloze_distractors_en":[],"examples":[{"es":"Después de cinco años de relación, decidieron separarse.","en":"After five years together, they decided to break up."}]},{"spanish_text":"Calmarse","english_text":"Calm down","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"to become or cause someone to become less agitated or upset","main_translations_es":["tranquilizarse","relajarse"],"collocations":["Calm down and think","Calm down, please","Calm down, it''s not a big deal"],"synonyms_en":["relax","settle down","chill out"],"example_sentence":"After the argument, John decided to calm down and take a deep breath.","example_es":"Después de la discusión, Juan decidió calmarse y respirar profundamente.","example_en":"After the argument, John decided to calm down and take a deep breath.","mnemonic_en":"Picture a calm sea whispering calm down as the waves settle.","cloze_distractors_en":[],"examples":[{"es":"Después de la discusión, Juan decidió calmarse y respirar profundamente.","en":"After the argument, John decided to calm down and take a deep breath."}]},{"spanish_text":"Cancelar","english_text":"Call off","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To cancel or stop something that was planned.","main_translations_es":["Cancelar","Anular","Suspender"],"collocations":["call off the meeting","call off the search","call off the wedding","call off the strike"],"synonyms_en":["cancel","abort","scrap"],"example_sentence":"We decided to call off the party.","example_es":"Decidimos cancelar la fiesta.","example_en":"We decided to call off the party.","mnemonic_en":"Picture a phone call saying cancela to end the party.","cloze_distractors_en":[],"examples":[{"es":"Decidimos cancelar la fiesta.","en":"We decided to call off the party."}]},{"spanish_text":"Seguir adelante con","english_text":"Carry on","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"to continue doing something","main_translations_es":["Continuar con","Proseguir con","Avanzar con"],"collocations":["carry on with","carry on doing","carry on as usual","carry on regardless"],"synonyms_en":["continue","proceed","keep going"],"example_sentence":"He decided to carry on with the project despite the obstacles.","example_es":"Decidió seguir adelante con el proyecto a pesar de los obstáculos.","example_en":"He decided to carry on with the project despite the obstacles.","mnemonic_en":"Picture a cari (cariño) sprinting forward, carrying on the race.","cloze_distractors_en":[],"examples":[{"es":"Decidió seguir adelante con el proyecto a pesar de los obstáculos.","en":"He decided to carry on with the project despite the obstacles."}]},{"spanish_text":"Alcanzar","english_text":"Catch up","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"to reach the same level or position as someone or something after falling behind","main_translations_es":["Lograr","Conseguir","Ponerse al día"],"collocations":["catch up on","catch up with","catch up to","catch up later"],"synonyms_en":["keep up","close the gap","reach"],"example_sentence":"I need to catch up with my classmates so I don''t fall behind.","example_es":"Necesito alcanzar a mis compañeros de clase para no quedarme atrás.","example_en":"I need to catch up with my classmates so I don''t fall behind.","mnemonic_en":"Al can catch up with the runner","cloze_distractors_en":[],"examples":[{"es":"Necesito alcanzar a mis compañeros de clase para no quedarme atrás.","en":"I need to catch up with my classmates so I don''t fall behind."}]},{"spanish_text":"Comprobar","english_text":"Check out","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"to examine or look at something, or to borrow it from a library","main_translations_es":["verificar","confirmar","corroborar"],"collocations":["check out the new store","check out a book","check out of a hotel","check out the website"],"synonyms_en":["examine","look at","inspect"],"example_sentence":"I will check out the train schedule before leaving.","example_es":"Voy a comprobar el horario del tren antes de salir.","example_en":"I will check out the train schedule before leaving.","mnemonic_en":"I check out the giant compro bar that stamps my library books.","cloze_distractors_en":[],"examples":[{"es":"Voy a comprobar el horario del tren antes de salir.","en":"I will check out the train schedule before leaving."}]},{"spanish_text":"Contar con","english_text":"Count on","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"to rely on someone or something","main_translations_es":["Depender de","Confiar en","Apoyarse en"],"collocations":["count on me","count on someone","count on it","you can count on"],"synonyms_en":["rely on","depend on","trust"],"example_sentence":"You can count on my help to finish the project.","example_es":"Puedes contar con mi ayuda para terminar el proyecto.","example_en":"You can count on my help to finish the project.","mnemonic_en":"I count on you, picturing me counting coins (con) in my hand.","cloze_distractors_en":[],"examples":[{"es":"Puedes contar con mi ayuda para terminar el proyecto.","en":"You can count on my help to finish the project."}]},{"spanish_text":"Interrumpir abruptamente","english_text":"Cut off","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To stop or interrupt something abruptly.","main_translations_es":["Cortar de golpe","Interrumpir bruscamente","Cortar abruptamente"],"collocations":["cut off the power","cut off communication","cut off at the source","cut off from"],"synonyms_en":["interrupt","discontinue","sever"],"example_sentence":"The host decided to cut off the interview abruptly when the guest became nervous.","example_es":"El presentador decidió interrumpir abruptamente la entrevista cuando el invitado se puso nervioso.","example_en":"The host decided to cut off the interview abruptly when the guest became nervous.","mnemonic_en":"Imagine a scissors cut off the conversation, a sudden corte that abruptly interrupts.","cloze_distractors_en":[],"examples":[{"es":"El presentador decidió interrumpir abruptamente la entrevista cuando el invitado se puso nervioso.","en":"The host decided to cut off the interview abruptly when the guest became nervous."}]},{"spanish_text":"Lidiar con","english_text":"Deal with","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To address, manage, or handle a problem, situation, or person.","main_translations_es":["Enfrentarse a","Tratar con","Abordar"],"collocations":["deal with a problem","deal with customers","deal with the situation","deal with stress"],"synonyms_en":["handle","manage","address"],"example_sentence":"I have to deal with many problems at work.","example_es":"Tengo que lidiar con muchos problemas en el trabajo.","example_en":"I have to deal with many problems at work.","mnemonic_en":"Deal with it like dealing cards while wearing a lid on your ear.","cloze_distractors_en":[],"examples":[{"es":"Tengo que lidiar con muchos problemas en el trabajo.","en":"I have to deal with many problems at work."}]},{"spanish_text":"Acabar con","english_text":"Do without","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb phrase","definition_en":"To manage or survive without something.","main_translations_es":["Eliminar","Poner fin a","Deshacerse de"],"collocations":["can''t do without","do without sugar","do without help"],"synonyms_en":["forego","manage without","go without"],"example_sentence":"I''m going to do without sugar.","example_es":"Voy a acabar con el azúcar.","example_en":"I''m going to do without sugar.","mnemonic_en":"Picture a con being finished, so you do without the con.","cloze_distractors_en":[],"examples":[{"es":"Voy a acabar con el azúcar.","en":"I''m going to do without sugar."}]},{"spanish_text":"Abandonar","english_text":"Drop out","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To quit a school, program, or activity before completing it.","main_translations_es":["Dejar","Renunciar","Desistir"],"collocations":["drop out of school","drop out of college","drop out of the race"],"synonyms_en":["quit","withdraw","leave school"],"example_sentence":"He decided to drop out of college after the first semester.","example_es":"Decidió abandonar la universidad después del primer semestre.","example_en":"He decided to drop out of college after the first semester.","mnemonic_en":"I dropped out, abandoning the game like a broken drop falling away.","cloze_distractors_en":[],"examples":[{"es":"Decidió abandonar la universidad después del primer semestre.","en":"He decided to drop out of college after the first semester."}]},{"spanish_text":"Comerse todo","english_text":"Eat up","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"to consume something completely, especially to finish eating it","main_translations_es":["comer todo","devorarlo todo","tragarse todo"],"collocations":["eat up the leftovers","eat up the competition","eat up the information"],"synonyms_en":["devour","finish","consume"],"example_sentence":"I''m going to eat up the whole cake.","example_es":"Voy a comerme todo el pastel.","example_en":"I''m going to eat up the whole cake.","mnemonic_en":"Picture a hungry monster that eats up every crumb, just like comerse todo.","cloze_distractors_en":[],"examples":[{"es":"Voy a comerme todo el pastel.","en":"I''m going to eat up the whole cake."}]},{"spanish_text":"Explicar","english_text":"Explain away","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To dismiss or rationalize something as unimportant or untrue by offering an explanation that reduces its significance.","main_translations_es":["Aclarar","Desglosar","Ilustrar"],"collocations":["explain away the mistake","explain away the scandal","can''t explain away the evidence","explain away the problem"],"synonyms_en":["rationalize","justify","make excuses"],"example_sentence":"He tried to explain away his mistake as if it were nothing.","example_es":"Trató de explicar su error como si no fuera gran cosa.","example_en":"He tried to explain away his mistake as if it were nothing.","mnemonic_en":"Picture an ex‑plane flying away, explaining the mystery.","cloze_distractors_en":[],"examples":[{"es":"Trató de explicar su error como si no fuera gran cosa.","en":"He tried to explain away his mistake as if it were nothing."}]},{"spanish_text":"Llenarse","english_text":"Fill up","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To cause something to become full or to become full oneself.","main_translations_es":["llenarse","completarse","colmarse"],"collocations":["fill up the tank","fill up on food","fill up the glass","fill up quickly"],"synonyms_en":["top up","replenish","load"],"example_sentence":"The glass filled up with water.","example_es":"El vaso se llenó de agua.","example_en":"The glass filled up with water.","mnemonic_en":"Picture Lena''s cup overflowing as it fills up.","cloze_distractors_en":[],"examples":[{"es":"El vaso se llenó de agua.","en":"The glass filled up with water."}]},{"spanish_text":"Encajar","english_text":"Fit in","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"to be accepted as part of a group or environment","main_translations_es":["Ajustar","Adaptarse","Encajar"],"collocations":["fit in with","fit in at","fit in nicely"],"synonyms_en":["blend","integrate","conform"],"example_sentence":"I had a hard time fitting in with the new work team.","example_es":"Me costó mucho encajar en el nuevo equipo de trabajo.","example_en":"I had a hard time fitting in with the new work team.","mnemonic_en":"Picture a key that fits in a lock, just like encajar means to fit in.","cloze_distractors_en":[],"examples":[{"es":"Me costó mucho encajar en el nuevo equipo de trabajo.","en":"I had a hard time fitting in with the new work team."}]},{"spanish_text":"Seguir adelante a pesar de","english_text":"Get on with","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb (phrasal verb)","definition_en":"to continue doing something despite obstacles or difficulties","main_translations_es":["Continuar a pesar de","Seguir adelante pese a","Prosseguir a pesar de"],"collocations":["get on with it","get on with your life","get on with the work","get on with the project"],"synonyms_en":["Proceed","Carry on","Continue"],"example_sentence":"We must get on with the project despite the setbacks.","example_es":"Debemos seguir adelante a pesar de los contratiempos.","example_en":"We must get on with the project despite the setbacks.","mnemonic_en":"A cat with a briefcase yells ''Get on with it!'' as it pushes forward.","cloze_distractors_en":[],"examples":[{"es":"Debemos seguir adelante a pesar de los contratiempos.","en":"We must get on with the project despite the setbacks."}]},{"spanish_text":"Bajarse de","english_text":"Get off","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To descend from or leave a vehicle, platform, or other surface.","main_translations_es":["Descender de","Salir de","Desmontarse de"],"collocations":["get off the bus","get off work","get off my back","get off the ground"],"synonyms_en":["disembark","step down","alight"],"example_sentence":"I got off the bus just in time.","example_es":"Me bajé del autobús justo a tiempo.","example_en":"I got off the bus just in time.","mnemonic_en":"When you get off, imagine shouting baja as you step down the stairs.","cloze_distractors_en":[],"examples":[{"es":"Me bajé del autobús justo a tiempo.","en":"I got off the bus just in time."}]},{"spanish_text":"Subirse a","english_text":"Get on","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To board or mount something, such as a vehicle or animal.","main_translations_es":["Montarse en","Subir a","Entrar en"],"collocations":["get on the bus","get on board","get on with","get on the train"],"synonyms_en":["board","mount","climb aboard"],"example_sentence":"I''m going to get on the bus before it leaves.","example_es":"Voy a subirme al autobús antes de que salga.","example_en":"I''m going to get on the bus before it leaves.","mnemonic_en":"I get on the bus while shouting subir as the doors rise","cloze_distractors_en":[],"examples":[{"es":"Voy a subirme al autobús antes de que salga.","en":"I''m going to get on the bus before it leaves."}]},{"spanish_text":"Volver","english_text":"Go back","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To return to a previous place or condition.","main_translations_es":["Regresar","Retornar","Volver atrás"],"collocations":["go back to the drawing board","go back home","go back in time"],"synonyms_en":["return","revert","come back"],"example_sentence":"I need to go back home before the storm.","example_es":"Necesito volver a casa antes de la tormenta.","example_en":"I need to go back home before the storm.","mnemonic_en":"Picture a goat (go) backing up toward a volcano (volver).","cloze_distractors_en":[],"examples":[{"es":"Necesito volver a casa antes de la tormenta.","en":"I need to go back home before the storm."}]},{"spanish_text":"Salir","english_text":"Go out","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To leave a place and go outside.","main_translations_es":["Ir afuera","Salir de casa","Ir fuera"],"collocations":["go out for dinner","go out with friends","go out on a date"],"synonyms_en":["leave","exit","step out"],"example_sentence":"We are going to go out after dinner.","example_es":"Vamos a salir después de la cena.","example_en":"We are going to go out after dinner.","mnemonic_en":"Imagine a sailor stepping out of the ship—''salir'' sounds like sailor, so you go out.","cloze_distractors_en":[],"examples":[{"es":"Vamos a salir después de la cena.","en":"We are going to go out after dinner."}]},{"spanish_text":"Acelerarse","english_text":"Hurry up","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"A command telling someone to act more quickly.","main_translations_es":["Apurarse","Darse prisa","Acelerar"],"collocations":["Hurry up and wait","Hurry up, we''re late","Hurry up already"],"synonyms_en":["rush","step on it","make it quick"],"example_sentence":"You have to hurry up if you don''t want to miss the train.","example_es":"Debes acelerarte si no quieres perder el tren.","example_en":"You have to hurry up if you don''t want to miss the train.","mnemonic_en":"Imagine a hare hurrying up a steep hill, shouting Acelera! – that reminds you of hurry up.","cloze_distractors_en":[],"examples":[{"es":"Debes acelerarte si no quieres perder el tren.","en":"You have to hurry up if you don''t want to miss the train."}]},{"spanish_text":"Posponer hasta más tarde","english_text":"Hold off","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To delay or postpone something.","main_translations_es":["Aplazar","Dejar para después","Postergar"],"collocations":["hold off on","hold off until","hold off for a while"],"synonyms_en":["delay","postpone","defer"],"example_sentence":"We decided to hold off the meeting until later.","example_es":"Decidimos posponer la reunión hasta más tarde.","example_en":"We decided to hold off the meeting until later.","mnemonic_en":"Imagine holding a post off the road to postpone it.","cloze_distractors_en":[],"examples":[{"es":"Decidimos posponer la reunión hasta más tarde.","en":"We decided to hold off the meeting until later."}]},{"spanish_text":"Permanecer despierto","english_text":"Keep up","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To continue doing something or maintain a certain level or pace.","main_translations_es":["Mantenerse despierto","No dormirse","Estar despierto"],"collocations":["keep up with","keep up the pace","keep up the good work","keep up the momentum"],"synonyms_en":["maintain","stay current","keep pace"],"example_sentence":"I need to keep up to finish the project.","example_es":"Necesito permanecer despierto para terminar el proyecto.","example_en":"I need to keep up to finish the project.","mnemonic_en":"I keep up with coffee, staying despierto all night.","cloze_distractors_en":[],"examples":[{"es":"Necesito permanecer despierto para terminar el proyecto.","en":"I need to keep up to finish the project."}]},{"spanish_text":"Irse sin pagar","english_text":"Make off","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb (phrasal verb)","definition_en":"To leave hurriedly, especially after stealing something.","main_translations_es":["Escaparse sin pagar","Huir sin pagar","Irse sin abonar"],"collocations":["make off with","make off after","make off quickly"],"synonyms_en":["flee","run away","escape"],"example_sentence":"The customers decided to make off without paying the restaurant bill.","example_es":"Los clientes decidieron irse sin pagar la cuenta del restaurante.","example_en":"The customers decided to make off without paying the restaurant bill.","mnemonic_en":"He makes off, like a thief making the bill vanish off the table.","cloze_distractors_en":[],"examples":[{"es":"Los clientes decidieron irse sin pagar la cuenta del restaurante.","en":"The customers decided to make off without paying the restaurant bill."}]},{"spanish_text":"Inventar","english_text":"Make up","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To create something false or fictitious, such as a story, excuse, or invention.","main_translations_es":["Crear","Fabricar","Idear"],"collocations":["make up a story","make up the bed","make up for","make up with"],"synonyms_en":["fabricate","invent","concoct"],"example_sentence":"She decided to make up an excuse to be late.","example_es":"Ella decidió inventar una excusa para llegar tarde.","example_en":"She decided to make up an excuse to be late.","mnemonic_en":"He makes up a new gadget, invent a device—just like inventar.","cloze_distractors_en":[],"examples":[{"es":"Ella decidió inventar una excusa para llegar tarde.","en":"She decided to make up an excuse to be late."}]},{"spanish_text":"Pasar por encima de","english_text":"Move past","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To go beyond or ignore something.","main_translations_es":["Superar","Dejar atrás","Pasar más allá de"],"collocations":["move past the obstacle","move past the issue","move past the pain","move past the past"],"synonyms_en":["Pass by","Go beyond","Proceed past"],"example_sentence":"You can''t move past the rules of the game.","example_es":"No puedes pasar por encima de las reglas del juego.","example_en":"You can''t move past the rules of the game.","mnemonic_en":"Pass a rope over the fence to move past the obstacle.","cloze_distractors_en":[],"examples":[{"es":"No puedes pasar por encima de las reglas del juego.","en":"You can''t move past the rules of the game."}]},{"spanish_text":"Mencionar casualmente","english_text":"Pass on","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"to give or transmit something to someone else","main_translations_es":["Mencionar de pasada","Aludir casualmente","Hacer una mención casual"],"collocations":["pass on the message","pass on the information","pass on a tradition","pass on to the next generation"],"synonyms_en":["relay","hand over","convey"],"example_sentence":"He passed on that the meeting had been cancelled.","example_es":"Mencionó casualmente que la reunión se había cancelado.","example_en":"He passed on that the meeting had been cancelled.","mnemonic_en":"Imagine saying ''pasa on'' while you casually drop a comment.","cloze_distractors_en":[],"examples":[{"es":"Mencionó casualmente que la reunión se había cancelado.","en":"He passed on that the meeting had been cancelled."}]},{"spanish_text":"Recoger","english_text":"Pick up","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To lift something from a surface or to collect it.","main_translations_es":["Alcanzar","Levantar","Recoger"],"collocations":["pick up the phone","pick up where you left off","pick up the tab","pick up a habit"],"synonyms_en":["collect","gather","retrieve"],"example_sentence":"I will pick up the package from the office.","example_es":"Voy a recoger el paquete de la oficina.","example_en":"I will pick up the package from the office.","mnemonic_en":"Pick up the record gear lying on the table","cloze_distractors_en":[],"examples":[{"es":"Voy a recoger el paquete de la oficina.","en":"I will pick up the package from the office."}]},{"spanish_text":"Señalar con precisión","english_text":"Pin down","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To identify or locate something precisely, often by determining its exact nature or details.","main_translations_es":["Precisar","Detallar con exactitud","Ubicar con precisión"],"collocations":["pin down the details","pin down the location","pin down the meaning","pin down the cause"],"synonyms_en":["identify","determine","pinpoint"],"example_sentence":"The detective managed to pin down the location of the body.","example_es":"El detective logró señalar con precisión la ubicación del cuerpo.","example_en":"The detective managed to pin down the location of the body.","mnemonic_en":"Imagine a pin marking the exact spot you point at","cloze_distractors_en":[],"examples":[{"es":"El detective logró señalar con precisión la ubicación del cuerpo.","en":"The detective managed to pin down the location of the body."}]},{"spanish_text":"Presentar formalmente","english_text":"Put forward","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"to propose or suggest something for consideration","main_translations_es":["exponer formalmente","proponer formalmente","someter formalmente"],"collocations":["put forward a proposal","put forward an idea","put forward a suggestion","put forward a theory"],"synonyms_en":["propose","suggest","advance"],"example_sentence":"The lawyer put forward the evidence to the jury.","example_es":"El abogado presentó formalmente la evidencia al jurado.","example_en":"The lawyer put forward the evidence to the jury.","mnemonic_en":"Picture a presenter putting a forward arrow on the screen","cloze_distractors_en":[],"examples":[{"es":"El abogado presentó formalmente la evidencia al jurado.","en":"The lawyer put forward the evidence to the jury."}]},{"spanish_text":"Encender","english_text":"Put on","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To dress oneself in something, or to cause something to be worn.","main_translations_es":["prender","activar","encender"],"collocations":["put on a coat","put on makeup","put on a show","put on weight"],"synonyms_en":["don","wear","slip on"],"example_sentence":"I''m going to put on the heating because it''s cold.","example_es":"Voy a encender la calefacción porque hace frío.","example_en":"I''m going to put on the heating because it''s cold.","mnemonic_en":"Picture putting on a bright jacket that lights up, just like you encender a lamp.","cloze_distractors_en":[],"examples":[{"es":"Voy a encender la calefacción porque hace frío.","en":"I''m going to put on the heating because it''s cold."}]},{"spanish_text":"Apagar","english_text":"Put out","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To extinguish a fire, light, or similar source.","main_translations_es":["Extinguir","Desactivar","Cerrar"],"collocations":["put out a fire","put out the lights","put out a cigarette","put out a call"],"synonyms_en":["extinguish","turn off","snuff"],"example_sentence":"Put out the candle before you leave.","example_es":"Apaga la vela antes de irte.","example_en":"Put out the candle before you leave.","mnemonic_en":"Picture a fire and hand a pager that says STOP to put it out.","cloze_distractors_en":[],"examples":[{"es":"Apaga la vela antes de irte.","en":"Put out the candle before you leave."}]},{"spanish_text":"Expulsar","english_text":"Throw out","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To discard or eject something.","main_translations_es":["Echar","Despedir","Eliminar"],"collocations":["throw out the trash","throw out a suggestion","throw out the window"],"synonyms_en":["discard","eject","expel"],"example_sentence":"The guard had to throw out the thief from the building.","example_es":"El guardia tuvo que expulsar al ladrón del edificio.","example_en":"The guard had to throw out the thief from the building.","mnemonic_en":"Visualize throwing a trash can out the door, you expel it—like the Spanish expulsar.","cloze_distractors_en":[],"examples":[{"es":"El guardia tuvo que expulsar al ladrón del edificio.","en":"The guard had to throw out the thief from the building."}]},{"spanish_text":"Resurgir","english_text":"Crop up","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb (phrasal)","definition_en":"to appear or occur unexpectedly","main_translations_es":["Aparecer","Reaparecer","Surgir de nuevo"],"collocations":["issues crop up","questions crop up","problems crop up","new ideas crop up"],"synonyms_en":["appear","arise","emerge"],"example_sentence":"Old problems can crop up after years.","example_es":"Los problemas antiguos pueden resurgir después de años.","example_en":"Old problems can crop up after years.","mnemonic_en":"The resurging wheat fields suddenly crop up like green fireworks.","cloze_distractors_en":[],"examples":[{"es":"Los problemas antiguos pueden resurgir después de años.","en":"Old problems can crop up after years."}]},{"spanish_text":"Darse cuenta de","english_text":"Cotton on","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"to become aware of something","main_translations_es":["darse cuenta","percatarse de","notar"],"collocations":["cotton on to","cotton on quickly","cotton on to the fact","cotton on over time"],"synonyms_en":["realize","notice","become aware"],"example_sentence":"I cottoned on that I had left the door open.","example_es":"Me di cuenta de que había dejado la puerta abierta.","example_en":"I cottoned on that I had left the door open.","mnemonic_en":"Seeing the soft cotton pillow, I finally cotton on to the hidden clue.","cloze_distractors_en":[],"examples":[{"es":"Me di cuenta de que había dejado la puerta abierta.","en":"I cottoned on that I had left the door open."}]},{"spanish_text":"Enfrentarse a","english_text":"Face up to","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"to confront or deal with something directly, especially a problem or difficulty.","main_translations_es":["Encarar","Hacerse cargo de","Confrontar"],"collocations":["face up to the reality","face up to the facts","face up to the consequences","face up to the problem"],"synonyms_en":["confront","deal with","address"],"example_sentence":"I have to face up to my fears.","example_es":"Tengo que enfrentarme a mis miedos.","example_en":"I have to face up to my fears.","mnemonic_en":"Picture a face looking up, ready to enfrentarse a the challenge.","cloze_distractors_en":[],"examples":[{"es":"Tengo que enfrentarme a mis miedos.","en":"I have to face up to my fears."}]},{"spanish_text":"Tomar apuntes","english_text":"Jot down","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"to write something quickly, especially brief notes.","main_translations_es":["Anotar","Escribir notas","Apuntar"],"collocations":["jot down notes","jot down a reminder","jot down ideas"],"synonyms_en":["write down","note","record"],"example_sentence":"During the class, I like to jot down notes so I don''t forget anything.","example_es":"Durante la clase, me gusta tomar apuntes para no olvidar nada.","example_en":"During the class, I like to jot down notes so I don''t forget anything.","mnemonic_en":"I jot down notes while I take apuntes, picturing a tiny jot of paper.","cloze_distractors_en":[],"examples":[{"es":"Durante la clase, me gusta tomar apuntes para no olvidar nada.","en":"During the class, I like to jot down notes so I don''t forget anything."}]},{"spanish_text":"Reducirse a","english_text":"Boil down to","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb phrase","definition_en":"To simplify something to its essential point or main idea.","main_translations_es":["Limitarse a","Resumirse a","Condensarse en"],"collocations":["It all boils down to","The problem boils down to","Everything boils down to","In the end, it boils down to"],"synonyms_en":["reduce to","condense to","simplify to"],"example_sentence":"The whole problem boils down to a matter of trust.","example_es":"Todo el problema se reduce a una cuestión de confianza.","example_en":"The whole problem boils down to a matter of trust.","mnemonic_en":"See a boiling bowl that shrinks down to a tiny cup.","cloze_distractors_en":[],"examples":[{"es":"Todo el problema se reduce a una cuestión de confianza.","en":"The whole problem boils down to a matter of trust."}]},{"spanish_text":"Salir con una idea","english_text":"Dream up","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To imagine or invent something, especially an idea or plan.","main_translations_es":["Idear","Proponer una idea","Concebir una idea"],"collocations":["dream up a plan","dream up a story","dream up an excuse"],"synonyms_en":["conceive","imagine","invent"],"example_sentence":"The scientist dreamed up a brilliant idea to solve the problem.","example_es":"El científico salió con una idea brillante para resolver el problema.","example_en":"The scientist dreamed up a brilliant idea to solve the problem.","mnemonic_en":"Picture a dream balloon floating up, as if a Spanish sueño flies arriba with a new idea.","cloze_distractors_en":[],"examples":[{"es":"El científico salió con una idea brillante para resolver el problema.","en":"The scientist dreamed up a brilliant idea to solve the problem."}]},{"spanish_text":"Renunciar a","english_text":"Walk away from","section_name":"Advanced Phrasal Verbs","part_of_speech":"phrasal verb","definition_en":"to leave or abandon something or someone","main_translations_es":["Abandonar","Dejar","Desistir de"],"collocations":["walk away from the problem","walk away from a relationship","walk away from danger"],"synonyms_en":["leave","depart","abandon"],"example_sentence":"He decided to walk away from his job after ten years.","example_es":"Decidió renunciar a su trabajo después de diez años.","example_en":"He decided to walk away from his job after ten years.","mnemonic_en":"When you renounce, you walk away from the scene.","cloze_distractors_en":[],"examples":[{"es":"Decidió renunciar a su trabajo después de diez años.","en":"He decided to walk away from his job after ten years."}]},{"spanish_text":"Asentarse","english_text":"Settle down","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"to become comfortable and stable in a place or situation, often by establishing a residence or routine","main_translations_es":["instalarse","establecerse","posarse"],"collocations":["settle down and relax","settle down in a new city","settle down with a partner"],"synonyms_en":["calm down","establish oneself","take root"],"example_sentence":"After moving to the new city, he decided to settle down in a small apartment near the park.","example_es":"Después de mudarse a la nueva ciudad, decidió asentarse en un pequeño apartamento cerca del parque.","example_en":"After moving to the new city, he decided to settle down in a small apartment near the park.","mnemonic_en":"Settle down like finding a seat (asiento) and sitting.","cloze_distractors_en":[],"examples":[{"es":"Después de mudarse a la nueva ciudad, decidió asentarse en un pequeño apartamento cerca del parque.","en":"After moving to the new city, he decided to settle down in a small apartment near the park."}]},{"spanish_text":"Derivar de","english_text":"Stem from","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"to originate or develop from something","main_translations_es":["Proceder de","Originarse en","Derivarse de"],"collocations":["stem from a problem","stem from the fact that","stem from years of experience","stem from underlying causes"],"synonyms_en":["originate from","derive from","come from"],"example_sentence":"The problem stems from poor communication.","example_es":"El problema deriva de una mala comunicación.","example_en":"The problem stems from poor communication.","mnemonic_en":"The tree''s stem from the earth derives, just like a river (deriva) flows out.","cloze_distractors_en":[],"examples":[{"es":"El problema deriva de una mala comunicación.","en":"The problem stems from poor communication."}]},{"spanish_text":"Asumir el mando","english_text":"Step up","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"to assume a higher level of responsibility or authority","main_translations_es":["Tomar el control","Asumir la dirección","Encabezar"],"collocations":["step up to the plate","step up your game","step up and take charge","step up the pace"],"synonyms_en":["take charge","assume responsibility","rise to the occasion"],"example_sentence":"When the captain fell ill, he had to step up and take command of the ship.","example_es":"Cuando el capitán cayó enfermo, tuvo que asumir el mando del barco.","example_en":"When the captain fell ill, he had to step up and take command of the ship.","mnemonic_en":"Imagine stepping up a ladder to asume the command.","cloze_distractors_en":[],"examples":[{"es":"Cuando el capitán cayó enfermo, tuvo que asumir el mando del barco.","en":"When the captain fell ill, he had to step up and take command of the ship."}]},{"spanish_text":"Suprimir gradualmente","english_text":"Weed out","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To gradually remove or eliminate unwanted or undesirable items or people.","main_translations_es":["Eliminar poco a poco","Deshacerse gradualmente","Ir eliminando"],"collocations":["weed out the weak","weed out candidates","weed out problems","weed out unnecessary items"],"synonyms_en":["eliminate","cull","filter out"],"example_sentence":"The company decided to weed out unnecessary positions.","example_es":"La empresa decidió suprimir gradualmente los puestos de trabajo innecesarios.","example_en":"The company decided to weed out unnecessary positions.","mnemonic_en":"Imagine pulling weeds out slowly, like you suppress (suprimir) them one by one.","cloze_distractors_en":[],"examples":[{"es":"La empresa decidió suprimir gradualmente los puestos de trabajo innecesarios.","en":"The company decided to weed out unnecessary positions."}]},{"spanish_text":"Desmenuzar","english_text":"Break down into","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb phrase","definition_en":"to separate something into smaller parts or components","main_translations_es":["desmenuzar","desglosar","descomponer"],"collocations":["break down into pieces","break down into steps","break down into components","break down into categories"],"synonyms_en":["analyze","decompose","dissect"],"example_sentence":"Break down the information into smaller parts to understand it better.","example_es":"Desmenuzar la información en partes más pequeñas ayuda a comprenderla mejor.","example_en":"Break down the information into smaller parts to understand it better.","mnemonic_en":"Break the cake into crumbs, just like desmenuzar.","cloze_distractors_en":[],"examples":[{"es":"Desmenuzar la información en partes más pequeñas ayuda a comprenderla mejor.","en":"Break down the information into smaller parts to understand it better."}]},{"spanish_text":"Superar con esfuerzo","english_text":"Pull through","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"to survive or recover from a difficult situation","main_translations_es":["Salir adelante con esfuerzo","Superar con dificultad","Lograrlo con esfuerzo"],"collocations":["pull through a crisis","pull through the tough times","pull through with help"],"synonyms_en":["survive","make it","get through"],"example_sentence":"With a lot of effort, we managed to pull through the economic crisis.","example_es":"Con mucho trabajo, logramos superar con esfuerzo la crisis económica.","example_en":"With a lot of effort, we managed to pull through the economic crisis.","mnemonic_en":"Pull the rope through, like polishing (pulir) your way past a tough wall.","cloze_distractors_en":[],"examples":[{"es":"Con mucho trabajo, logramos superar con esfuerzo la crisis económica.","en":"With a lot of effort, we managed to pull through the economic crisis."}]},{"spanish_text":"No presentarse","english_text":"Back out of","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"to withdraw from a commitment or fail to follow through with a plan","main_translations_es":["ausentarse","no acudir","no comparecer"],"collocations":["back out of a deal","back out of a commitment","back out of an agreement","back out of a promise"],"synonyms_en":["withdraw","pull out of","renege on"],"example_sentence":"I backed out of the meeting because I was feeling sick.","example_es":"No me presenté a la reunión porque me sentía enfermo.","example_en":"I backed out of the meeting because I was feeling sick.","mnemonic_en":"Picture yourself backing out of a door, shouting No presentarse as you vanish before anyone sees you.","cloze_distractors_en":[],"examples":[{"es":"No me presenté a la reunión porque me sentía enfermo.","en":"I backed out of the meeting because I was feeling sick."}]},{"spanish_text":"Tachar","english_text":"Cross out","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"To draw a line through text or a mark to indicate it should be deleted or ignored.","main_translations_es":["rayar","borrar","tachar"],"collocations":["cross out a mistake","cross out the word","cross out the line","cross out the name"],"synonyms_en":["delete","strike through","erase"],"example_sentence":"Please cross out the mistakes in the document.","example_es":"Por favor, tachar los errores en el documento.","example_en":"Please cross out the mistakes in the document.","mnemonic_en":"Cross out a mistake by drawing a big T over the char.","cloze_distractors_en":[],"examples":[{"es":"Por favor, tachar los errores en el documento.","en":"Please cross out the mistakes in the document."}]},{"spanish_text":"Ir acompañado de","english_text":"Go together with","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb phrase","definition_en":"to accompany someone or something","main_translations_es":["Ir con","Ir acompañado de","Ir en compañía de"],"collocations":["go together with friends","go together with a purpose","go together with the team","go together with the plan"],"synonyms_en":["accompany","travel with","go with"],"example_sentence":"I go together with my dog to the park.","example_es":"Voy al parque acompañado de mi perro.","example_en":"I go together with my dog to the park.","mnemonic_en":"Picture a goat (go) walking together with a companion named Acompañado.","cloze_distractors_en":[],"examples":[{"es":"Voy al parque acompañado de mi perro.","en":"I go together with my dog to the park."}]},{"spanish_text":"Recaer en","english_text":"Fall back on","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb","definition_en":"to rely again on something or someone for support or help","main_translations_es":["caer de nuevo en","volver a incurrir en","incurrir de nuevo en"],"collocations":["fall back on savings","fall back on experience","fall back on a plan","fall back on your instincts"],"synonyms_en":["rely on","depend on","turn to"],"example_sentence":"When I don''t know what to do, I always fall back on my old habits.","example_es":"Cuando no sé qué hacer, siempre recaigo en mis viejos hábitos.","example_en":"When I don''t know what to do, I always fall back on my old habits.","mnemonic_en":"Picture a falling rope you re‑cair onto when you need backup.","cloze_distractors_en":[],"examples":[{"es":"Cuando no sé qué hacer, siempre recaigo en mis viejos hábitos.","en":"When I don''t know what to do, I always fall back on my old habits."}]},{"spanish_text":"Insistir en","english_text":"Press ahead with","section_name":"Advanced Phrasal Verbs","part_of_speech":"verb phrase","definition_en":"To continue doing something with determination despite obstacles.","main_translations_es":["Persistir en","Mantenerse firme en","Continuar con"],"collocations":["press ahead with the plan","press ahead with the project","press ahead with reforms","press ahead with negotiations"],"synonyms_en":["continue with","forge ahead with","push forward with"],"example_sentence":"He pressed ahead with finishing the project on time.","example_es":"Insistió en terminar el proyecto a tiempo.","example_en":"He pressed ahead with finishing the project on time.","mnemonic_en":"Press a head like a stubborn insist from Spanish insistir.","cloze_distractors_en":[],"examples":[{"es":"Insistió en terminar el proyecto a tiempo.","en":"He pressed ahead with finishing the project on time."}]}]'::jsonb) as x(
  spanish_text text, english_text text, section_name text, part_of_speech text, definition_en text,
  main_translations_es jsonb, collocations jsonb, synonyms_en jsonb, example_sentence text, example_es text, example_en text, mnemonic_en text, cloze_distractors_en jsonb, examples jsonb
