where c.deck_id = dk.id
  and lower(c.spanish_text) = lower(x.spanish_text)
  and lower(c.english_text) = lower(x.english_text);

-- english-discussion-and-debate (105 cards)
update public.decks set
  title = 'Discussion and Debate', description = 'Expressions for giving opinions, agreeing, disagreeing, clarifying, and structuring advanced spoken English.',
  language_from = 'es', language_to = 'en'
where slug = 'english-discussion-and-debate';

update public.cards c set
  section_name = x.section_name, part_of_speech = x.part_of_speech, definition_en = x.definition_en,
  main_translations_es = coalesce(x.main_translations_es, '[]'::jsonb),
  collocations = coalesce(x.collocations, '[]'::jsonb),
  synonyms_en = coalesce(x.synonyms_en, '[]'::jsonb),
  example_sentence = x.example_sentence, example_es = x.example_es, example_en = x.example_en,
  mnemonic_en = coalesce(x.mnemonic_en, c.mnemonic_en),
  cloze_distractors_en = case when jsonb_array_length(coalesce(x.cloze_distractors_en, '[]'::jsonb)) > 0
                              then x.cloze_distractors_en else c.cloze_distractors_en end,
  examples = case when jsonb_array_length(coalesce(x.examples, '[]'::jsonb)) > 0
                  then x.examples else c.examples end
from (select id from public.decks where slug = 'english-discussion-and-debate') dk
cross join jsonb_to_recordset('[{"spanish_text":"Estoy totalmente de acuerdo","english_text":"I completely agree","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A statement indicating total agreement with something.","main_translations_es":["Estoy completamente de acuerdo","Coincido plenamente","Estoy totalmente de acuerdo"],"collocations":["I completely agree with you","I completely agree that","I completely agree, indeed"],"synonyms_en":["agree wholeheartedly","fully concur","absolutely agree"],"example_sentence":"I completely agree with your proposal.","example_es":"Estoy totalmente de acuerdo con tu propuesta.","example_en":"I completely agree with your proposal.","mnemonic_en":"I completely nod, because agree sounds like Spanish acuerdo.","cloze_distractors_en":[],"examples":[{"es":"Estoy totalmente de acuerdo con tu propuesta.","en":"I completely agree with your proposal."}]},{"spanish_text":"Estoy de acuerdo hasta cierto punto","english_text":"I agree to some extent","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"To express partial agreement with something.","main_translations_es":["Estoy de acuerdo en parte","Estoy parcialmente de acuerdo","Coincido hasta cierto punto"],"collocations":["I agree to some extent with you","I agree to some extent, however","I agree to some extent on that point"],"synonyms_en":["partially agree","somewhat agree","agree in part"],"example_sentence":"I agree to some extent with what you say.","example_es":"Estoy de acuerdo hasta cierto punto con lo que dices.","example_en":"I agree to some extent with what you say.","mnemonic_en":"Visualize an agrarian handshake extending just enough to pitch a tiny tent at a point.","cloze_distractors_en":[],"examples":[{"es":"Estoy de acuerdo hasta cierto punto con lo que dices.","en":"I agree to some extent with what you say."}]},{"spanish_text":"No lo veo así","english_text":"I do not see it that way","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A statement indicating that the speaker does not share that perspective.","main_translations_es":["No lo percibo de esa manera","No lo entiendo así","No lo concibo así"],"collocations":["I do not see it that way, but...","I do not see it that way at all","I do not see it that way, however"],"synonyms_en":["I disagree","I see it differently","That''s not how I view it"],"example_sentence":"I don''t see it that way, but I understand your point.","example_es":"No lo veo así, pero entiendo tu punto.","example_en":"I don''t see it that way, but I understand your point.","mnemonic_en":"Imagine a NO sign covering a low V while a sea says as I","cloze_distractors_en":[],"examples":[{"es":"No lo veo así, pero entiendo tu punto.","en":"I don''t see it that way, but I understand your point."}]},{"spanish_text":"No estoy del todo convencido","english_text":"I am not entirely convinced","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A statement indicating that someone is not fully persuaded.","main_translations_es":["No estoy completamente convencido","No me convence del todo","No estoy totalmente seguro"],"collocations":["I am not entirely convinced that…","I''m not entirely convinced by…","We are not entirely convinced about…"],"synonyms_en":["I''m not fully convinced","I''m skeptical","I''m doubtful"],"example_sentence":"I am not entirely convinced that this is the best solution.","example_es":"No estoy del todo convencido de que esa sea la mejor solución.","example_en":"I am not entirely convinced that this is the best solution.","mnemonic_en":"I stare at a half‑filled glass, not entirely convinced it''s full.","cloze_distractors_en":[],"examples":[{"es":"No estoy del todo convencido de que esa sea la mejor solución.","en":"I am not entirely convinced that this is the best solution."}]},{"spanish_text":"Discrepo","english_text":"I beg to differ","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A polite way of saying that you disagree.","main_translations_es":["No estoy de acuerdo","Me opongo","Diferir"],"collocations":["I beg to differ, but...","I beg to differ with you","I beg to differ on that point"],"synonyms_en":["I disagree","I dissent","I take exception"],"example_sentence":"I beg to differ with his opinion on the matter.","example_es":"Discrepo con su opinión sobre el tema.","example_en":"I beg to differ with his opinion on the matter.","mnemonic_en":"I beg to differ, thinking \"this crepe, oh!\" isn’t the same.","cloze_distractors_en":[],"examples":[{"es":"Discrepo con su opinión sobre el tema.","en":"I beg to differ with his opinion on the matter."}]},{"spanish_text":"Eso no refleja toda la realidad","english_text":"That does not tell the whole story","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"It means that something fails to convey the complete truth or full situation.","main_translations_es":["Eso no muestra toda la realidad","Eso no cuenta toda la historia","Eso no refleja todo el panorama"],"collocations":["The numbers do not tell the whole story","One example does not tell the whole story","Statistics often do not tell the whole story","A single incident does not tell the whole story"],"synonyms_en":["doesn''t show the full picture","doesn''t capture everything","doesn''t convey the entire truth"],"example_sentence":"That does not tell the whole story about the situation.","example_es":"Eso no refleja toda la realidad de la situación.","example_en":"That does not tell the whole story about the situation.","mnemonic_en":"That does not tell the whole story, like a real idea (realidad) with missing pages.","cloze_distractors_en":[],"examples":[{"es":"Eso no refleja toda la realidad de la situación.","en":"That does not tell the whole story about the situation."}]},{"spanish_text":"Desde mi punto de vista","english_text":"From my perspective","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A phrase used to indicate that something is being considered according to one''s own point of view.","main_translations_es":["A mi parecer","En mi opinión","Según mi punto de vista"],"collocations":["From my perspective, ...","From my perspective, the situation is clear","From my perspective, we should proceed","From my perspective, the results are promising"],"synonyms_en":["In my view","In my opinion","As I see it"],"example_sentence":"From my perspective, education should be free for everyone.","example_es":"Desde mi punto de vista, la educación debería ser gratuita para todos.","example_en":"From my perspective, education should be free for everyone.","mnemonic_en":"Picture a camera called From my pointing at a vista, reminding you of desde mi punto de vista.","cloze_distractors_en":[],"examples":[{"es":"Desde mi punto de vista, la educación debería ser gratuita para todos.","en":"From my perspective, education should be free for everyone."}]},{"spanish_text":"Tal como yo lo veo","english_text":"As I see it","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A phrase used to introduce one''s personal opinion or perspective.","main_translations_es":["Tal como lo percibo","Según mi punto de vista","A mi modo de ver"],"collocations":["as I see it, ...","as I see it, the problem is","as I see it, we should","as I see it, that''s the case"],"synonyms_en":["in my opinion","from my perspective","the way I see it"],"example_sentence":"As I see it, the situation is unsustainable.","example_es":"Tal como yo lo veo, la situación es insostenible.","example_en":"As I see it, the situation is unsustainable.","mnemonic_en":"Picture a camera: ''As I see it''—just like saying ''tal como yo lo veo''.","cloze_distractors_en":[],"examples":[{"es":"Tal como yo lo veo, la situación es insostenible.","en":"As I see it, the situation is unsustainable."}]},{"spanish_text":"Por lo que entiendo","english_text":"As far as I understand","section_name":"Discussion and Debate","part_of_speech":"idiomatic expression","definition_en":"It indicates that the speaker is stating something based on their current understanding.","main_translations_es":["Según entiendo","Hasta donde entiendo","En lo que entiendo"],"collocations":["as far as I understand it","as far as I understand, ...","as far as I understand the situation","as far as I understand from the report"],"synonyms_en":["to my knowledge","as I see it","as I understand it"],"example_sentence":"As far as I understand, the project will be completed on time.","example_es":"Por lo que entiendo, el proyecto se completará a tiempo.","example_en":"As far as I understand, the project will be completed on time.","mnemonic_en":"From far away, I understand the ''por'' door opens.","cloze_distractors_en":[],"examples":[{"es":"Por lo que entiendo, el proyecto se completará a tiempo.","en":"As far as I understand, the project will be completed on time."}]},{"spanish_text":"Hasta donde sé","english_text":"As far as I know","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"It means that the speaker is stating something based on their current knowledge, but may not be certain.","main_translations_es":["Hasta donde tengo entendido","Según lo que sé","Según mi conocimiento"],"collocations":["as far as I know, it''s true","as far as I know, there are no issues","as far as I know, that''s the case"],"synonyms_en":["to my knowledge","as far as I''m aware","to the best of my knowledge"],"example_sentence":"As far as I know, the meeting will be tomorrow at ten.","example_es":"Hasta donde sé, la reunión será mañana a las diez.","example_en":"As far as I know, the meeting will be tomorrow at ten.","mnemonic_en":"I see a far horizon and whisper hasta while I know the answer.","cloze_distractors_en":[],"examples":[{"es":"Hasta donde sé, la reunión será mañana a las diez.","en":"As far as I know, the meeting will be tomorrow at ten."}]},{"spanish_text":"Dicho esto","english_text":"That said","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A phrase used to introduce a statement that qualifies or contrasts with what was previously said.","main_translations_es":["Con eso dicho","Eso dicho","Dicho lo anterior"],"collocations":["That said, we should proceed","That said, it''s not guaranteed","That said, I think","That said, the results are inconclusive"],"synonyms_en":["Nevertheless","However","Even so"],"example_sentence":"That said, I think we should proceed with the original plan.","example_es":"Dicho esto, creo que deberíamos continuar con el plan original.","example_en":"That said, I think we should proceed with the original plan.","mnemonic_en":"Picture a hat shouting ''That said'' as you read the Spanish phrase dicho esto.","cloze_distractors_en":[],"examples":[{"es":"Dicho esto, creo que deberíamos continuar con el plan original.","en":"That said, I think we should proceed with the original plan."}]},{"spanish_text":"Al mismo tiempo","english_text":"At the same time","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"Indicates that two or more events occur simultaneously.","main_translations_es":["Simultáneamente","A la vez","En simultáneo"],"collocations":["at the same time as","at the same time, however","at the same time, too"],"synonyms_en":["simultaneously","concurrently","in tandem"],"example_sentence":"At the same time, we decided to go to the beach and visit my grandparents.","example_es":"Al mismo tiempo, decidimos viajar a la playa y visitar a mis abuelos.","example_en":"At the same time, we decided to go to the beach and visit my grandparents.","mnemonic_en":"Sam and Tim are at the same time.","cloze_distractors_en":[],"examples":[{"es":"Al mismo tiempo, decidimos viajar a la playa y visitar a mis abuelos.","en":"At the same time, we decided to go to the beach and visit my grandparents."}]},{"spanish_text":"Sin restarle importancia","english_text":"Without downplaying","section_name":"Discussion and Debate","part_of_speech":"phrase","definition_en":"In a way that does not diminish or lessen the importance of something.","main_translations_es":["Sin minimizar","Sin restar importancia","Sin restarle relevancia"],"collocations":["without downplaying the risks","without downplaying the importance","without downplaying the facts","without downplaying the situation"],"synonyms_en":["without minimizing","without diminishing","without belittling"],"example_sentence":"Without downplaying the minor issues, we must focus on the main solution.","example_es":"Sin restarle importancia a los problemas menores, debemos enfocarnos en la solución principal.","example_en":"Without downplaying the minor issues, we must focus on the main solution.","mnemonic_en":"Picture a sin that refuses to downplay its importance.","cloze_distractors_en":[],"examples":[{"es":"Sin restarle importancia a los problemas menores, debemos enfocarnos en la solución principal.","en":"Without downplaying the minor issues, we must focus on the main solution."}]},{"spanish_text":"En otras palabras","english_text":"In other words","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A phrase used to restate something in a different way.","main_translations_es":["En otras palabras","Dicho de otra forma"],"collocations":["in other words, ...","to put it another way","that is"],"synonyms_en":["that is","to put it differently","to rephrase"],"example_sentence":"In other words, the project is delayed.","example_es":"En otras palabras, el proyecto está retrasado.","example_en":"In other words, the project is delayed.","mnemonic_en":"Picture a sign reading EN OTRAS PALABRAS and you whisper in other words to translate it.","cloze_distractors_en":[],"examples":[{"es":"En otras palabras, el proyecto está retrasado.","en":"In other words, the project is delayed."}]},{"spanish_text":"Dicho de otro modo","english_text":"Put differently","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"Used to introduce a restatement of something in other words.","main_translations_es":["En otras palabras","De otra forma","Dicho de otra manera"],"collocations":["Put differently, ...","To put it differently","Put differently, however"],"synonyms_en":["in other words","to rephrase","that is"],"example_sentence":"Put differently, the situation is unsustainable.","example_es":"Dicho de otro modo, la situación es insostenible.","example_en":"Put differently, the situation is unsustainable.","mnemonic_en":"Put a pot (put) on a different shelf labeled ''diferente''.","cloze_distractors_en":[],"examples":[{"es":"Dicho de otro modo, la situación es insostenible.","en":"Put differently, the situation is unsustainable."}]},{"spanish_text":"Para ser más preciso","english_text":"To be more precise","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"Used to introduce a more exact statement or clarification.","main_translations_es":["Para ser más exacto","Con mayor precisión","En términos más precisos"],"collocations":["To be more precise, ...","To be more precise, the answer is ...","To be more precise, we should note that ..."],"synonyms_en":["more accurately","to be exact","in other words"],"example_sentence":"To be more precise, the project will be completed in three months.","example_es":"Para ser más preciso, el proyecto se completará en tres meses.","example_en":"To be more precise, the project will be completed in three months.","mnemonic_en":"Picture a precise (preciso) ruler announcing, to be more precise, I measure twice.","cloze_distractors_en":[],"examples":[{"es":"Para ser más preciso, el proyecto se completará en tres meses.","en":"To be more precise, the project will be completed in three months."}]},{"spanish_text":"Permíteme reformularlo","english_text":"Let me rephrase that","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A polite way of saying that you will restate something using different words.","main_translations_es":["Déjame reformularlo","Permíteme decirlo de otra manera","Voy a expresarlo de nuevo"],"collocations":["Let me rephrase that for clarity","Let me rephrase that in simpler terms","Let me rephrase that to be sure","Let me rephrase that another way"],"synonyms_en":["I''ll put it another way","Allow me to restate","I''ll say it differently"],"example_sentence":"Let me rephrase that to make it clearer.","example_es":"Permíteme reformularlo para que sea más claro.","example_en":"Let me rephrase that to make it clearer.","mnemonic_en":"Imagine me saying let me rephrase that as I reform a broken sign, linking rephrase to reformar","cloze_distractors_en":[],"examples":[{"es":"Permíteme reformularlo para que sea más claro.","en":"Let me rephrase that to make it clearer."}]},{"spanish_text":"Lo que intento decir es","english_text":"What I am trying to say is","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A phrase used to introduce or clarify what the speaker intends to convey.","main_translations_es":["Lo que quiero decir es","Lo que pretendo decir es","Lo que intento expresar es"],"collocations":["What I am trying to say is that...","What I am trying to say is, in short,...","What I am trying to say is, basically,..."],"synonyms_en":["In other words","To put it another way","My point is"],"example_sentence":"What I am trying to say is that we need more time.","example_es":"Lo que intento decir es que necesitamos más tiempo.","example_en":"What I am trying to say is that we need more time.","mnemonic_en":"Picture an intent speaker shouting what I am trying to say is","cloze_distractors_en":[],"examples":[{"es":"Lo que intento decir es que necesitamos más tiempo.","en":"What I am trying to say is that we need more time."}]},{"spanish_text":"Si lo analizamos","english_text":"If we break it down","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A phrase used to introduce a detailed analysis or explanation of something.","main_translations_es":["Si lo desglosamos","Si lo examinamos","Si lo estudiamos"],"collocations":["If we break it down further","If we break it down step by step","If we break it down, we can see","If we break it down, the problem becomes clear"],"synonyms_en":["If we analyze it","If we examine it","If we look at it closely"],"example_sentence":"If we break it down carefully, we will find the cause of the problem.","example_es":"Si lo analizamos detenidamente, encontraremos la causa del problema.","example_en":"If we break it down carefully, we will find the cause of the problem.","mnemonic_en":"Picture a scientist saying If we break it down while whispering si lo analizamos as he dissects a puzzle.","cloze_distractors_en":[],"examples":[{"es":"Si lo analizamos detenidamente, encontraremos la causa del problema.","en":"If we break it down carefully, we will find the cause of the problem."}]},{"spanish_text":"Ese es un buen punto","english_text":"That is a fair point","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A statement acknowledging that someone has made a valid or reasonable argument.","main_translations_es":["Eso es un punto válido","Ese es un buen argumento","Tienes un buen punto"],"collocations":["That''s a fair point, but...","Well, that''s a fair point.","I have to admit that''s a fair point.","You make a fair point."],"synonyms_en":["That''s a valid point","Good point","You have a point"],"example_sentence":"That is a fair point, we should consider it before deciding.","example_es":"Ese es un buen punto, deberíamos considerarlo antes de decidir.","example_en":"That is a fair point, we should consider it before deciding.","mnemonic_en":"At the fair the judge stamps a badge that reads Buen Point","cloze_distractors_en":[],"examples":[{"es":"Ese es un buen punto, deberíamos considerarlo antes de decidir.","en":"That is a fair point, we should consider it before deciding."}]},{"spanish_text":"Eso merece atención","english_text":"That is worth considering","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"It means something deserves attention or consideration.","main_translations_es":["Eso merece atención","Eso vale la pena","Eso merece ser considerado"],"collocations":["worth considering","worth a second look","worth taking into account"],"synonyms_en":["It''s worth thinking about","It deserves attention","It''s notable"],"example_sentence":"That is worth considering, so we should review it.","example_es":"Eso merece atención, así que deberíamos revisarlo.","example_en":"That is worth considering, so we should review it.","mnemonic_en":"A gold coin worth checking, because it merece attention.","cloze_distractors_en":[],"examples":[{"es":"Eso merece atención, así que deberíamos revisarlo.","en":"That is worth considering, so we should review it."}]},{"spanish_text":"No había pensado en eso","english_text":"I had not thought of that","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A statement indicating that one had not considered something before.","main_translations_es":["No lo había considerado","No lo había pensado","No se me había ocurrido"],"collocations":["I had not thought of that before","I had not thought of that possibility","I had not thought of that angle"],"synonyms_en":["I hadn''t considered that","That never occurred to me","I hadn''t realized that"],"example_sentence":"I hadn''t thought of that before you told me.","example_es":"No había pensado en eso antes de que me lo dijeras.","example_en":"I hadn''t thought of that before you told me.","mnemonic_en":"Picture a bee saying no while I forget the idea","cloze_distractors_en":[],"examples":[{"es":"No había pensado en eso antes de que me lo dijeras.","en":"I hadn''t thought of that before you told me."}]},{"spanish_text":"Sin embargo","english_text":"Having said that","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A phrase used to introduce a statement that contrasts with or qualifies what was previously said.","main_translations_es":["No obstante","Aun así","Con todo"],"collocations":["Having said that, I think we should proceed.","Having said that, we need to consider the costs.","Having said that, it''s not a guarantee.","Having said that, let''s move on."],"synonyms_en":["that said","still","nevertheless"],"example_sentence":"Having said that, the project was cancelled.","example_es":"Sin embargo, el proyecto fue cancelado.","example_en":"Having said that, the project was cancelled.","mnemonic_en":"Having said that, picture a sin without an embargo, a forbidden gate swinging open.","cloze_distractors_en":[],"examples":[{"es":"Sin embargo, el proyecto fue cancelado.","en":"Having said that, the project was cancelled."}]},{"spanish_text":"Aun así","english_text":"Even so","section_name":"Discussion and Debate","part_of_speech":"conjunctive adverb","definition_en":"Used to introduce a statement that contrasts with or qualifies what has just been said.","main_translations_es":["Sin embargo","No obstante","Aun así"],"collocations":["even so","even so, however","even so, nevertheless"],"synonyms_en":["Nevertheless","Nonetheless","Still"],"example_sentence":"Even so, he decided to go to the concert despite the rain.","example_es":"Aun así, decidió ir al concierto a pesar de la lluvia.","example_en":"Even so, he decided to go to the concert despite the rain.","mnemonic_en":"Even so, picture a lawn (awn) still standing after rain, just like aun.","cloze_distractors_en":[],"examples":[{"es":"Aun así, decidió ir al concierto a pesar de la lluvia.","en":"Even so, he decided to go to the concert despite the rain."}]},{"spanish_text":"Pese a ello","english_text":"Despite that","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A phrase used to indicate that something is true in spite of a previously mentioned fact.","main_translations_es":["Aun así","Sin embargo","No obstante"],"collocations":["Despite that, ...","Despite that, he continued","Despite that, the results were positive"],"synonyms_en":["Nevertheless","Even so","Nonetheless"],"example_sentence":"Despite that, he decided to continue with the project.","example_es":"Pese a ello, decidió continuar con el proyecto.","example_en":"Despite that, he decided to continue with the project.","mnemonic_en":"Picture peas rolling past the word that, still moving despite that","cloze_distractors_en":[],"examples":[{"es":"Pese a ello, decidió continuar con el proyecto.","en":"Despite that, he decided to continue with the project."}]},{"spanish_text":"No necesariamente","english_text":"Not necessarily","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"Used to indicate that something is not always the case or not required.","main_translations_es":["No tiene que ser","No es obligatorio","No necesariamente"],"collocations":["not necessarily true","not necessarily the case","not necessarily required","not necessarily a problem"],"synonyms_en":["maybe not","not always","perhaps not"],"example_sentence":"You don''t necessarily have to work on weekends.","example_es":"No necesariamente tienes que trabajar los fines de semana.","example_en":"You don''t necessarily have to work on weekends.","mnemonic_en":"Picture a loose knot that isn’t necessarily tied, as if the Spanish ''no'' refuses to be fixed.","cloze_distractors_en":[],"examples":[{"es":"No necesariamente tienes que trabajar los fines de semana.","en":"You don''t necessarily have to work on weekends."}]},{"spanish_text":"No se sigue de eso","english_text":"That does not necessarily follow","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A statement indicating that a conclusion cannot be assumed from the given premise.","main_translations_es":["No se deduce de eso","No se infiere de eso","No se concluye a partir de eso"],"collocations":["does not necessarily follow","necessarily follow from","does not follow logically","does not necessarily follow that"],"synonyms_en":["It may not follow","That isn’t implied","It doesn’t necessarily follow"],"example_sentence":"Just because you won the lottery, that does not necessarily follow that you''ll be happy.","example_es":"Solo porque ganaste la lotería, no se sigue de eso que serás feliz.","example_en":"Just because you won the lottery, that does not necessarily follow that you''ll be happy.","mnemonic_en":"Picture a sign reading “No se” that refuses to follow the line.","cloze_distractors_en":[],"examples":[{"es":"Solo porque ganaste la lotería, no se sigue de eso que serás feliz.","en":"Just because you won the lottery, that does not necessarily follow that you''ll be happy."}]},{"spanish_text":"Eso depende","english_text":"That depends","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"It indicates that the outcome or answer varies depending on certain conditions.","main_translations_es":["Depende","Depende de eso","Eso depende de"],"collocations":["That depends on…","It depends on the situation","That depends on the context","It depends"],"synonyms_en":["It varies","Depends on","It''s conditional"],"example_sentence":"That depends on the time you arrive.","example_es":"Eso depende de la hora en que llegues.","example_en":"That depends on the time you arrive.","mnemonic_en":"Imagine a seesaw labeled eso that tilts each time you say that depends","cloze_distractors_en":[],"examples":[{"es":"Eso depende de la hora en que llegues.","en":"That depends on the time you arrive."}]},{"spanish_text":"Depende del contexto","english_text":"It depends on the context","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A statement indicating that the meaning or outcome varies according to the situation.","main_translations_es":["Depende de la situación","Según el contexto","Varía según el contexto"],"collocations":["It depends on the context","That depends on the context","It all depends on the context"],"synonyms_en":["depends on the situation","varies with context","contingent on the context"],"example_sentence":"It depends on the context, but it is usually used in formal situations.","example_es":"Depende del contexto, pero generalmente se usa en situaciones formales.","example_en":"It depends on the context, but it is usually used in formal situations.","mnemonic_en":"Picture a dependent leaning on a book of text, because it depends on the context","cloze_distractors_en":[],"examples":[{"es":"Depende del contexto, pero generalmente se usa en situaciones formales.","en":"It depends on the context, but it is usually used in formal situations."}]},{"spanish_text":"No es tan simple","english_text":"It is not that straightforward","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"It means that something is not as simple or clear as it might seem.","main_translations_es":["No es tan sencillo","No es tan fácil","No es tan claro"],"collocations":["It is not that straightforward to explain","It is not that straightforward to solve","It is not that straightforward in practice","It is not that straightforward for beginners"],"synonyms_en":["It''s not that simple","It''s not that easy","It''s more complicated"],"example_sentence":"It''s not that simple to solve this problem.","example_es":"No es tan simple resolver este problema.","example_en":"It''s not that simple to solve this problem.","mnemonic_en":"Picture a ''no'' sign crossing a simple line—so it''s not that straightforward.","cloze_distractors_en":[],"examples":[{"es":"No es tan simple resolver este problema.","en":"It''s not that simple to solve this problem."}]},{"spanish_text":"Es una simplificación excesiva","english_text":"That is an oversimplification","section_name":"Discussion and Debate","part_of_speech":"noun","definition_en":"A statement that reduces a complex issue to overly simple terms.","main_translations_es":["Es una simplificación exagerada","Es una simplificación demasiado simple","Es una simplificación desmedida"],"collocations":["That''s an oversimplification of the issue","It''s an oversimplification of the problem","Such a view is an oversimplification","Calling it an oversimplification"],"synonyms_en":["overly simplistic","too simplistic","simplistic"],"example_sentence":"Saying that the problem will be solved in a week is an oversimplification.","example_es":"Decir que el problema se resolverá en una semana es una simplificación excesiva.","example_en":"Saying that the problem will be solved in a week is an oversimplification.","mnemonic_en":"Picture an over‑simplified map called oversimplification, echoing the Spanish simplificación.","cloze_distractors_en":[],"examples":[{"es":"Decir que el problema se resolverá en una semana es una simplificación excesiva.","en":"Saying that the problem will be solved in a week is an oversimplification."}]},{"spanish_text":"Podría interpretarse de otra manera","english_text":"It could be interpreted differently","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"It means that something may be understood in another way.","main_translations_es":["Podría entenderse de otra forma","Se podría interpretar de otra manera","Podría leerse de modo distinto"],"collocations":["This statement could be interpreted differently","The results could be interpreted differently","Such a comment could be interpreted differently","These findings could be interpreted differently"],"synonyms_en":["It may be understood differently","It could be read another way","It might be seen differently"],"example_sentence":"It could be interpreted differently if we consider the context.","example_es":"Podría interpretarse de otra manera si consideramos el contexto.","example_en":"It could be interpreted differently if we consider the context.","mnemonic_en":"A pod could be read as a different story.","cloze_distractors_en":[],"examples":[{"es":"Podría interpretarse de otra manera si consideramos el contexto.","en":"It could be interpreted differently if we consider the context."}]},{"spanish_text":"Hay margen para debatir","english_text":"There is room for debate","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"It means that a topic can be discussed and different opinions are possible.","main_translations_es":["Hay espacio para debatir","Se puede debatir","Existe margen para debatir"],"collocations":["There is room for debate on this issue","It leaves room for debate","This point is open to debate","The matter remains open to debate"],"synonyms_en":["Open to discussion","It''s debatable","Subject to debate"],"example_sentence":"In the meeting, there is room for debate about the proposed changes.","example_es":"En la reunión, hay margen para debatir los cambios propuestos.","example_en":"In the meeting, there is room for debate about the proposed changes.","mnemonic_en":"Picture a spacious room with a margin line where everyone debates loudly.","cloze_distractors_en":[],"examples":[{"es":"En la reunión, hay margen para debatir los cambios propuestos.","en":"In the meeting, there is room for debate about the proposed changes."}]},{"spanish_text":"Eso sigue siendo discutible","english_text":"That remains debatable","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"It means that the matter is still open to debate.","main_translations_es":["Eso sigue siendo debatible","Eso continúa siendo discutible","Eso aún es objeto de debate"],"collocations":["The issue remains debatable","His claim remains debatable","The outcome remains debatable"],"synonyms_en":["still questionable","still up for debate","still arguable"],"example_sentence":"Even after all this time, that remains debatable.","example_es":"Aunque ya pasó mucho tiempo, eso sigue siendo discutible.","example_en":"Even after all this time, that remains debatable.","mnemonic_en":"That remains debatable, as ''discutible'' sounds like ''this cute table'' that never settles.","cloze_distractors_en":[],"examples":[{"es":"Aunque ya pasó mucho tiempo, eso sigue siendo discutible.","en":"Even after all this time, that remains debatable."}]},{"spanish_text":"Es una cuestión compleja","english_text":"It is a complex issue","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A statement that something is complicated or difficult.","main_translations_es":["Es un tema complejo","Se trata de un asunto complicado","Es una cuestión complicada"],"collocations":["a complex issue","address a complex issue","tackle a complex issue","the complex issue"],"synonyms_en":["It''s a complicated matter","It''s a difficult problem","It''s a tangled situation"],"example_sentence":"It is a complex issue.","example_es":"Es una cuestión compleja.","example_en":"It is a complex issue.","mnemonic_en":"See a complex maze with a sign that reads cuestión to remember it’s a complex issue","cloze_distractors_en":[],"examples":[{"es":"Es una cuestión compleja.","en":"It is a complex issue."}]},{"spanish_text":"No hay una respuesta única","english_text":"There is no one-size-fits-all answer","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"It means that no single solution works for every situation.","main_translations_es":["No existe una única respuesta","No hay una solución única","No hay una respuesta universal"],"collocations":["There is no one-size-fits-all answer, so we must adapt","Because there is no one-size-fits-all answer, each case is different","There is no one-size-fits-all answer; tailor your strategy accordingly"],"synonyms_en":["no universal answer","no single solution","no blanket answer"],"example_sentence":"There is no one-size-fits-all answer to this problem.","example_es":"No hay una respuesta única a este problema.","example_en":"There is no one-size-fits-all answer to this problem.","mnemonic_en":"Picture a ''no hay'' sign over a one-size-fits-all answer, showing it''s not unique.","cloze_distractors_en":[],"examples":[{"es":"No hay una respuesta única a este problema.","en":"There is no one-size-fits-all answer to this problem."}]},{"spanish_text":"Estoy a favor","english_text":"I am in favor of","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"Used to state that you support or agree with something.","main_translations_es":["Apoyo","Estoy a favor de","Me inclino por"],"collocations":["I am in favor of the proposal","I am in favor of this plan","I am in favor of change"],"synonyms_en":["I support","I approve of","I back"],"example_sentence":"I am in favor of the proposed law.","example_es":"Estoy a favor de la propuesta de ley.","example_en":"I am in favor of the proposed law.","mnemonic_en":"Picture yourself handing a favor to someone and saying, I am in favor of it.","cloze_distractors_en":[],"examples":[{"es":"Estoy a favor de la propuesta de ley.","en":"I am in favor of the proposed law."}]},{"spanish_text":"Estoy en contra","english_text":"I am opposed to","section_name":"Discussion and Debate","part_of_speech":"verb phrase","definition_en":"It means that I am against something.","main_translations_es":["Me opongo a","Estoy en desacuerdo con","No estoy a favor de"],"collocations":["I am opposed to the new policy","I am opposed to violence","I am opposed to that idea"],"synonyms_en":["I disagree with","I object to","I am against"],"example_sentence":"I am opposed to the government''s decision.","example_es":"Estoy en contra de la decisión del gobierno.","example_en":"I am opposed to the government''s decision.","mnemonic_en":"I am opposed to the big red ''contra'' sign on the door.","cloze_distractors_en":[],"examples":[{"es":"Estoy en contra de la decisión del gobierno.","en":"I am opposed to the government''s decision."}]},{"spanish_text":"Valoro tu punto","english_text":"I appreciate your point","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A polite way of saying that you understand and value someone''s argument or opinion.","main_translations_es":["Aprecio tu punto","Valoro tu argumento","Reconozco tu punto"],"collocations":["I appreciate your point, but...","I appreciate your point of view","I really appreciate your point","I appreciate your point and will consider it"],"synonyms_en":["I see your point","I value your point","I understand your point"],"example_sentence":"I appreciate your point, but I think there''s another perspective.","example_es":"Valoro tu punto, pero creo que hay otra perspectiva.","example_en":"I appreciate your point, but I think there''s another perspective.","mnemonic_en":"Picture a valet (valoro) handing you a pointy pen, saying ''I appreciate your point''.","cloze_distractors_en":[],"examples":[{"es":"Valoro tu punto, pero creo que hay otra perspectiva.","en":"I appreciate your point, but I think there''s another perspective."}]},{"spanish_text":"Entiendo de dónde vienes","english_text":"I see where you are coming from","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"It means that you understand someone''s perspective or reasoning.","main_translations_es":["Comprendo de dónde vienes","Entiendo tu punto de vista","Sé de dónde vienes"],"collocations":["I see where you''re coming from","I get your point","I understand your perspective","I see your point"],"synonyms_en":["I understand your perspective","I get your point","I see your point"],"example_sentence":"I see where you are coming from, so I will support your decision.","example_es":"Entiendo de dónde vienes, así que apoyaré tu decisión.","example_en":"I see where you are coming from, so I will support your decision.","mnemonic_en":"I picture a vein (vien) pointing from your hometown, so I see where you come from","cloze_distractors_en":[],"examples":[{"es":"Entiendo de dónde vienes, así que apoyaré tu decisión.","en":"I see where you are coming from, so I will support your decision."}]},{"spanish_text":"Eso tiene sentido","english_text":"That makes sense","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"Used to say that something is logical or understandable.","main_translations_es":["Tiene sentido","Eso tiene lógica","Eso tiene razón"],"collocations":["makes sense of","makes sense to","makes sense now","it makes sense"],"synonyms_en":["makes sense","is logical","adds up"],"example_sentence":"That makes sense, so I''ll follow the plan.","example_es":"Eso tiene sentido, así que seguiré el plan.","example_en":"That makes sense, so I''ll follow the plan.","mnemonic_en":"Imagine a sensible hat that says sentido and nods, showing that makes sense.","cloze_distractors_en":[],"examples":[{"es":"Eso tiene sentido, así que seguiré el plan.","en":"That makes sense, so I''ll follow the plan."}]},{"spanish_text":"No estoy seguro de que eso sea exacto","english_text":"I am not sure that is accurate","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A statement expressing uncertainty about the accuracy of something.","main_translations_es":["No estoy seguro de que sea exacto","No tengo la certeza de que eso sea exacto","Dudo que eso sea exacto"],"collocations":["I''m not sure that''s accurate","I''m not sure if that''s accurate","I''m not sure about the accuracy"],"synonyms_en":["I''m uncertain it''s correct","I doubt it''s precise","I''m not convinced it''s right"],"example_sentence":"I''m not sure that is accurate, but I think it''s close.","example_es":"No estoy seguro de que eso sea exacto, pero creo que está cerca.","example_en":"I''m not sure that is accurate, but I think it''s close.","mnemonic_en":"I''m not sure, like a doubtful cow rating exactness, so I question if it''s accurate","cloze_distractors_en":[],"examples":[{"es":"No estoy seguro de que eso sea exacto, pero creo que está cerca.","en":"I''m not sure that is accurate, but I think it''s close."}]},{"spanish_text":"Eso no parece convincente","english_text":"That does not sound convincing","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"It means that something is not perceived as believable or persuasive.","main_translations_es":["Eso no suena convincente","Eso no parece creíble","Eso no resulta convincente"],"collocations":["does not sound convincing","sounds unconvincing","fails to convince","lacks credibility"],"synonyms_en":["unconvincing","not persuasive","hard to believe"],"example_sentence":"That does not sound convincing, so I don''t believe it.","example_es":"Eso no parece convincente, así que no lo creo.","example_en":"That does not sound convincing, so I don''t believe it.","mnemonic_en":"Picture a speaker shouting That does not sound convincing as the word sonido shatters.","cloze_distractors_en":[],"examples":[{"es":"Eso no parece convincente, así que no lo creo.","en":"That does not sound convincing, so I don''t believe it."}]},{"spanish_text":"Me cuesta aceptar esa idea","english_text":"I struggle to accept that idea","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"To have difficulty accepting that idea.","main_translations_es":["Me cuesta aceptar esa idea","Me resulta difícil aceptar esa idea","Tengo problemas para aceptar esa idea"],"collocations":["I struggle to accept that idea","It''s hard to accept that idea","I find it difficult to accept that idea","I can''t seem to accept that idea"],"synonyms_en":["find it hard to accept that idea","have trouble accepting that idea","can''t come to terms with that idea"],"example_sentence":"I struggle to accept that idea, but I know it''s important.","example_es":"Me cuesta aceptar esa idea, pero sé que es importante.","example_en":"I struggle to accept that idea, but I know it''s important.","mnemonic_en":"I picture a heavy cost weighing on me as I try to accept the idea.","cloze_distractors_en":[],"examples":[{"es":"Me cuesta aceptar esa idea, pero sé que es importante.","en":"I struggle to accept that idea, but I know it''s important."}]},{"spanish_text":"Podrías tener razón","english_text":"You may be right","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A polite way of saying that someone could be correct.","main_translations_es":["Quizás tengas razón","Puede que tengas razón","Tal vez tengas razón"],"collocations":["You may be right about that","You may be right, after all","You may be right, I guess"],"synonyms_en":["perhaps you''re correct","could be right","maybe correct"],"example_sentence":"You may be right, but I still want to try.","example_es":"Podrías tener razón, pero aún así quiero intentarlo.","example_en":"You may be right, but I still want to try.","mnemonic_en":"Picture a judge nodding, saying ''You may be right'', holding a big sign that reads RAZÓN.","cloze_distractors_en":[],"examples":[{"es":"Podrías tener razón, pero aún así quiero intentarlo.","en":"You may be right, but I still want to try."}]},{"spanish_text":"Hay algo de verdad en eso","english_text":"There is some truth in that","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"It means that the statement contains a certain amount of truth.","main_translations_es":["Hay algo de verdad en eso","Hay algo de verdad en lo que dices","Hay algo de verdad en esa afirmación"],"collocations":["There''s some truth in that.","There''s some truth to that.","There''s some truth in what you said.","There''s some truth behind that claim."],"synonyms_en":["That''s partly true","There''s some validity there","That''s somewhat true"],"example_sentence":"There is some truth in that, although not everything is accurate.","example_es":"Hay algo de verdad en eso, aunque no todo es exacto.","example_en":"There is some truth in that, although not everything is accurate.","mnemonic_en":"When you shout Hey and see a big truth sign, you remember There is some truth in that.","cloze_distractors_en":[],"examples":[{"es":"Hay algo de verdad en eso, aunque no todo es exacto.","en":"There is some truth in that, although not everything is accurate."}]},{"spanish_text":"No descartaría esa posibilidad","english_text":"I would not rule that out","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A statement indicating that something is still considered possible.","main_translations_es":["No excluiría esa posibilidad","No descartaría esa opción","No lo descartaría"],"collocations":["I would not rule out the possibility","I would not rule out that option","I would not rule out a chance","I would not rule out the idea"],"synonyms_en":["I wouldn''t dismiss that","I wouldn''t eliminate that","I wouldn''t rule it out"],"example_sentence":"I would not rule that out, even though I''m still uncertain.","example_es":"No descartaría esa posibilidad, aunque todavía tengo dudas.","example_en":"I would not rule that out, even though I''m still uncertain.","mnemonic_en":"Picture a big sign saying No regla while I say I would not rule that out","cloze_distractors_en":[],"examples":[{"es":"No descartaría esa posibilidad, aunque todavía tengo dudas.","en":"I would not rule that out, even though I''m still uncertain."}]},{"spanish_text":"Vale la pena analizarlo","english_text":"It is worth examining","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"Something that should be looked at because it may be valuable or important.","main_translations_es":["Merece ser analizado","Vale la pena revisarlo","Conviene examinarlo"],"collocations":["It is worth examining further","It is worth examining the data","It is worth examining the evidence"],"synonyms_en":["deserves scrutiny","merits investigation","should be studied"],"example_sentence":"It is worth examining it before making a decision.","example_es":"Vale la pena analizarlo antes de tomar una decisión.","example_en":"It is worth examining it before making a decision.","mnemonic_en":"Imagine a valuable pen being examined under a microscope.","cloze_distractors_en":[],"examples":[{"es":"Vale la pena analizarlo antes de tomar una decisión.","en":"It is worth examining it before making a decision."}]},{"spanish_text":"No deberíamos apresurarnos","english_text":"We should not jump to conclusions","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"It means we ought not to form opinions before having all the facts.","main_translations_es":["No deberíamos precipitarse","No debemos apresurarnos","No hay que ir deprisa"],"collocations":["don''t jump to conclusions","avoid jumping to conclusions","stop jumping to conclusions"],"synonyms_en":["avoid assumptions","don''t assume","hold off judgment"],"example_sentence":"We should not jump to conclusions before analyzing all the data.","example_es":"No deberíamos apresurarnos a sacar conclusiones sin analizar todos los datos.","example_en":"We should not jump to conclusions before analyzing all the data.","mnemonic_en":"Visualize a frantic jumper pausing at the finish line, reminding you not to rush and jump to conclusions.","cloze_distractors_en":[],"examples":[{"es":"No deberíamos apresurarnos a sacar conclusiones sin analizar todos los datos.","en":"We should not jump to conclusions before analyzing all the data."}]},{"spanish_text":"Conviene matizar","english_text":"We need to qualify that","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"To add a clarification or nuance to a statement.","main_translations_es":["Es conveniente matizar","Resulta necesario matizar","Conviene aclarar"],"collocations":["to qualify that statement","to qualify that claim","to qualify that point","to qualify that observation"],"synonyms_en":["We must clarify that","We should specify that","We have to qualify that"],"example_sentence":"We need to qualify that the report does not include all the relevant data.","example_es":"Conviene matizar que el informe no incluye todos los datos relevantes.","example_en":"We need to qualify that the report does not include all the relevant data.","mnemonic_en":"To qualify that, imagine a judge placing a mat on the document.","cloze_distractors_en":[],"examples":[{"es":"Conviene matizar que el informe no incluye todos los datos relevantes.","en":"We need to qualify that the report does not include all the relevant data."}]},{"spanish_text":"Eso requiere evidencia","english_text":"That requires evidence","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"It states that something needs proof or supporting evidence.","main_translations_es":["Eso necesita pruebas","Eso demanda evidencia","Eso requiere pruebas"],"collocations":["requires evidence","requires solid evidence","requires concrete evidence","requires supporting evidence"],"synonyms_en":["needs proof","calls for proof","demands proof"],"example_sentence":"That requires evidence before making a decision.","example_es":"Eso requiere evidencia antes de tomar una decisión.","example_en":"That requires evidence before making a decision.","mnemonic_en":"Imagine a detective saying That requires evidence while holding a file labeled evidencia.","cloze_distractors_en":[],"examples":[{"es":"Eso requiere evidencia antes de tomar una decisión.","en":"That requires evidence before making a decision."}]},{"spanish_text":"¿En qué te basas?","english_text":"What are you basing that on?","section_name":"Discussion and Debate","part_of_speech":"question","definition_en":"A question asking for the basis or justification of something.","main_translations_es":["¿En qué te basas?","¿Sobre qué te apoyas?","¿Qué fundamento tiene?"],"collocations":["basing decisions on","basing your argument on","basing the plan on"],"synonyms_en":["What''s your source?","On what basis?","What evidence supports that?"],"example_sentence":"What are you basing that on when you say the project will fail?","example_es":"¿En qué te basas para decir que el proyecto fracasará?","example_en":"What are you basing that on when you say the project will fail?","mnemonic_en":"Picture a baseball base shouting, What are you basing that on?","cloze_distractors_en":[],"examples":[{"es":"¿En qué te basas para decir que el proyecto fracasará?","en":"What are you basing that on when you say the project will fail?"}]},{"spanish_text":"¿Podrías desarrollar esa idea?","english_text":"Could you elaborate on that?","section_name":"Discussion and Debate","part_of_speech":"question","definition_en":"A polite request for more detail about something previously mentioned.","main_translations_es":["¿Podrías ampliar esa idea?","¿Podrías profundizar en esa idea?","¿Podrías detallar esa idea?"],"collocations":["Could you elaborate on that, please?","Could you elaborate on that a bit more?","Could you elaborate on that further?"],"synonyms_en":["Can you expand on that?","Would you clarify that?","Please give more details."],"example_sentence":"Could you elaborate on that?","example_es":"¿Podrías desarrollar esa idea?","example_en":"Could you elaborate on that?","mnemonic_en":"Picture a teacher asking could you elaborate while you elabora the idea on the board.","cloze_distractors_en":[],"examples":[{"es":"¿Podrías desarrollar esa idea?","en":"Could you elaborate on that?"}]},{"spanish_text":"¿Podrías dar un ejemplo?","english_text":"Could you give an example?","section_name":"Discussion and Debate","part_of_speech":"question","definition_en":"A polite request asking someone to provide an example.","main_translations_es":["¿Puedes dar un ejemplo?","¿Me podrías dar un ejemplo?","¿Podrías proporcionar un ejemplo?"],"collocations":["Could you give an example of that?","Could you give an example, please?","Could you give an example to illustrate?"],"synonyms_en":["Can you provide an example?","Would you show an example?","Please give an example."],"example_sentence":"Could you give an example of how to use this word?","example_es":"¿Podrías dar un ejemplo de cómo se usa esta palabra?","example_en":"Could you give an example of how to use this word?","mnemonic_en":"Picture a chef handing you a sample dish, saying ejemplo as he gives an example.","cloze_distractors_en":[],"examples":[{"es":"¿Podrías dar un ejemplo de cómo se usa esta palabra?","en":"Could you give an example of how to use this word?"}]},{"spanish_text":"¿Qué quieres decir exactamente?","english_text":"What exactly do you mean?","section_name":"Discussion and Debate","part_of_speech":"question","definition_en":"A request for clarification about the precise meaning of something.","main_translations_es":["¿Qué quieres decir con eso?","¿A qué te refieres exactamente?","¿Qué significa exactamente?"],"collocations":["What exactly do you mean by that?","I’m not sure what exactly you mean.","Could you explain what exactly you mean?","Tell me what exactly you mean."],"synonyms_en":["What do you mean?","What are you trying to say?","What are you saying?"],"example_sentence":"When he explained his plan, I asked, \"What exactly do you mean?\"","example_es":"Cuando me explicó su plan, le pregunté: ¿Qué quieres decir exactamente?","example_en":"When he explained his plan, I asked, \"What exactly do you mean?\"","mnemonic_en":"Picture an ex‑actly‑clear sign asking what you mean.","cloze_distractors_en":[],"examples":[{"es":"Cuando me explicó su plan, le pregunté: ¿Qué quieres decir exactamente?","en":"When he explained his plan, I asked, \"What exactly do you mean?\""}]},{"spanish_text":"Aclaremos un punto","english_text":"Let us clarify one point","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A polite phrase used to introduce an explanation of a specific matter.","main_translations_es":["Aclararemos un punto","Aclarar un punto","Vamos a aclarar un punto"],"collocations":["let us clarify","clarify one point","to clarify a point","let me clarify"],"synonyms_en":["Let''s clear up a point","Let''s make one thing clear","Let''s explain a point"],"example_sentence":"Let''s clarify one point before we continue.","example_es":"Aclaremos un punto antes de continuar.","example_en":"Let''s clarify one point before we continue.","mnemonic_en":"Let us make a clear point.","cloze_distractors_en":[],"examples":[{"es":"Aclaremos un punto antes de continuar.","en":"Let''s clarify one point before we continue."}]},{"spanish_text":"Quiero dejar algo claro","english_text":"I want to make something clear","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A statement used to indicate that the speaker intends to clarify a point.","main_translations_es":["Quiero aclarar algo","Quisiera dejar algo claro","Deseo dejar algo claro"],"collocations":["to make something clear","to make it clear","to be clear","to clarify"],"synonyms_en":["I want to clarify","let me clarify","I need to clarify"],"example_sentence":"I want to make something clear: I will not do it again.","example_es":"Quiero dejar algo claro: no volveré a hacerlo.","example_en":"I want to make something clear: I will not do it again.","mnemonic_en":"Picture a crystal-clear glass shouting claro as I want to make something clear.","cloze_distractors_en":[],"examples":[{"es":"Quiero dejar algo claro: no volveré a hacerlo.","en":"I want to make something clear: I will not do it again."}]},{"spanish_text":"No pretendo decir que","english_text":"I am not suggesting that","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A phrase used to state that the speaker is not implying or proposing something.","main_translations_es":["No quiero decir que","No intento afirmar que","No pretendo afirmar que"],"collocations":["I am not suggesting that you should quit","I am not suggesting that it''s a bad idea","I am not suggesting that we go now"],"synonyms_en":["I''m not implying that","I don''t mean that","I''m not insinuating that"],"example_sentence":"I am not suggesting that everyone agrees, but I think it''s important.","example_es":"No pretendo decir que todos estén de acuerdo, pero creo que es importante.","example_en":"I am not suggesting that everyone agrees, but I think it''s important.","mnemonic_en":"Picture a no‑pretend sign stopping a suggestion.","cloze_distractors_en":[],"examples":[{"es":"No pretendo decir que todos estén de acuerdo, pero creo que es importante.","en":"I am not suggesting that everyone agrees, but I think it''s important."}]},{"spanish_text":"No debería interpretarse como","english_text":"It should not be interpreted as","section_name":"Discussion and Debate","part_of_speech":"verb phrase","definition_en":"Indicates that something must not be understood in a particular way.","main_translations_es":["No debe interpretarse como","No se debe interpretar como","No ha de interpretarse como"],"collocations":["It should not be interpreted as a criticism","It should not be interpreted as a guarantee","It should not be interpreted as a promise","It should not be interpreted as an endorsement"],"synonyms_en":["It shouldn''t be taken as","It must not be read as","It is not to be understood as"],"example_sentence":"It should not be interpreted as disrespect, but as constructive criticism.","example_es":"No debería interpretarse como una falta de respeto, sino como una crítica constructiva.","example_en":"It should not be interpreted as disrespect, but as constructive criticism.","mnemonic_en":"Picture a big red NO sign over a book, reminding you it should not be interpreted as true.","cloze_distractors_en":[],"examples":[{"es":"No debería interpretarse como una falta de respeto, sino como una crítica constructiva.","en":"It should not be interpreted as disrespect, but as constructive criticism."}]},{"spanish_text":"En términos generales","english_text":"Broadly speaking","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"Used to introduce a general statement or overview of a topic.","main_translations_es":["En general","De manera general","En líneas generales"],"collocations":["Broadly speaking, the market is expanding","Broadly speaking, we can conclude","Broadly speaking, the results are positive"],"synonyms_en":["generally","in general","overall"],"example_sentence":"Broadly speaking, the country''s economy has improved this year.","example_es":"En términos generales, la economía del país ha mejorado este año.","example_en":"Broadly speaking, the country''s economy has improved this year.","mnemonic_en":"Picture a wide speaker broadcasting general terms to a crowd.","cloze_distractors_en":[],"examples":[{"es":"En términos generales, la economía del país ha mejorado este año.","en":"Broadly speaking, the country''s economy has improved this year."}]},{"spanish_text":"En términos concretos","english_text":"In practical terms","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"Used to introduce a concrete or realistic explanation of something.","main_translations_es":["En términos prácticos","En la práctica","De manera concreta"],"collocations":["In practical terms, this means...","In practical terms, we can see...","In practical terms, the cost is...","In practical terms, it''s easier..."],"synonyms_en":["practically speaking","in practice","actually"],"example_sentence":"In practical terms, the project will cost ten thousand euros.","example_es":"En términos concretos, el proyecto costará diez mil euros.","example_en":"In practical terms, the project will cost ten thousand euros.","mnemonic_en":"Picture a concrete block labeled In practical terms on a construction plan.","cloze_distractors_en":[],"examples":[{"es":"En términos concretos, el proyecto costará diez mil euros.","en":"In practical terms, the project will cost ten thousand euros."}]},{"spanish_text":"A primera vista","english_text":"At first glance","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"Used to indicate an initial impression based on a quick look.","main_translations_es":["A primera vista","A simple vista","A primera impresión"],"collocations":["At first glance, it seems...","At first glance, the data suggests...","At first glance, the results appear..."],"synonyms_en":["at first sight","on first look","at a glance"],"example_sentence":"At first glance, the painting seems simple, but upon closer inspection it reveals many details.","example_es":"A primera vista, el cuadro parece sencillo, pero al observarlo más de cerca revela muchos detalles.","example_en":"At first glance, the painting seems simple, but upon closer inspection it reveals many details.","mnemonic_en":"Imagine a first‑glance view of a beautiful vista, a prima scene you see instantly.","cloze_distractors_en":[],"examples":[{"es":"A primera vista, el cuadro parece sencillo, pero al observarlo más de cerca revela muchos detalles.","en":"At first glance, the painting seems simple, but upon closer inspection it reveals many details."}]},{"spanish_text":"A largo plazo","english_text":"In the long term","section_name":"Discussion and Debate","part_of_speech":"adverbial phrase","definition_en":"Refers to a period of time far in the future.","main_translations_es":["A largo plazo","A futuro","En el futuro"],"collocations":["in the long term","over the long term","in the long run","for the long term"],"synonyms_en":["over time","in the long run","eventually"],"example_sentence":"In the long term, investing in renewable energy will generate economic benefits.","example_es":"A largo plazo, la inversión en energía renovable generará beneficios económicos.","example_en":"In the long term, investing in renewable energy will generate economic benefits.","mnemonic_en":"Picture a long, endless runway labeled ''largo'' showing the future lasting forever.","cloze_distractors_en":[],"examples":[{"es":"A largo plazo, la inversión en energía renovable generará beneficios económicos.","en":"In the long term, investing in renewable energy will generate economic benefits."}]},{"spanish_text":"A corto plazo","english_text":"In the short term","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"During a brief period of time; referring to the near future.","main_translations_es":["A corto plazo","En el corto plazo","A corto término"],"collocations":["in the short term","short‑term plan","short‑term benefits","short‑term outlook"],"synonyms_en":["short‑term","temporarily","for now"],"example_sentence":"In the short term, the company plans to increase its sales by 10%.","example_es":"A corto plazo, la empresa planea aumentar sus ventas en un 10%.","example_en":"In the short term, the company plans to increase its sales by 10%.","mnemonic_en":"Picture a short‑term deadline tied to a tight ''corto'' rope.","cloze_distractors_en":[],"examples":[{"es":"A corto plazo, la empresa planea aumentar sus ventas en un 10%.","en":"In the short term, the company plans to increase its sales by 10%."}]},{"spanish_text":"En el peor de los casos","english_text":"In the worst-case scenario","section_name":"Discussion and Debate","part_of_speech":"idiomatic expression","definition_en":"It refers to the most unfavorable possible outcome.","main_translations_es":["En el peor de los casos","En el peor escenario","En el caso más desfavorable"],"collocations":["In the worst-case scenario, we could lose everything.","In the worst-case scenario, the project will be delayed.","In the worst-case scenario, the system may crash."],"synonyms_en":["at worst","in the worst case","in worst-case"],"example_sentence":"In the worst-case scenario, we will have to cancel the event.","example_es":"En el peor de los casos, tendremos que cancelar el evento.","example_en":"In the worst-case scenario, we will have to cancel the event.","mnemonic_en":"Picture a worst-case scenario as a ''peor'' case spilling over the floor.","cloze_distractors_en":[],"examples":[{"es":"En el peor de los casos, tendremos que cancelar el evento.","en":"In the worst-case scenario, we will have to cancel the event."}]},{"spanish_text":"En el mejor de los casos","english_text":"In the best-case scenario","section_name":"Discussion and Debate","part_of_speech":"idiomatic expression","definition_en":"Used to describe the most favorable possible outcome.","main_translations_es":["En el mejor de los casos","En el caso más favorable","En el escenario óptimo"],"collocations":["In the best-case scenario, we succeed","In the best-case scenario, costs are lower","In the best-case scenario, the project finishes early"],"synonyms_en":["at best","in the ideal case","if all goes well"],"example_sentence":"In the best-case scenario, the project will be completed in three months.","example_es":"En el mejor de los casos, el proyecto se completará en tres meses.","example_en":"In the best-case scenario, the project will be completed in three months.","mnemonic_en":"Picture a mayor (mejor) approving the best‑case scenario.","cloze_distractors_en":[],"examples":[{"es":"En el mejor de los casos, el proyecto se completará en tres meses.","en":"In the best-case scenario, the project will be completed in three months."}]},{"spanish_text":"En última instancia","english_text":"Ultimately","section_name":"Discussion and Debate","part_of_speech":"adverb","definition_en":"In the end, after everything else has been considered.","main_translations_es":["Finalmente","A fin de cuentas","En definitiva"],"collocations":["Ultimately, we decided to go ahead","Ultimately, it comes down to cost","Ultimately, the results speak for themselves"],"synonyms_en":["in the end","finally","eventually"],"example_sentence":"Ultimately, we will decide whether the project continues.","example_es":"En última instancia, decidiremos si el proyecto continúa.","example_en":"Ultimately, we will decide whether the project continues.","mnemonic_en":"Picture the ultimate trophy on the final última podium, showing everything ends there.","cloze_distractors_en":[],"examples":[{"es":"En última instancia, decidiremos si el proyecto continúa.","en":"Ultimately, we will decide whether the project continues."}]},{"spanish_text":"Al fin y al cabo","english_text":"After all","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"Used to emphasize a conclusion that follows from what has been said or to point out that something is true when all factors are considered.","main_translations_es":["En definitiva","Al final","A fin de cuentas"],"collocations":["after all is said and done","after all, it''s worth trying","after all, we are human"],"synonyms_en":["in the end","ultimately","when all is said and done"],"example_sentence":"After all, we all make mistakes.","example_es":"Al fin y al cabo, todos cometemos errores.","example_en":"After all, we all make mistakes.","mnemonic_en":"Picture the final curtain falling and everyone saying after al as the show ends.","cloze_distractors_en":[],"examples":[{"es":"Al fin y al cabo, todos cometemos errores.","en":"After all, we all make mistakes."}]},{"spanish_text":"En resumen","english_text":"To sum up","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"Used to introduce a brief summary of what has been said.","main_translations_es":["En síntesis","En pocas palabras","Resumiendo"],"collocations":["To sum up, ...","To sum up the findings","To sum up the report"],"synonyms_en":["In short","In summary","Overall"],"example_sentence":"To sum up, the project was a success.","example_es":"En resumen, el proyecto fue un éxito.","example_en":"To sum up, the project was a success.","mnemonic_en":"Picture a calculator adding a suma, then you sum up the whole story.","cloze_distractors_en":[],"examples":[{"es":"En resumen, el proyecto fue un éxito.","en":"To sum up, the project was a success."}]},{"spanish_text":"Para resumir","english_text":"To summarize","section_name":"Discussion and Debate","part_of_speech":"verb","definition_en":"To give a brief statement of the main points.","main_translations_es":["En resumen","Resumiendo","Para concluir"],"collocations":["To summarize, ...","To summarize the findings","To summarize briefly","To summarize the main points"],"synonyms_en":["In brief","In summary","To sum up"],"example_sentence":"To summarize, the project was a success.","example_es":"Para resumir, el proyecto fue un éxito.","example_en":"To summarize, the project was a success.","mnemonic_en":"Picture a parrot giving a quick summary, shouting ''para resumir'' as it folds the paper.","cloze_distractors_en":[],"examples":[{"es":"Para resumir, el proyecto fue un éxito.","en":"To summarize, the project was a success."}]},{"spanish_text":"En esencia","english_text":"Essentially","section_name":"Discussion and Debate","part_of_speech":"adverb","definition_en":"In a basic or fundamental way; basically.","main_translations_es":["Básicamente","En resumen","En esencia"],"collocations":["essentially the same","essentially a matter of","essentially, …"],"synonyms_en":["basically","fundamentally","in essence"],"example_sentence":"Essentially, the project aims to improve air quality in the city.","example_es":"En esencia, el proyecto busca mejorar la calidad del aire en la ciudad.","example_en":"Essentially, the project aims to improve air quality in the city.","mnemonic_en":"Think of a bottle labeled en esencia, the essential core, and you’ll recall essentially.","cloze_distractors_en":[],"examples":[{"es":"En esencia, el proyecto busca mejorar la calidad del aire en la ciudad.","en":"Essentially, the project aims to improve air quality in the city."}]},{"spanish_text":"En pocas palabras","english_text":"In a nutshell","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"Briefly; in a concise summary.","main_translations_es":["En resumen","En síntesis","Resumiendo"],"collocations":["to put it in a nutshell","in a nutshell, ...","the story in a nutshell","the whole thing in a nutshell"],"synonyms_en":["briefly","to sum up","in short"],"example_sentence":"In a nutshell, the project was a success.","example_es":"En pocas palabras, el proyecto fue un éxito.","example_en":"In a nutshell, the project was a success.","mnemonic_en":"Imagine a tiny nut shell holding just a few words.","cloze_distractors_en":[],"examples":[{"es":"En pocas palabras, el proyecto fue un éxito.","en":"In a nutshell, the project was a success."}]},{"spanish_text":"La cuestión central es","english_text":"The key issue is","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A phrase used to introduce the most important problem or topic.","main_translations_es":["El tema principal es","El asunto central es","Lo fundamental es"],"collocations":["The key issue is whether…","The key issue is how…","The key issue is that…","The key issue is the lack of…"],"synonyms_en":["The main point is","The primary concern is","The central matter is"],"example_sentence":"The key issue is how to improve education in rural areas.","example_es":"La cuestión central es cómo mejorar la educación en las zonas rurales.","example_en":"The key issue is how to improve education in rural areas.","mnemonic_en":"Picture a key opening a big issue sign, like the Spanish ''qué'' and ''cuestión''.","cloze_distractors_en":[],"examples":[{"es":"La cuestión central es cómo mejorar la educación en las zonas rurales.","en":"The key issue is how to improve education in rural areas."}]},{"spanish_text":"Eso nos lleva a","english_text":"That brings us to","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A phrase used to transition to the next point or topic.","main_translations_es":["Esto nos lleva a","Esto nos conduce a","Esto nos dirige a"],"collocations":["That brings us to the next point","That brings us to a conclusion","That brings us to the final step","That brings us to the heart of the matter"],"synonyms_en":["This leads to","Now we come to","This takes us to"],"example_sentence":"That brings us to the conclusion that we must act now.","example_es":"Eso nos lleva a la conclusión de que debemos actuar ahora.","example_en":"That brings us to the conclusion that we must act now.","mnemonic_en":"Picture a bridge labeled That brings us to, while the Spanish chant eso nos lleva a echoes across it.","cloze_distractors_en":[],"examples":[{"es":"Eso nos lleva a la conclusión de que debemos actuar ahora.","en":"That brings us to the conclusion that we must act now."}]},{"spanish_text":"Hay otro ángulo","english_text":"There is another angle to consider","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"It means that there is an additional perspective or aspect that should be taken into account.","main_translations_es":["Existe otro ángulo","Hay otra perspectiva","Se puede observar otro ángulo"],"collocations":["We should remember there is another angle to consider","It''s important to note there is another angle to consider","Before concluding, consider that there is another angle to consider"],"synonyms_en":["another perspective","another viewpoint","another aspect to consider"],"example_sentence":"There is another angle we must consider.","example_es":"Hay otro ángulo que debemos considerar.","example_en":"There is another angle we must consider.","mnemonic_en":"Picture a fresh angle shaped like ''otro'' pointing at a triangle, reminding you there is another angle to consider","cloze_distractors_en":[],"examples":[{"es":"Hay otro ángulo que debemos considerar.","en":"There is another angle we must consider."}]},{"spanish_text":"No perdamos de vista que","english_text":"Let us not lose sight of the fact that","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A phrase urging someone to keep an important point in mind.","main_translations_es":["No olvidemos que","No perdamos de vista el hecho de que","Mantengamos presente que"],"collocations":["let us not lose sight of the fact that","we must not lose sight of the fact that","do not lose sight of the fact that","it is crucial not to lose sight of the fact that"],"synonyms_en":["let''s keep in mind","let''s bear in mind","let''s not overlook"],"example_sentence":"Let us not lose sight of the fact that health is the most important thing.","example_es":"No perdamos de vista que la salud es lo más importante.","example_en":"Let us not lose sight of the fact that health is the most important thing.","mnemonic_en":"Let us not lose sight—imagine a lighthouse keeping the vista clear.","cloze_distractors_en":[],"examples":[{"es":"No perdamos de vista que la salud es lo más importante.","en":"Let us not lose sight of the fact that health is the most important thing."}]},{"spanish_text":"Conviene recordar que","english_text":"It is worth remembering that","section_name":"Discussion and Debate","part_of_speech":"idiomatic expression","definition_en":"A phrase used to indicate that something should be kept in mind.","main_translations_es":["Vale la pena recordar que","Hay que recordar que","Es importante recordar que"],"collocations":["It is worth remembering that...","It is worth remembering that you should...","It is worth remembering that the rules apply"],"synonyms_en":["keep in mind","remember that","note that"],"example_sentence":"It is worth remembering that punctuality is a sign of respect.","example_es":"Conviene recordar que la puntualidad es una muestra de respeto.","example_en":"It is worth remembering that punctuality is a sign of respect.","mnemonic_en":"Conveniently, I remember that it is worth noting.","cloze_distractors_en":[],"examples":[{"es":"Conviene recordar que la puntualidad es una muestra de respeto.","en":"It is worth remembering that punctuality is a sign of respect."}]},{"spanish_text":"Si somos sinceros","english_text":"If we are being honest","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A phrase used to introduce an honest statement.","main_translations_es":["Si hablamos con franqueza","Si somos francos","Si lo decimos con sinceridad"],"collocations":["If we are being honest, ...","If we are being honest, I think...","If we are being honest, the truth is...","If we are being honest, we must admit..."],"synonyms_en":["to be truthful","honestly speaking","frankly"],"example_sentence":"If we are being honest, we should admit our mistakes.","example_es":"Si somos sinceros, deberíamos admitir nuestros errores.","example_en":"If we are being honest, we should admit our mistakes.","mnemonic_en":"Visualize a truth‑telling elf saying \"If we are being honest\" while shouting \"si somos!\"","cloze_distractors_en":[],"examples":[{"es":"Si somos sinceros, deberíamos admitir nuestros errores.","en":"If we are being honest, we should admit our mistakes."}]},{"spanish_text":"En rigor","english_text":"Strictly speaking","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"Used to indicate that a statement is true only when considered in a precise or technical sense.","main_translations_es":["En realidad","En términos estrictos","En sentido estricto"],"collocations":["strictly speaking, ...","strictly speaking, the answer is","strictly speaking, it''s not","strictly speaking, we should"],"synonyms_en":["technically","in strict terms","to be precise"],"example_sentence":"Strictly speaking, the project is not finished.","example_es":"En rigor, el proyecto no está terminado.","example_en":"Strictly speaking, the project is not finished.","mnemonic_en":"Picture a strict ruler shouting En rigor as the rule for every word.","cloze_distractors_en":[],"examples":[{"es":"En rigor, el proyecto no está terminado.","en":"Strictly speaking, the project is not finished."}]},{"spanish_text":"A decir verdad","english_text":"To be honest","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A phrase used to indicate that the speaker is about to speak truthfully or sincerely.","main_translations_es":["A decir verdad","Para ser sincero","Siendo honesto"],"collocations":["to be honest, I think","to be honest with you","to be honest about","to be honest, it''s"],"synonyms_en":["frankly","honestly","in all honesty"],"example_sentence":"To be honest, I didn''t like the movie.","example_es":"A decir verdad, no me gustó la película.","example_en":"To be honest, I didn''t like the movie.","mnemonic_en":"Imagine an honest man chanting a decir verdad as his truth motto.","cloze_distractors_en":[],"examples":[{"es":"A decir verdad, no me gustó la película.","en":"To be honest, I didn''t like the movie."}]},{"spanish_text":"No me malinterpretes","english_text":"Do not get me wrong","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A request for the listener to avoid misunderstanding what the speaker means.","main_translations_es":["No me tomes a mal","No me saques conclusiones equivocadas","No me malinterpretes"],"collocations":["Do not get me wrong, but…","Do not get me wrong, I’m not…","Do not get me wrong, I love it","Do not get me wrong, it’s just…"],"synonyms_en":["don''t misunderstand me","don''t take me the wrong way","don''t misinterpret me"],"example_sentence":"Don''t get me wrong, but I think you should reconsider your decision.","example_es":"No me malinterpretes, pero creo que deberías reconsiderar tu decisión.","example_en":"Don''t get me wrong, but I think you should reconsider your decision.","mnemonic_en":"Picture a sign No me blocking a wrong road, reminding you: Do not get me wrong.","cloze_distractors_en":[],"examples":[{"es":"No me malinterpretes, pero creo que deberías reconsiderar tu decisión.","en":"Don''t get me wrong, but I think you should reconsider your decision."}]},{"spanish_text":"Sin ánimo de ofender","english_text":"No offense intended","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A statement used to indicate that the speaker does not mean to offend anyone.","main_translations_es":["Sin intención de ofender","No es mi intención ofender","No pretendo ofender"],"collocations":["no offense, but…","no offense taken","no offense, just saying","no offense, I’m being honest"],"synonyms_en":["no offense","not meant to offend","no disrespect intended"],"example_sentence":"No offense intended, I think you should reconsider your decision.","example_es":"Sin ánimo de ofender, creo que deberías reconsiderar tu decisión.","example_en":"No offense intended, I think you should reconsider your decision.","mnemonic_en":"Picture a No offense sign being torn by a sad Sin ánimo de ofender banner.","cloze_distractors_en":[],"examples":[{"es":"Sin ánimo de ofender, creo que deberías reconsiderar tu decisión.","en":"No offense intended, I think you should reconsider your decision."}]},{"spanish_text":"Con el debido respeto","english_text":"With all due respect","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A polite phrase used to preface a statement that may be critical or contrary, showing respect while disagreeing.","main_translations_es":["Con todo respeto","Con el mayor respeto","Con el debido respeto"],"collocations":["With all due respect, I must disagree","With all due respect, that''s not accurate","With all due respect, here''s my opinion"],"synonyms_en":["respectfully","if I may be frank","no offense but"],"example_sentence":"With all due respect, I think your proposal is not feasible.","example_es":"Con el debido respeto, creo que su propuesta no es viable.","example_en":"With all due respect, I think your proposal is not feasible.","mnemonic_en":"Picture a polite bow, saying ''due'' (debido) while handing over a ''respect'' (respeto) badge.","cloze_distractors_en":[],"examples":[{"es":"Con el debido respeto, creo que su propuesta no es viable.","en":"With all due respect, I think your proposal is not feasible."}]},{"spanish_text":"Permíteme disentir","english_text":"Allow me to disagree","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A polite way of saying that you do not share someone''s opinion.","main_translations_es":["Déjame disentir","Permíteme estar en desacuerdo","Permíteme discrepar"],"collocations":["Allow me to disagree, but...","Allow me to disagree with you","Allow me to disagree for a moment","Allow me to disagree on this point"],"synonyms_en":["I beg to differ","If I may object","I must disagree"],"example_sentence":"Allow me to disagree, but I think that solution won''t work.","example_es":"Permíteme disentir, pero creo que esa solución no funcionará.","example_en":"Allow me to disagree, but I think that solution won''t work.","mnemonic_en":"I raise my hand and say Allow me while a big red DISAGREE sign flashes over DISENTIR","cloze_distractors_en":[],"examples":[{"es":"Permíteme disentir, pero creo que esa solución no funcionará.","en":"Allow me to disagree, but I think that solution won''t work."}]},{"spanish_text":"Lo plantearía de otra forma","english_text":"I would frame it differently","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"To present something using different wording or perspective.","main_translations_es":["Lo expresaría de otra manera","Lo diría de otro modo","Lo presentaría de forma distinta"],"collocations":["to frame it differently","frame it in a different way","reframe the issue","look at it from another angle"],"synonyms_en":["rephrase it","present it another way","put it another way"],"example_sentence":"If I had to explain the problem, I would frame it differently.","example_es":"Si tuviera que explicar el problema, lo plantearía de otra forma.","example_en":"If I had to explain the problem, I would frame it differently.","mnemonic_en":"Picture a plant in a frame, then swap the frame for a different one.","cloze_distractors_en":[],"examples":[{"es":"Si tuviera que explicar el problema, lo plantearía de otra forma.","en":"If I had to explain the problem, I would frame it differently."}]},{"spanish_text":"Eso cambia las cosas","english_text":"That changes the picture","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"It means that the situation or understanding is altered.","main_translations_es":["Eso altera la situación","Eso modifica las cosas","Eso cambia el panorama"],"collocations":["That changes the picture completely","That changes the picture significantly","That changes the picture dramatically"],"synonyms_en":["That alters the situation","That shifts the perspective","That modifies the view"],"example_sentence":"That changes the picture, so we’ll have to rethink the plan.","example_es":"Eso cambia las cosas, así que tendremos que replantear el plan.","example_en":"That changes the picture, so we’ll have to rethink the plan.","mnemonic_en":"That changes the picture, like a photo that suddenly says ''cambia'' and flips.","cloze_distractors_en":[],"examples":[{"es":"Eso cambia las cosas, así que tendremos que replantear el plan.","en":"That changes the picture, so we’ll have to rethink the plan."}]},{"spanish_text":"Eso fortalece tu argumento","english_text":"That strengthens your argument","section_name":"Discussion and Debate","part_of_speech":"statement","definition_en":"It indicates that something makes your argument more convincing.","main_translations_es":["Eso refuerza tu argumento","Eso consolida tu argumento","Eso respalda tu argumento"],"collocations":["This evidence strengthens your argument","A strong example strengthens your argument","Such data strengthens your argument","That point strengthens your argument"],"synonyms_en":["bolsters your case","reinforces your point","supports your claim"],"example_sentence":"When you present concrete data, that strengthens your argument.","example_es":"Cuando presentas datos concretos, eso fortalece tu argumento.","example_en":"When you present concrete data, that strengthens your argument.","mnemonic_en":"That weight adds fuerza, strengthening your argument.","cloze_distractors_en":[],"examples":[{"es":"Cuando presentas datos concretos, eso fortalece tu argumento.","en":"When you present concrete data, that strengthens your argument."}]},{"spanish_text":"Eso debilita la postura","english_text":"That weakens the case","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"It means that something reduces the strength or persuasiveness of an argument.","main_translations_es":["Eso debilita la posición","Eso debilita el argumento","Eso debilita la postura"],"collocations":["This evidence weakens the case","Such arguments weaken the case","It weakens the case considerably","These facts weaken the case"],"synonyms_en":["undermines the argument","undercuts the case","diminishes the case"],"example_sentence":"If the witness lies, that weakens the case.","example_es":"Si el testigo miente, eso debilita la postura.","example_en":"If the witness lies, that weakens the case.","mnemonic_en":"Visualize a cracked case that slouches, because that weakens the case just like a bad posture.","cloze_distractors_en":[],"examples":[{"es":"Si el testigo miente, eso debilita la postura.","en":"If the witness lies, that weakens the case."}]},{"spanish_text":"Eso respalda la idea","english_text":"That supports the claim","section_name":"Discussion and Debate","part_of_speech":"sentence","definition_en":"It indicates that something provides evidence for or backs up a particular claim.","main_translations_es":["Eso respalda la idea","Eso sustenta la idea","Eso avala la idea"],"collocations":["as evidence that supports the claim","which supports the claim","to support the claim"],"synonyms_en":["backs the claim","reinforces the argument","substantiates the claim"],"example_sentence":"That supports the claim that climate change is real.","example_es":"Eso respalda la idea de que el cambio climático es real.","example_en":"That supports the claim that climate change is real.","mnemonic_en":"Picture a sturdy back (respaldo) holding up a claim.","cloze_distractors_en":[],"examples":[{"es":"Eso respalda la idea de que el cambio climático es real.","en":"That supports the claim that climate change is real."}]},{"spanish_text":"Eso entra en conflicto con","english_text":"That conflicts with","section_name":"Discussion and Debate","part_of_speech":"verb","definition_en":"To be in disagreement or incompatibility with something.","main_translations_es":["Eso está en conflicto con","Eso contradice a","Eso choca con"],"collocations":["conflicts with","is at odds with","clashes with","contradicts"],"synonyms_en":["contradicts","is at odds with","clashes with"],"example_sentence":"That conflicts with the company''s policies.","example_es":"Eso entra en conflicto con las normas de la empresa.","example_en":"That conflicts with the company''s policies.","mnemonic_en":"Picture a conflict as a door that enters the room, clashing with everything inside.","cloze_distractors_en":[],"examples":[{"es":"Eso entra en conflicto con las normas de la empresa.","en":"That conflicts with the company''s policies."}]},{"spanish_text":"Parece contradictorio","english_text":"That appears contradictory","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"It means that something seems to be in conflict or inconsistent.","main_translations_es":["Resulta contradictorio","Se muestra contradictorio","Parece contradictorio"],"collocations":["That appears contradictory to the earlier statement","That appears contradictory at first glance","That appears contradictory, but further analysis clarifies","That appears contradictory in context"],"synonyms_en":["seems inconsistent","looks conflicting","appears paradoxical"],"example_sentence":"That appears contradictory to claim that the climate is changing while the scientific evidence is denied.","example_es":"Parece contradictorio afirmar que el clima está cambiando mientras se niega la evidencia científica.","example_en":"That appears contradictory to claim that the climate is changing while the scientific evidence is denied.","mnemonic_en":"Visualize a billboard that appears, flashing the word ''contradictorio'' in bright colors.","cloze_distractors_en":[],"examples":[{"es":"Parece contradictorio afirmar que el clima está cambiando mientras se niega la evidencia científica.","en":"That appears contradictory to claim that the climate is changing while the scientific evidence is denied."}]},{"spanish_text":"No estoy cerrado a esa idea","english_text":"I am open to that idea","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A statement indicating willingness to consider or accept a suggestion.","main_translations_es":["Estoy abierto a esa idea","No me opongo a esa idea","No rechazo esa idea"],"collocations":["open to suggestions","open to new ideas","open to possibilities","open to feedback"],"synonyms_en":["I''m receptive","I''m willing","I consider it"],"example_sentence":"I''m not closed to that idea, so we can consider it.","example_es":"No estoy cerrado a esa idea, así que podemos considerarla.","example_en":"I''m not closed to that idea, so we can consider it.","mnemonic_en":"Picture a door swinging open as you say I am open to that idea, opposite of cerrado","cloze_distractors_en":[],"examples":[{"es":"No estoy cerrado a esa idea, así que podemos considerarla.","en":"I''m not closed to that idea, so we can consider it."}]},{"spanish_text":"Estoy dispuesto a reconsiderarlo","english_text":"I am willing to reconsider","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A statement indicating readiness to think about something again.","main_translations_es":["Estoy dispuesto a reconsiderar","Podría reconsiderarlo","Estoy abierto a reconsiderar"],"collocations":["I am willing to reconsider the proposal","I am willing to reconsider my decision","I am willing to reconsider the terms","I am willing to reconsider the offer"],"synonyms_en":["I am open to reconsidering","I am prepared to rethink","I am ready to review"],"example_sentence":"I am willing to reconsider it if you present me with new arguments.","example_es":"Estoy dispuesto a reconsiderarlo si me presentas nuevos argumentos.","example_en":"I am willing to reconsider it if you present me with new arguments.","mnemonic_en":"I''m willing to reconsider, like a Spanish dispuesto chef tasting a new recipe.","cloze_distractors_en":[],"examples":[{"es":"Estoy dispuesto a reconsiderarlo si me presentas nuevos argumentos.","en":"I am willing to reconsider it if you present me with new arguments."}]},{"spanish_text":"Eso es discutible","english_text":"That is open to debate","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A statement indicating that something is arguable or not settled.","main_translations_es":["Eso es debatible","Eso es cuestionable","Eso es discutible"],"collocations":["open to debate","subject to debate","open for debate"],"synonyms_en":["debatable","questionable","up for discussion"],"example_sentence":"The argument you presented is open to debate, so we won''t accept it without further discussion.","example_es":"El argumento que presentaste es discutible, así que no lo aceptaremos sin más.","example_en":"The argument you presented is open to debate, so we won''t accept it without further discussion.","mnemonic_en":"Picture a door labeled Debate swinging open, reminding you that discutible means open to debate.","cloze_distractors_en":[],"examples":[{"es":"El argumento que presentaste es discutible, así que no lo aceptaremos sin más.","en":"The argument you presented is open to debate, so we won''t accept it without further discussion."}]},{"spanish_text":"No me convence del todo","english_text":"I am not fully persuaded","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A statement indicating that one is not completely convinced.","main_translations_es":["No me convence del todo","No me convence completamente","No me convence por completo"],"collocations":["I am not fully persuaded by his argument","I am not fully persuaded yet","I am not fully persuaded about the decision"],"synonyms_en":["unconvinced","not convinced","skeptical"],"example_sentence":"I am not fully persuaded by the theory presented at the conference.","example_es":"No me convence del todo la teoría que presentaron en la conferencia.","example_en":"I am not fully persuaded by the theory presented at the conference.","mnemonic_en":"Picture a con trying to convince me, but only half the story reaches me, so I''m not fully persuaded.","cloze_distractors_en":[],"examples":[{"es":"No me convence del todo la teoría que presentaron en la conferencia.","en":"I am not fully persuaded by the theory presented at the conference."}]},{"spanish_text":"Tu argumento es sólido","english_text":"Your argument is sound","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A statement indicating that someone''s reasoning or evidence is solid and reliable.","main_translations_es":["Tu razonamiento es sólido","Tu argumento es firme","Tu argumento está bien fundamentado"],"collocations":["Your argument is sound, so we can move forward","If your argument is sound, the conclusion follows","A sound argument is persuasive","Your argument is sound and convincing"],"synonyms_en":["Your argument is solid","Your reasoning is valid","Your case is convincing"],"example_sentence":"Your argument is sound, so we should consider it seriously.","example_es":"Tu argumento es sólido, así que debemos considerarlo seriamente.","example_en":"Your argument is sound, so we should consider it seriously.","mnemonic_en":"A solid argument sounds like a sturdy drum echoing certainty","cloze_distractors_en":[],"examples":[{"es":"Tu argumento es sólido, así que debemos considerarlo seriamente.","en":"Your argument is sound, so we should consider it seriously."}]},{"spanish_text":"Eso carece de fundamento","english_text":"That lacks foundation","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"It means something is unsupported or has no basis.","main_translations_es":["No tiene fundamento","Carece de base","No está fundamentado"],"collocations":["lacks a solid foundation","lacks any foundation","lacks foundational support"],"synonyms_en":["baseless","groundless","unfounded"],"example_sentence":"The accusation that he stole the bank is unfounded; that lacks foundation.","example_es":"La acusación de que él robó el banco es infundada; eso carece de fundamento.","example_en":"The accusation that he stole the bank is unfounded; that lacks foundation.","mnemonic_en":"Picture a shaky house: that lacks foundation, just like a broken Spanish fundamento.","cloze_distractors_en":[],"examples":[{"es":"La acusación de que él robó el banco es infundada; eso carece de fundamento.","en":"The accusation that he stole the bank is unfounded; that lacks foundation."}]},{"spanish_text":"No es una conclusión inevitable","english_text":"That is not an inevitable conclusion","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A statement asserting that a particular outcome is not unavoidable.","main_translations_es":["No es una conclusión inevitable","No constituye una conclusión inevitable","No resulta una conclusión inevitable"],"collocations":["However, that is not an inevitable conclusion.","Thus, that is not an inevitable conclusion.","In any case, that is not an inevitable conclusion."],"synonyms_en":["It''s not a foregone conclusion","It''s not unavoidable","It''s not predetermined"],"example_sentence":"That is not an inevitable conclusion, but we should keep investigating.","example_es":"No es una conclusión inevitable, pero debemos seguir investigando.","example_en":"That is not an inevitable conclusion, but we should keep investigating.","mnemonic_en":"Imagine a nose shaking its head, saying that conclusion is not inevitable.","cloze_distractors_en":[],"examples":[{"es":"No es una conclusión inevitable, pero debemos seguir investigando.","en":"That is not an inevitable conclusion, but we should keep investigating."}]},{"spanish_text":"Puede haber una explicación alternativa","english_text":"There may be an alternative explanation","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"It suggests that an alternative explanation could exist.","main_translations_es":["Podría existir una explicación alternativa","Existe la posibilidad de una explicación alternativa","Hay una posible explicación alternativa"],"collocations":["Consider that there may be an alternative explanation","It''s possible that there may be an alternative explanation","We should keep in mind there may be an alternative explanation"],"synonyms_en":["An alternative explanation might exist","Possibly another explanation","There could be another explanation"],"example_sentence":"There may be an alternative explanation for this phenomenon.","example_es":"Puede haber una explicación alternativa para este fenómeno.","example_en":"There may be an alternative explanation for this phenomenon.","mnemonic_en":"Picture a native altering the story while giving an explanation.","cloze_distractors_en":[],"examples":[{"es":"Puede haber una explicación alternativa para este fenómeno.","en":"There may be an alternative explanation for this phenomenon."}]},{"spanish_text":"Lo dejaría en que","english_text":"I would put it this way","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A phrase used to introduce a particular way of stating something.","main_translations_es":["Lo expresaría así","Lo diría de esta manera","Lo plantearía así"],"collocations":["I would put it this way: ...","Let me put it this way","I would put it this way, if you will"],"synonyms_en":["I would phrase it like this","That''s how I''d put it","I would say it like this"],"example_sentence":"I would put it this way: that everything turns out well.","example_es":"Lo dejaría en que todo salga bien.","example_en":"I would put it this way: that everything turns out well.","mnemonic_en":"Picture a low jar where you put the idea, like saying ''I would put it this way''.","cloze_distractors_en":[],"examples":[{"es":"Lo dejaría en que todo salga bien.","en":"I would put it this way: that everything turns out well."}]},{"spanish_text":"Estoy de acuerdo en lo esencial","english_text":"I agree in principle","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"To express agreement with the general idea or underlying principle, without committing to all specifics.","main_translations_es":["Coincido en lo esencial","Estoy de acuerdo en lo fundamental","Comparto la idea esencial"],"collocations":["I agree in principle, but...","We can move forward; I agree in principle","I agree in principle with your suggestion"],"synonyms_en":["agree in theory","agree fundamentally","agree on the basics"],"example_sentence":"I agree in principle, although some details may vary.","example_es":"Estoy de acuerdo en lo esencial, aunque algunos detalles pueden variar.","example_en":"I agree in principle, although some details may vary.","mnemonic_en":"Picture a principal (principle) shaking hands, saying I agree—like saying acuerdo in Spanish.","cloze_distractors_en":[],"examples":[{"es":"Estoy de acuerdo en lo esencial, aunque algunos detalles pueden variar.","en":"I agree in principle, although some details may vary."}]},{"spanish_text":"No estoy en desacuerdo con eso","english_text":"I do not disagree with that","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A statement indicating that the speaker does not oppose or contradict that.","main_translations_es":["Estoy de acuerdo con eso","Comparto esa opinión","No difiero con eso"],"collocations":["I do not disagree with that point","I do not disagree with that view","I do not disagree with that statement","I do not disagree with that assessment"],"synonyms_en":["I agree","I concur","I''m in agreement"],"example_sentence":"I do not disagree with that, but I think we could improve the proposal.","example_es":"No estoy en desacuerdo con eso, pero creo que podríamos mejorar la propuesta.","example_en":"I do not disagree with that, but I think we could improve the proposal.","mnemonic_en":"Imagine I tie a knot that refuses to split, so I do not disagree.","cloze_distractors_en":[],"examples":[{"es":"No estoy en desacuerdo con eso, pero creo que podríamos mejorar la propuesta.","en":"I do not disagree with that, but I think we could improve the proposal."}]},{"spanish_text":"Eso es justamente el problema","english_text":"That is precisely the problem","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"A statement indicating that something exactly constitutes the issue.","main_translations_es":["Ese es precisamente el problema","Eso es exactamente el problema","Ese es el problema justo"],"collocations":["That''s precisely the problem","And that''s precisely the problem","Which is precisely the problem","That''s precisely the problem we face"],"synonyms_en":["That''s exactly the issue","That''s the exact problem","That''s the crux"],"example_sentence":"That is precisely the problem we have been discussing.","example_es":"Eso es justamente el problema que hemos estado discutiendo.","example_en":"That is precisely the problem we have been discussing.","mnemonic_en":"Imagine a precise judge saying that is precisely the problem while holding a just scale","cloze_distractors_en":[],"examples":[{"es":"Eso es justamente el problema que hemos estado discutiendo.","en":"That is precisely the problem we have been discussing."}]},{"spanish_text":"Eso va al corazón del asunto","english_text":"That goes to the heart of the matter","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"It means that something addresses the most important or central point of an issue.","main_translations_es":["Eso llega al meollo del asunto","Eso toca el punto clave","Eso va al fondo del asunto"],"collocations":["gets to the heart of the matter","goes straight to the heart of the matter","hits the heart of the matter","addresses the heart of the matter"],"synonyms_en":["gets to the crux","gets to the point","hits the nail on the head"],"example_sentence":"That goes to the heart of the matter and allows us to find a solution.","example_es":"Eso va al corazón del asunto y nos permite encontrar una solución.","example_en":"That goes to the heart of the matter and allows us to find a solution.","mnemonic_en":"Picture a core (corazón) heart that slides straight into the matter","cloze_distractors_en":[],"examples":[{"es":"Eso va al corazón del asunto y nos permite encontrar una solución.","en":"That goes to the heart of the matter and allows us to find a solution."}]},{"spanish_text":"Da que pensar","english_text":"That gives food for thought","section_name":"Discussion and Debate","part_of_speech":"expression","definition_en":"It means something that provokes reflection or consideration.","main_translations_es":["Da que reflexionar","Invita a la reflexión","Hace pensar"],"collocations":["gives me food for thought","provides food for thought","offers food for thought"],"synonyms_en":["thought‑provoking","makes you think","gives pause"],"example_sentence":"His argument gives food for thought.","example_es":"Su argumento da que pensar.","example_en":"His argument gives food for thought.","mnemonic_en":"Picture a queue of pens serving tasty ideas on a plate","cloze_distractors_en":[],"examples":[{"es":"Su argumento da que pensar.","en":"His argument gives food for thought."}]}]'::jsonb) as x(
  spanish_text text, english_text text, section_name text, part_of_speech text, definition_en text,
  main_translations_es jsonb, collocations jsonb, synonyms_en jsonb, example_sentence text, example_es text, example_en text, mnemonic_en text, cloze_distractors_en jsonb, examples jsonb
)
